-- Poems batch 199
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('75b5c01c-b146-4b37-8801-547b94251bec','秋興  其二','汪莘','宋','宋诗','song-poetry','','[]','天外涵天心廣大，月中吐月性光明。',32,'全唐诗/poet.song.189000.json','["天外涵天心廣大，月中吐月性光明。", "夜來飛上崑崙頂，獨倚瓊樓嘯一聲。"]'),
('09be67a3-f814-41ef-b179-8f7a05bd29a9','秋興  其三','汪莘','宋','宋诗','song-poetry','','[]','一旦秋風起洛濱，東歸聊復寄鱸蓴。',32,'全唐诗/poet.song.189000.json','["一旦秋風起洛濱，東歸聊復寄鱸蓴。", "如今已在漁鄉住，宜與清朝作散人。"]'),
('3b3d58a1-4adb-411f-adeb-5ff13400b854','秋興  其四','汪莘','宋','宋诗','song-poetry','','[]','水邊楊柳怯秋風，憶昨杏花相映紅。',32,'全唐诗/poet.song.189000.json','["水邊楊柳怯秋風，憶昨杏花相映紅。", "心地不隨時節變，始知天下有英雄。"]'),
('ee52251b-4b98-433f-b557-ea1279d392b6','秋興  其五','汪莘','宋','宋诗','song-poetry','','[]','蘿衣嫋嫋带凉風，人道秋空豈是空。',32,'全唐诗/poet.song.189000.json','["蘿衣嫋嫋带凉風，人道秋空豈是空。", "白日不知天上事，衆星環拱紫微宮。"]'),
('c86997d0-98e4-4af4-b85f-b65f93b3edea','秋興  其六','汪莘','宋','宋诗','song-poetry','','[]','七尺經霜翠竹竿，斬來石壁釣江湍。',32,'全唐诗/poet.song.189000.json','["七尺經霜翠竹竿，斬來石壁釣江湍。", "絲頭垂下驪龍口，掣得明珠似月寒。"]'),
('bb7b889c-c809-4ec0-a185-ae2cc6828772','秋興  其七','汪莘','宋','宋诗','song-poetry','','[]','秋天尤覺曉天清，仰首看天俯首行。',32,'全唐诗/poet.song.189000.json','["秋天尤覺曉天清，仰首看天俯首行。", "不但長歌聲似鶴，一身渾似鶴般輕。"]'),
('0ce26eef-48ac-4443-9e11-bd74d153e494','除日寄黟山周尊師','汪莘','宋','宋诗','song-poetry','','[]','眼有神光射靄山，不須更問列仙班。',32,'全唐诗/poet.song.189000.json','["眼有神光射靄山，不須更問列仙班。", "道人四海都遊遍，只有先生一介閑。"]'),
('38f25c66-f8d5-4549-b743-49dd0e6eaa41','東行途中有感','汪莘','宋','宋诗','song-poetry','','[]','一路桃花愁殺人，柳塘茅屋正宜春。',32,'全唐诗/poet.song.189000.json','["一路桃花愁殺人，柳塘茅屋正宜春。", "春風不是不相識，不遣春山養病身。"]'),
('2c653983-f908-49ca-b037-19e0cc85a996','去昌化縣西四十里留宿陳東魯南樓','汪莘','宋','宋诗','song-poetry','','[]','碧玉山中白玉溪，武陵村落午時雞。',32,'全唐诗/poet.song.189000.json','["碧玉山中白玉溪，武陵村落午時雞。", "南樓一覺春宵雨，夾路桃花送馬蹄。"]'),
('50f7df5c-37e7-43a7-b60a-6504108022e0','謁真直院楊花滿路口占一絕見直院誦之','汪莘','宋','宋诗','song-poetry','','[]','三月天寒尚臘衣，錢塘遊子嘆斜暉。',32,'全唐诗/poet.song.189000.json','["三月天寒尚臘衣，錢塘遊子嘆斜暉。", "柳間蘇小無由見，惹得楊花滿袖歸。"]'),
('a3dece69-6ee9-4635-95c5-782b1fc752ad','真直院招飲道山群玉堂自陳秘監而下凡八人坐上賦絕句','汪莘','宋','宋诗','song-poetry','','[]','壓架春風十萬條，護檐霜榦自蕭蕭。',32,'全唐诗/poet.song.189000.json','["壓架春風十萬條，護檐霜榦自蕭蕭。", "一朝盡識群賢面，陡覺星辰共碧霄。"]'),
('11aec7b7-688c-4048-bb0c-78d00adb2565','直院自言願所以相拯之意有非毫楮所可宣者歸途口占一絕爲寄','汪莘','宋','宋诗','song-poetry','','[]','傾國佳人默怨天，紅顔過了拜尊前。',32,'全唐诗/poet.song.189000.json','["傾國佳人默怨天，紅顔過了拜尊前。", "世家大族多兄嫂，獨得公姑分外憐。"]'),
('b49c1bc9-a241-403c-8b42-0ce760748478','三月十九日過松江五絕  其一','汪莘','宋','宋诗','song-poetry','','[]','在家每憶松江好，及到松江又憶家。',32,'全唐诗/poet.song.189000.json','["在家每憶松江好，及到松江又憶家。", "夢見樵青來竹裏，笑將漁父插桃花。"]'),
('56ebde91-4efd-4cee-b2e5-d031d18a78e1','三月十九日過松江五絕  其二','汪莘','宋','宋诗','song-poetry','','[]','萬頃烟波短棹飛，一雙鷗鳥弄斜暉。',32,'全唐诗/poet.song.189000.json','["萬頃烟波短棹飛，一雙鷗鳥弄斜暉。", "如今頻作姑蘇客，遥指當年舊釣磯。"]'),
('742651bf-f2d1-4f3a-98a8-137b4f9742be','三月十九日過松江五絕  其三','汪莘','宋','宋诗','song-poetry','','[]','煎茶徐讀散人傳，對酒朗吟漁父詞。',32,'全唐诗/poet.song.189000.json','["煎茶徐讀散人傳，對酒朗吟漁父詞。", "除却月風同此意，祗應烟雨暗相知。"]'),
('d7c9acb0-6535-4816-9416-4f5a9d269a21','三月十九日過松江五絕  其四','汪莘','宋','宋诗','song-poetry','','[]','薰風吹夢聽新蟬，又向長橋艤釣船。',32,'全唐诗/poet.song.189000.json','["薰風吹夢聽新蟬，又向長橋艤釣船。", "好剪吳松半江水，袖歸三十六峰前。"]'),
('614d6155-d7ac-45b0-b64a-cb73eba3d322','三月十九日過松江五絕  其五','汪莘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','笠澤滄波擁洞庭，望中七十二峰青。',32,'全唐诗/poet.song.189000.json','["笠澤滄波擁洞庭，望中七十二峰青。", "待偕龍女乘雲去，占取參天一畫屏。"]'),
('db7a5214-2aa0-4bc2-9476-692f9fbb52f8','過丹陽界中新豐市','汪莘','宋','宋诗','song-poetry','','[]','道過新豐沽酒樓，不須濯足故相酬。',32,'全唐诗/poet.song.189000.json','["道過新豐沽酒樓，不須濯足故相酬。", "華山仙伯徐思看，爭遣時人識馬周。"]'),
('4946e47c-29e0-4f1e-ac4c-88bc26558131','途中再詠金陵','汪莘','宋','宋诗','song-poetry','','[]','石頭城上望斜暉，覽盡金陵寂寞歸。',32,'全唐诗/poet.song.189000.json','["石頭城上望斜暉，覽盡金陵寂寞歸。", "嘆息青天如許大，可無一箇鳳凰飛。"]'),
('2a070679-28c3-498f-bcd3-4a7b7d1150a5','回至松江  其一','汪莘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','欲向江南採白蘋，杜鵑啼後已無春。',32,'全唐诗/poet.song.189000.json','["欲向江南採白蘋，杜鵑啼後已無春。", "洞庭龍女雲中降，手把雙珠笑贈人。"]'),
('0a3d23d8-6689-4ea9-ad4c-ecce5218b3cf','回至松江  其二','汪莘','宋','宋诗','song-poetry','','[]','深林茅屋隠漁樵，時有扁舟過石橋。',32,'全唐诗/poet.song.189000.json','["深林茅屋隠漁樵，時有扁舟過石橋。", "誰把客星入圖畫，曉風殘月伴吹簫。"]'),
('f9ea0056-8ebc-47f8-89e1-6c0f62734f03','到高亭山望南北高峰','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','每泛西湖不忍還，高亭數疊出雲間。',32,'全唐诗/poet.song.189000.json','["每泛西湖不忍還，高亭數疊出雲間。", "如今回至高亭路，却望西湖數疊山。"]'),
('7191ffd2-0537-4198-bd1b-0dfc6a214fcf','程朝望送梅花','汪莘','宋','宋诗','song-poetry','','[]','昨夜燈前把酒杯，鄱陽主簿送春來。',32,'全唐诗/poet.song.189000.json','["昨夜燈前把酒杯，鄱陽主簿送春來。", "只疑天地無清氣，都在江頭一樹梅。"]'),
('b162b8d3-c6e7-41fb-89f5-6e633f4982d4','再用韵  其一','汪莘','宋','宋诗','song-poetry','','[]','長恨無人共一杯，直知好友自天來。',32,'全唐诗/poet.song.189000.json','["長恨無人共一杯，直知好友自天來。", "淵明到死真成菊，和靖平生却是梅。"]'),
('3a643a2c-f17f-4431-b2ee-0f448d31f6db','再用韵  其二','汪莘','宋','宋诗','song-poetry','','[]','接得南枝即按杯，似和霜月带將來。',32,'全唐诗/poet.song.189000.json','["接得南枝即按杯，似和霜月带將來。", "自從驛使相逢後，千載無人解寄梅。"]'),
('ba33ecfd-5a3e-44d9-94f9-7318668c3474','重陽趙使君惠酒','汪莘','宋','宋诗','song-poetry','','[]','何嘗自覓王弘酒，頗怪曾麾道濟粱。',32,'全唐诗/poet.song.189000.json','["何嘗自覓王弘酒，頗怪曾麾道濟粱。", "處士固應高一着，江州太守味尤長。"]'),
('88431734-7efc-4d4b-9d0d-28cb4b5b0e7b','寓清湖橋夜枕聞雨','汪莘','宋','宋诗','song-poetry','','[]','要識人間過去愁，春宵風雨到湖樓。',32,'全唐诗/poet.song.189000.json','["要識人間過去愁，春宵風雨到湖樓。", "如今此恨無分處，應有知人在後頭。"]'),
('180205a7-d198-486c-b1cd-311aaf2789be','夜坐有感','汪莘','宋','宋诗','song-poetry','','[]','前賢相遇是前程，不見斯人莫誤行。',32,'全唐诗/poet.song.189000.json','["前賢相遇是前程，不見斯人莫誤行。", "白面書生那解事，只將文字住京城。"]'),
('fabd4e77-1e78-49fd-b90f-a7177255d64f','晚晴即事','汪莘','宋','宋诗','song-poetry','','[]','君平簾外雨霏霏，寂寞何人識少微。',32,'全唐诗/poet.song.189000.json','["君平簾外雨霏霏，寂寞何人識少微。", "怪得湖邊天色好，小舟爭載夕陽歸。"]'),
('ed86c0fd-ba24-4c97-a558-ea8f12fc00df','夏日西湖閑居十首  其一','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里湖山苦見招，柳堤荷蕩赤欄橋。',32,'全唐诗/poet.song.189000.json','["十里湖山苦見招，柳堤荷蕩赤欄橋。", "待他朝市人歸後，獨泛扁舟吹玉簫。"]'),
('4e527eda-668d-4254-bb02-52c5b1c16b2d','夏日西湖閑居十首  其二','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','急管繁絃樽俎閒，何人靜眼對湖山。',32,'全唐诗/poet.song.189000.json','["急管繁絃樽俎閒，何人靜眼對湖山。", "怪來水面無鷗鷺，多在殘蒲落照灣。"]'),
('a69868be-11c0-4a43-83a8-7a8e69424dc5','夏日西湖閑居十首  其三','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','每嘆西湖境未殊，向來人物有還無。',32,'全唐诗/poet.song.189000.json','["每嘆西湖境未殊，向來人物有還無。", "紅蕖綠竹渾相得，明月清風亦不孤。"]'),
('d13b6edd-10fd-4bab-bc70-e4b44d74f401','夏日西湖閑居十首  其四','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晚風吹動碧琳寒，初日花房露未乾。',32,'全唐诗/poet.song.189000.json','["晚風吹動碧琳寒，初日花房露未乾。", "誰道幽人無伴侶，紅蕖萬朵竹千竿。"]'),
('fb789e58-60da-4541-873e-0c2dc1613583','夏日西湖閑居十首  其五','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','修竹祠堂曲水濱，寒泉菊盞久埃塵。',32,'全唐诗/poet.song.189000.json','["修竹祠堂曲水濱，寒泉菊盞久埃塵。", "道傍車馬無心到，似我頻來有幾人。"]'),
('bc43672d-2d72-4c12-bd53-1adace350e48','夏日西湖閑居十首  其六','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一曲波光徹太虛，四垂碧漢罩湖魚。',32,'全唐诗/poet.song.189000.json','["一曲波光徹太虛，四垂碧漢罩湖魚。", "遊人眼被荷花礙，不覺琉璃泡裏居。"]'),
('035cc778-5ca1-42d0-a590-b34b93804b86','夏日西湖閑居十首  其七','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','露冷風清斗柄遷，芙蕖零落謝家船。',32,'全唐诗/poet.song.189000.json','["露冷風清斗柄遷，芙蕖零落謝家船。", "都人正作黄粱夢，獨占西湖明月天。"]'),
('14deebc4-855e-4c4d-ace5-da43dc965067','夏日西湖閑居十首  其八','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清夜湖心把酒杯，花間風月共徘徊。',32,'全唐诗/poet.song.189000.json','["清夜湖心把酒杯，花間風月共徘徊。", "金鐘何事催天曉，又恐遊人相逐來。"]'),
('bd492fc5-4ae1-4a13-9911-df7395215950','夏日西湖閑居十首  其九','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','醉把青荷當篛笠，亂披紅芰作蓑衣。',32,'全唐诗/poet.song.189000.json','["醉把青荷當篛笠，亂披紅芰作蓑衣。", "漁翁家在蓬瀛上，欲駕蓮舟一葉歸。"]'),
('8a15a515-18ba-47c9-ac36-e5950d274f9c','夏日西湖閑居十首  其一○','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','藕蔕嚼來殊解渴，荷香聞得亦忘饑。',32,'全唐诗/poet.song.189000.json','["藕蔕嚼來殊解渴，荷香聞得亦忘饑。", "幽人不趁槐花課，收得西湖幾句詩。"]'),
('1918a850-7dfe-48bd-854c-a2a7707028ad','感白髮','汪莘','宋','宋诗','song-poetry','','[]','一枕黄粱夢欲殘，死生大海浪漫漫。',32,'全唐诗/poet.song.189000.json','["一枕黄粱夢欲殘，死生大海浪漫漫。", "鬢邊白髮休除却，時向窗前把鏡看。"]'),
('92aab0ca-e908-4941-a973-62cd552d0449','湖上早秋偶興','汪莘','宋','宋诗','song-poetry','','[]','坐卧芙蓉花上頭，清香長繞飯中浮。',32,'全唐诗/poet.song.189000.json','["坐卧芙蓉花上頭，清香長繞飯中浮。", "金風玉露玻璃月，併作詩人富貴秋。"]'),
('55b5e308-0db1-4683-8504-6c16b5c17bab','夜興','汪莘','宋','宋诗','song-poetry','','[]','簟紋如水浸蟾光，睡覺湖邊月半牀。',32,'全唐诗/poet.song.189000.json','["簟紋如水浸蟾光，睡覺湖邊月半牀。", "道是廣寒疑不是，月中那得藕花香。"]'),
('79e9bdb8-cd7c-41e9-9145-65841203f1bf','泛小舟入蓮蕩微雨即事','汪莘','宋','宋诗','song-poetry','','[]','水光如錦葉如烟，微雨相從到洞天。',32,'全唐诗/poet.song.189000.json','["水光如錦葉如烟，微雨相從到洞天。", "翠盖紅妝無處避，一時挨入木蘭船。"]'),
('459e490b-17d2-480f-a94a-30c5c9ecb8d7','偶題','汪莘','宋','宋诗','song-poetry','','[]','浮雲散盡月孤明，月裏仙人影更清。',32,'全唐诗/poet.song.189000.json','["浮雲散盡月孤明，月裏仙人影更清。", "憶昔相逢不相識，如今同坐復同行。"]'),
('b9a5fea3-8844-44f0-be96-b5099737b9c8','臘月雪後','汪莘','宋','宋诗','song-poetry','','[]','林下雪消添晚汲，山中日出欠晨炊。',32,'全唐诗/poet.song.189000.json','["林下雪消添晚汲，山中日出欠晨炊。", "先生茅屋春猶早，只有階前碧草知。"]'),
('3e4f9b08-7b66-45d1-af2d-43f3aa25a3dc','遷入新居後客至偶成','汪莘','宋','宋诗','song-poetry','','[]','方壺客去偃雲牀，槐柳陰陰日自長。',32,'全唐诗/poet.song.189000.json','["方壺客去偃雲牀，槐柳陰陰日自長。", "睡起不知天早晚，問人山頂是斜陽。"]'),
