('55b071e1-5cf6-4b27-9bbc-45a82ce5f568','甲寅西歸江行春懷十首  其六','汪莘','宋','宋诗','song-poetry','','[]','塞空春意總分明，桃李無言却混成。',32,'全唐诗/poet.song.189000.json','["塞空春意總分明，桃李無言却混成。", "剛被幽禽知此意，風前拈出兩三聲。"]'),
('e4be6cf7-4e98-4a94-9fa4-92418e90bc51','甲寅西歸江行春懷十首  其七','汪莘','宋','宋诗','song-poetry','','[]','二月湖山把酒中，呼猿洞口水涵空。',32,'全唐诗/poet.song.189000.json','["二月湖山把酒中，呼猿洞口水涵空。", "醉來剝盡新花蘂，百疊生紅未見風。"]'),
('b43a0a61-04e9-4251-8f00-a382b344300a','甲寅西歸江行春懷十首  其八','汪莘','宋','宋诗','song-poetry','','[]','白晝春光綠染衣，東風千里挂帆歸。',32,'全唐诗/poet.song.189000.json','["白晝春光綠染衣，東風千里挂帆歸。", "竹籬紅白花相映，只聽雞聲在翠微。"]'),
('21575bb4-87a5-49c1-8fb3-785207103122','甲寅西歸江行春懷十首  其九','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖楊柳欲棲烏，遥想溪山似畫圖。',32,'全唐诗/poet.song.189000.json','["西湖楊柳欲棲烏，遥想溪山似畫圖。", "二月到家寒食近，末梢春境憶西湖。"]'),
('e14ec650-7a43-4814-9c3b-e3da095f448a','甲寅西歸江行春懷十首  其一○','汪莘','宋','宋诗','song-poetry','','[]','繞屋桃花可得追，迎門猶有海棠枝。',32,'全唐诗/poet.song.189000.json','["繞屋桃花可得追，迎門猶有海棠枝。", "牡丹未放酴醿小，併入青梅煮酒時。"]'),
('0f764a2e-2f44-46a6-ac71-654d9cfd979f','慶元五年休寧權縣鄭丞吳山寺勸農次韵  其一','汪莘','宋','宋诗','song-poetry','','[]','駿馬輕衫拂曉行，野塘春水縠紋生。',32,'全唐诗/poet.song.189000.json','["駿馬輕衫拂曉行，野塘春水縠紋生。", "心知沮溺無尋處，猶把津頭問耦耕。"]'),
('f5eabb5f-2db9-4adb-917d-3dd1e41673dd','慶元五年休寧權縣鄭丞吳山寺勸農次韵  其二','汪莘','宋','宋诗','song-poetry','','[]','鳳凰城裏舊徘徊，村裏吳山躍馬來。',32,'全唐诗/poet.song.189000.json','["鳳凰城裏舊徘徊，村裏吳山躍馬來。", "也有旗亭沽酒處，可憐桃杏向人開。"]'),
('caaf289e-2c2c-4d9c-a994-045c4904a663','八月十一夜作文起夜興','汪莘','宋','宋诗','song-poetry','','[]','點墨揮毫勢始停，起來耳目共時醒。',32,'全唐诗/poet.song.189000.json','["點墨揮毫勢始停，起來耳目共時醒。", "一窗月色元無響，四壁蟲聲不見形。"]'),
('53470a0a-17f8-4cc3-857e-f74acca4a630','辛酉正月初八日入郡赴高校書之約二十二日出西郊即事','汪莘','宋','宋诗','song-poetry','','[]','竹籬茅屋兩三家，白晝青春自歲華。',32,'全唐诗/poet.song.189000.json','["竹籬茅屋兩三家，白晝青春自歲華。", "碧縠水邊搓柳線，綠羅天畔繡桃花。"]'),
('73942757-1a9d-4cc2-bac7-ec095fb51e20','感秋  其一','汪莘','宋','宋诗','song-poetry','','[]','秋水無塵浸碧虛，風前一葉故飛飛。',32,'全唐诗/poet.song.189000.json','["秋水無塵浸碧虛，風前一葉故飛飛。", "瀟湘帝子何時降，立盡斜陽未肯歸。"]'),
('b94698af-b4f9-41a4-b586-a28696544ecf','感秋  其二','汪莘','宋','宋诗','song-poetry','','[]','閑佩仙瓢到柳汀，柳邊一點酒旗星。',32,'全唐诗/poet.song.189000.json','["閑佩仙瓢到柳汀，柳邊一點酒旗星。", "斜陽欲落無人惜，空有烟林作畫屏。"]'),
('bcb5c657-9f77-4ba4-ac50-f34a68ced8a7','感秋  其三','汪莘','宋','宋诗','song-poetry','','[]','行到籬邊菊已黄，相逢不改舊時香。',32,'全唐诗/poet.song.189000.json','["行到籬邊菊已黄，相逢不改舊時香。", "自憐失意秋風後，猶爲寒花一舉觴。"]'),
('5fc348ea-ad2f-4500-adad-6809755ad298','感秋  其四','汪莘','宋','宋诗','song-poetry','','[]','不須龜筮此生休，死去無心更出頭。',32,'全唐诗/poet.song.189000.json','["不須龜筮此生休，死去無心更出頭。", "莫說竹籬茅舍事，丹楓一樹正悲秋。"]'),
('66f579af-31a7-4aea-bbde-9495a623ea6e','感秋  其五','汪莘','宋','宋诗','song-poetry','','[]','獨步荒山日欲昏，數聲乾葦過遊魂。',32,'全唐诗/poet.song.189000.json','["獨步荒山日欲昏，數聲乾葦過遊魂。", "重崗複澗穿難盡，恍惚隨人月一痕。"]'),
('6168db49-5904-402a-ad0d-ef60550f3184','壬戌歲春懷  其一','汪莘','宋','宋诗','song-poetry','','[]','病起南臯二月時，鏡中樗散鬢成絲。',32,'全唐诗/poet.song.189000.json','["病起南臯二月時，鏡中樗散鬢成絲。", "不因雀噪檐間樹，春雪春晴總不知。"]'),
('2cd85507-3a68-4169-a965-10b4f1172e37','壬戌歲春懷  其二','汪莘','宋','宋诗','song-poetry','','[]','抱疾衡門與藥親，苦無筋力尚精神。',32,'全唐诗/poet.song.189000.json','["抱疾衡門與藥親，苦無筋力尚精神。", "東風日夜開桃李，不爲人間失意人。"]'),
('23c6a231-73a5-4853-a679-8a7f9146b622','四月十二日携家如錢塘二十二日過湖至九里松船步頭秦家安泊凡住百日八月還家仲冬題金德恭東園','汪莘','宋','宋诗','song-poetry','','[]','昔年曾訪此林坰，今日重來倍有情。',32,'全唐诗/poet.song.189000.json','["昔年曾訪此林坰，今日重來倍有情。", "道在山中人不會，竹風柏日總分明。"]'),
('8e0c38c0-783b-4d9b-bd52-08abbb2db14f','再到','汪莘','宋','宋诗','song-poetry','','[]','半近烟村半近城，東園花木鎖柴荆。',32,'全唐诗/poet.song.189000.json','["半近烟村半近城，東園花木鎖柴荆。", "我來獨對南山立，始信陶潛兩眼明。"]'),
('a8e79580-83da-47a1-ada5-91b4909fe987','賀王伯愚登第  其一','葉寘','宋','宋诗','song-poetry','','[]','先君有女嘗擇對，玉雪王郎真可人。',64,'全唐诗/poet.song.189000.json','["先君有女嘗擇對，玉雪王郎真可人。", "連榜舍升俱伯氏，中興家世最名臣。", "回翔璧水十年舊，踴躍龍門三月新。", "從此青霄騰踏上，久知陳孺不長貧。"]'),
('074c7eda-91b1-4e17-9231-79e5a7e474a2','賀王伯愚登第  其二','葉寘','宋','宋诗','song-poetry','','[]','世無羔雁到林泉，惟有登科路坦然。',64,'全唐诗/poet.song.189000.json','["世無羔雁到林泉，惟有登科路坦然。", "我亦門闌多喜色，君今衣鉢得家傳。", "龍旗方照三千字，虎榜爭趨五百仙。", "莫道中年情態薄，華塗名節儘加鞭。"]'),
('8be7040a-a765-4a1a-93dc-e1142cc5797e','壽陳監丞','葉寘','宋','宋诗','song-poetry','','[]','岷峨之秀如雲起，前有三蘇後三李。',216,'全唐诗/poet.song.189000.json','["岷峨之秀如雲起，前有三蘇後三李。", "三蘇專以節行聞，三李相承最工史。", "兩家百年成美談，盛事胡不云東南。", "春風樓前擁三山，秀出君家父子三。", "玉佩瓊琚詞大放，宏博取科跡相望。", "縯綸妙體王者言，下筆仍裁舍人樣。", "君於兄弟尤白眉，天質寬厚心平夷。", "如舟萬斛方整棹，駕揚穩聽天風吹。", "道山蓬萊陳几席，自當席草宮門北。", "玉堂深處覺天低，金鎖開時分夜直。", "人生窮達惟兩途，富貴外物如錙銖。", "生朝相祝何所如，導引願與欒城俱，名節要當參長蘇。", "凜然天地相終始，何獨扁舟載五湖。"]'),
('f161e3fa-c9ea-4118-8e87-14a2f146a2a9','送熊掌熊白','葉寘','宋','宋诗','song-poetry','','[]','熊掌舍魚吾有取，自幼嘗聞子車語。',128,'全唐诗/poet.song.189000.json','["熊掌舍魚吾有取，自幼嘗聞子車語。", "飯香獵戶分熊白，妙語涪翁乃能吐。", "世間兩味果稱珍，故人念我肯珍分。", "數千里致良不易，食美真當持獻君。", "從小知嘗熊膽苦，人不通今寧識古。", "熊皮兀坐二十年，毛去皮存縫誰補。", "人言窮命有時通，老翁八十卜非熊。", "試將兩味從公卜，世間真有磻溪翁。"]'),
('7fa3536d-d8d8-4c15-839b-557c6e3a9004','送玉面貍與月湖','葉寘','宋','宋诗','song-poetry','','[]','迎陽舐掌餐朝霜，虎額分白狐裘黄。',176,'全唐诗/poet.song.189000.json','["迎陽舐掌餐朝霜，虎額分白狐裘黄。", "野人供之未敢嘗，聊比澗沚溪毛將。", "方其潛遯嵌空去，塞向固然知墐戶。", "藏身爲地抑何拙，令人開戶知其處。", "貴重榮稱玉面郎，尾以牛後誇奇章。", "世間醜好誰爭强，賢否一語由臧倉。", "諗季貍兮美南國，範我馳驅非詭獲。", "衣褐褐見脫脫兮，雪綽通身妙藏白。", "人言可以貢金門，芹美猶云欲獻君。", "倘幸珍稱供玉食，全勝肥遯老邱園。", "侑以詩篇煩筆削，詩欠活眼覓一著。"]'),
('c07c78db-4e59-4239-af1e-c0070fb2c416','題壁','馮興宗','宋','宋诗','song-poetry','','[]','眼俗難觀古，時間只順天。',24,'全唐诗/poet.song.189000.json','["眼俗難觀古，時間只順天。", "平生羞詭遇，投老更加鞭。"]'),
('55bd242e-2e74-4fb9-a0a8-73a56aca330f','香巖院','潘景夔','宋','宋诗','song-poetry','','[]','晚入招提路，山風冷透裳。',48,'全唐诗/poet.song.189000.json','["晚入招提路，山風冷透裳。", "寒鴉互分合，霜稻半青黄。", "習訟傷澆俗，思閑慰故鄉。", "牧童如有感，扣角唱斜陽。"]'),
('e3d9e1f0-2078-4e7d-bb4b-9577f4eb71cb','六經閣','韓漪','宋','宋诗','song-poetry','','[]','小樓燈火夜青熒，風撼梧桐客夢驚。',32,'全唐诗/poet.song.189000.json','["小樓燈火夜青熒，風撼梧桐客夢驚。", "誰家更理琴烏曲，誤聽壁間絲竹聲。"]'),
('dfd4b797-3f34-4fd1-b1c9-613a00401a7b','句','蔡任','宋','宋诗','song-poetry','','[]','我與斯民同一性，誰言此邑號三陽。',16,'全唐诗/poet.song.189000.json','["我與斯民同一性，誰言此邑號三陽。"]'),
('12a90cdf-ce33-49ce-a7d8-bb8b9ceb7fa3','浯溪','鍾興嗣','宋','宋诗','song-poetry','','[]','羯奴禍唐室，宗社已傾危。',291,'全唐诗/poet.song.189000.json','["羯奴禍唐室，宗社已傾危。", "翠華幸西蜀，大物孰主持。", "儲君起靈武，事亦從權宜。", "人望既有屬，姦孽就誅夷。", "次山憂國切，聞此喜可知。", "歸美頌君父，隠惡義當爲。", "涪翁仗正論，凜然寓刺規。", "指擿心中過，併及宮闈微。", "茲用春秋法，肅宗其何詞。", "曾無一半語，追咎元子非。", "後來好事輩，往往互詆譏。", "或立黨同意，或費解嘲詩。", "識者具眼力，理解夫奚疑。", "盍觀我宋朝，崖上中興碑。", "光堯再造績，炳若日星垂。", "功成體天道，退處志莫移。", "神器親付授，嗣皇猶懇辭。", "數四不獲命，黽勉祗受之。", "飭躬備敬養，朝夕益孳孳。", "君不見帝典書之盛，端由揖遜基。", "二聖盡慈孝，堯舜並驅馳。", "俯視於李唐，德業有醇疵。", "惟餘尅復願，天每靳其機。", "孫支繼述責，未有易今時。"]'),
('9a36df4f-b0fb-4870-b282-982ac303373e','寶慶改元孟春中澣敬拜十賢於學宮謹哦唐律','汪統','宋','宋诗','song-poetry','','[]','詩書流澤自宮牆，祀謹先賢配孔堂。',64,'全唐诗/poet.song.189000.json','["詩書流澤自宮牆，祀謹先賢配孔堂。", "黄道中天臨下土，清時群牧盛維揚。", "固應奕世思功德，曾與皇家作棟梁。", "生晚敢斯師軌躅，寒泉一勺薦春觴。"]'),
('0b0d257c-5063-45cd-a5d2-940cb3099581','贈水簾洞黄秀才','林干之','宋','宋诗','song-poetry','','[]','讀書避世喧，結廬五雲表。',120,'全唐诗/poet.song.189000.json','["讀書避世喧，結廬五雲表。", "澹泊足生涯，詰曲藏深杳。", "仰觀紅日近，俯視衆山小。", "滄溟舞澎湃，雲氣度浩渺。", "喬松蔓翠蘿，絕壁挂啼鳥。", "一派從天來，長練挂木杪。", "海鷗忘機智，峝蝶驚飛繞。", "亦知山房靜，而被俗客擾。", "作詩寄殷勤，努力須壯少。", "他年騰踏去，蕙帳猿驚曉。"]'),
('5b4a0bf1-2931-40c1-839f-ba25d2e14bae','中和樓','沈大椿','宋','宋诗','song-poetry','','[]','愁少憐詩酒，閒多忽簿書。',48,'全唐诗/poet.song.189000.json','["愁少憐詩酒，閒多忽簿書。", "登樓當白晝，馮檻看清滁。", "風急移凉榻，雲歸想故廬。", "往來橋上客，誰得見長魚。"]'),
('c21689ac-ccaa-44b6-bd79-d4b9bcded5f1','自維揚回儀真','沈大椿','宋','宋诗','song-poetry','','[]','一官安敢問青氈，形影相看祇自憐。',64,'全唐诗/poet.song.189000.json','["一官安敢問青氈，形影相看祇自憐。", "黄鵠已登清漢去，白鷗空占淺沙眠。", "杏花開徧蕪城雨，柳色渾鋪瓜渚烟。", "老眼生疎堪自笑，浪驚風物向淮天。"]'),
('268b95df-a5d8-421a-b902-87ffa8dd296c','扃秀亭  其一','沈大椿','宋','宋诗','song-poetry','','[]','登臨興極未容還，拂拭緇塵扃秀間。',64,'全唐诗/poet.song.189000.json','["登臨興極未容還，拂拭緇塵扃秀間。", "萬事已甘軒鶴老，一身聊擬磧鷗閒。", "灘聲猶带湘江水，野色遥分建業山。", "雅志未容歸騎促，有情斜日尚蒼灣。"]'),
('03ac430b-fb15-4a9d-a73f-50ffcb3f40ca','扃秀亭  其二','沈大椿','宋','宋诗','song-poetry','','[]','倦飛山鳥未能還，心在孤雲疊嶂間。',64,'全唐诗/poet.song.189000.json','["倦飛山鳥未能還，心在孤雲疊嶂間。", "大水雄山須遠適，好風佳月自幽閒。", "非關謝傅當年事，何似周郎舊日山。", "安得此心成獨往，白鷗盟約在江灣。"]'),
('2be3b58a-feab-495b-bbc5-3b254cb88040','自維揚回真州','沈大椿','宋','宋诗','song-poetry','','[]','青蒲短短柳斜斜，入眼新愁亂莫遮。',64,'全唐诗/poet.song.189000.json','["青蒲短短柳斜斜，入眼新愁亂莫遮。", "雨潤固應宜筍蕨，風饕端不貸鶑花。", "春來止酒常因病，客裏逢人祗問家。", "安得扁舟下荆水，一歸老我舊生涯。"]'),
('63fc329a-f157-4388-86df-81dbdbe74958','烟雨奇觀樓','吳機','宋','宋诗','song-poetry','','[]','此景儀真亦有年，何人管領向樓前。',64,'全唐诗/poet.song.189000.json','["此景儀真亦有年，何人管領向樓前。", "江淮自昔雖南北，烟雨從來肯變遷。", "萬里孤帆遺恨在，半空佳句至今傳。", "諸公欲會當時意，且對滄波泛酒船。"]'),
('e62a1340-3b46-4bd6-816c-23940230cdaf','水竹亭','吳機','宋','宋诗','song-poetry','','[]','一泓清水數竿竹，消得詩人爲品題。',32,'全唐诗/poet.song.189000.json','["一泓清水數竿竹，消得詩人爲品題。", "今我公餘無俗事，不妨領客暫提携。"]'),
('00db1869-1a21-46ac-a2c5-e3fe254e8cac','聞凱亭','吳機','宋','宋诗','song-poetry','','[]','調發今年迥不同，折衝果在笑談中。',32,'全唐诗/poet.song.189000.json','["調發今年迥不同，折衝果在笑談中。", "若非制閫規模定，安得兼全戰守功。"]'),
('aa45e70a-82ae-4e97-b846-4f018835abb9','轉幽亭','吳機','宋','宋诗','song-poetry','','[]','從容行樂興無涯，地轉清幽亦可佳。',32,'全唐诗/poet.song.189000.json','["從容行樂興無涯，地轉清幽亦可佳。", "須信居塵塵不染，竹風飄拂爽人懷。"]'),
('7f34e229-34bf-4099-9aaa-2111626b4d20','喜凉亭','吳機','宋','宋诗','song-poetry','','[]','小亭新築藕花邊，爲愛陂塘五月天。',32,'全唐诗/poet.song.189000.json','["小亭新築藕花邊，爲愛陂塘五月天。", "最好一番風雨過，瓊珠無數落清泉。"]'),
('1116d46c-5fe3-4091-8d77-22f9cb347064','漣漪亭','吳機','宋','宋诗','song-poetry','','[]','回環流水漾晴波，一葉扁舟逸興多。',32,'全唐诗/poet.song.189000.json','["回環流水漾晴波，一葉扁舟逸興多。", "寄語遊人恣觀覽，豐年相與樂中和。"]'),
('a437b388-4426-48a9-950f-2c2c1dc1189e','得月亭','吳機','宋','宋诗','song-poetry','','[]','月照乾坤豈得私，只緣近水倍光輝。',32,'全唐诗/poet.song.189000.json','["月照乾坤豈得私，只緣近水倍光輝。", "况逢秋杪氣猶爽，一笑從容盡醉歸。"]'),
('e9fcbc42-f5d7-45d0-b10a-97d2d72fc543','天開圖畫亭  其一','吳機','宋','宋诗','song-poetry','','[]','天造地設非一端，諸公試爲倚闌干。',64,'全唐诗/poet.song.189000.json','["天造地設非一端，諸公試爲倚闌干。", "四時不改江山秀，萬象無窮宇宙寬。", "古往今來還復舊，風清月白不勝寒。", "長淮幸遇豐登歲，得與斯民奠枕安。"]'),
('b8c776ef-7cc6-408f-bbe8-dc52ab10c2ab','天開圖畫亭  其二','吳機','宋','宋诗','song-poetry','','[]','天祐長淮歲屢豐，熙熙還與舊時同。',64,'全唐诗/poet.song.189000.json','["天祐長淮歲屢豐，熙熙還與舊時同。", "月逢元夕清光滿，人在春風和氣中。", "自有儀真無此景，一新圖畫是誰功。", "與民共樂拚沉醉，蚤覺衰顔借酒紅。"]'),
('d82a2c83-ec69-4727-8245-8734f8d4d3a4','句','李一鰲','宋','宋诗','song-poetry','','[]','玉盆應有意，要洗貪者廉。',12,'全唐诗/poet.song.189000.json','["玉盆應有意，要洗貪者廉。"]'),
('5d146920-a58c-41fa-91df-0aba5e21f028','靈泉寺','樓鐩','宋','宋诗','song-poetry','','[]','孺興往事亦難明，對景思人想獨清。',64,'全唐诗/poet.song.189000.json','["孺興往事亦難明，對景思人想獨清。", "黄絹異時留好語，幽泉千古擅佳名。", "五星巧作聯珠勢，一派嘗聞瀉玉聲。", "他日相逢如話舊，也曾到此會簪纓。"]'),
('8b2c3c7e-5008-424d-917f-82180061607c','迴沙閘成用可齋陳公韵','魏峴','宋','宋诗','song-poetry','','[]','一堰限溪江，七鄉利耕稼。',192,'全唐诗/poet.song.189000.json','["一堰限溪江，七鄉利耕稼。", "滷汐回東溟，多水流仲夏。", "仁哉王長官，一勞貽永暇。", "長輸不盡澤，絕勝晴雨乍。", "旱魃縱肆威，恃此不足怕。", "滴水一滴金，欲買真無價。", "年來沙作祟，耄倪憂日夜。", "役夫鍤方舉，賢帥車已下。", "豐貲發公儲，嚴祀闡神舍。", "臨流肅旌騎，問瘼窮隙罅。", "買地開一吭，納水通百汊。", "山判不可移，石級誰敢跨。", "董正有贊府，相視皆別駕。", "仍憂竭尾閭，置柵抵立壩。", "即此是商霖，何必驕陽化。", "它山不可磨，錢秦特其亞。"]'),
('76637f96-d2e0-41cf-a140-3a6df2a4f7a8','它山堰次永嘉薛叔振韵','魏峴','宋','宋诗','song-poetry','','[]','一朝堰此水，千載粒吾民。',48,'全唐诗/poet.song.189000.json','["一朝堰此水，千載粒吾民。", "只仰溪爲雨，何勞旱望雲。", "四時人飲碧，六月稻嘗新。", "流出心源澤，年年惠我鄞。"]'),
('a70cfc15-9c1f-4348-8e14-651773f2aaa5','它山堰','薛叔振','宋','宋诗','song-poetry','','[]','官爲唐令尹，心切禹蒸民。',48,'全唐诗/poet.song.189000.json','["官爲唐令尹，心切禹蒸民。", "疊石流川水，分波及稼雲。", "萬濤驚不夜，千古見如新。", "更有朝宗脈，聲容匪獨鄞。"]'),
('5ee7d644-f19f-40ba-8f97-ac0cd8597ded','題臨安西湖','高孝璹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','珠簾白舫亂湖光，隔岸龍舟艤夕陽。',32,'全唐诗/poet.song.189000.json','["珠簾白舫亂湖光，隔岸龍舟艤夕陽。", "今日歡遊復明日，便將京洛看錢塘。"]'),
('9932bd61-f520-4ecf-bacf-a0b78b6505b8','題王文公祠','高孝璹','宋','宋诗','song-poetry','','[]','虛名自看數椽廬，流毒於今幾卷書。',32,'全唐诗/poet.song.189000.json','["虛名自看數椽廬，流毒於今幾卷書。", "擬代周顒報山鬼，移文逋客請先渠。"]'),
('74be0c03-5841-4207-a9db-20d866d3f854','新亭','徐觀','宋','宋诗','song-poetry','','[]','溪流湯湯，山容林林。',101,'全唐诗/poet.song.189000.json','["溪流湯湯，山容林林。", "公行於亭，鼓瑟鼓琴。", "山禽聒聒，溪石崒崒。", "公休於亭，左經右律。", "山有佳木，侯薪侯蒸。", "尋尺之木，厦屋之楹。", "渒彼容苀舠，蒸徒以顧。", "屹爾中流，恢我王度。", "公無戀斯，民無去思。", "百里之闓，千里之畿。"]'),
('b2591640-0647-4b93-afc9-baa302e759b5','送胡季昭','胡炎','宋','宋诗','song-poetry','','[]','一封朝奏大明宮，吹起廬陵古直風。',64,'全唐诗/poet.song.189000.json','["一封朝奏大明宮，吹起廬陵古直風。", "言路從來天樣闊，蠻烟誰使徑旁通。", "朝中競送長沙傅，嶺表爭迎小澹翁。", "學館諸生空飽飯，臨分憂國意何窮。"]'),
('ef17dd1d-7529-442b-81fe-1c91fbf73381','武夷漫興二首  其一','胡炎','宋','宋诗','song-poetry','','[]','丹梯百丈掛雲門，尺五天高青可捫。',32,'全唐诗/poet.song.189000.json','["丹梯百丈掛雲門，尺五天高青可捫。", "劈破琅玕成老石，當年曾共見曾孫。"]'),
('b6e1bca6-0d81-4719-b4c2-2fb220287358','武夷漫興二首  其二','胡炎','宋','宋诗','song-poetry','','[]','棹轉溪迴生面開，此峰竟作別峰猜。',32,'全唐诗/poet.song.189000.json','["棹轉溪迴生面開，此峰竟作別峰猜。", "雲堆石路迷山脚，忽聽鷄聲縹緲來。"]'),
('576a9f92-48ed-4304-9206-291d155715c0','識時梅歌','謝璡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寇至人遠避，寇退人復歸。',332,'全唐诗/poet.song.189000.json','["寇至人遠避，寇退人復歸。", "歸來尋舊址，草蕪迷荒基。", "哀哉住傍梅，清夢常相依。", "可憐歲寒心，能識存亡機。", "不欲染塵垢，先枯避時虞。", "方今向太平，枯幹生新枝。", "主人修廢墜，古梅仍春輝。", "俗態分榮瘁，梅心無改移。", "如我耐寒友，頭白不相違。", "梅花自奇絕，世事與古別。", "花下獨徘徊，似聽梅花說。", "不願傍官驛，驛外塵飛多馬跡。", "幾番驛使自南來，南枝折盡花狼藉。", "不願在深宮，蛾眉人去壽陽空。", "繽紛簷下花飛片，不上宮粧入草叢。", "不願在西湖，舊時逋仙迹已蕪。", "可惜暗香疎影處，邇來都是給樵蘇。", "不願近東閣，無人更管花開落。", "黄昏風雨鎖朱門，和羹人伴歸沙漠。", "但願開向千巖窟，饕虐馮陵任風雪。", "花香只繞處士廬，花飛不點征人骨。", "吟翁索笑癡更癡，誰似梅花能識時。", "始終不渝含酸味，去就長存調鼎資。", "廣平鐵石筆何在，生死與我深相知。"]'),
('0e7e0c1f-e9c2-4ab0-9623-bce797fce2af','送胡季昭二首  其一','羅茂良','宋','宋诗','song-poetry','','[]','好讀牀頭易一編，盈虛消息總天然。',32,'全唐诗/poet.song.189000.json','["好讀牀頭易一編，盈虛消息總天然。", "崢嶸齒頰皆冰雪，肯怕炎方有瘴煙。"]'),
('37945b78-4d83-4a8e-8c99-5b826974d915','送胡季昭二首  其二','羅茂良','宋','宋诗','song-poetry','','[]','頻寄書回洗我愁，莫言無雁到南州。',32,'全唐诗/poet.song.189000.json','["頻寄書回洗我愁，莫言無雁到南州。", "長相思外加餐飯，計取承君舊話頭。"]'),
('246768e7-c9b5-47ed-a0dc-54a013708932','送曾雲巢被召','羅茂良','宋','宋诗','song-poetry','','[]','泰華山人上赤墀，上嗟安在見何遲。',64,'全唐诗/poet.song.189000.json','["泰華山人上赤墀，上嗟安在見何遲。", "老於尚父投竿日，少似轅生對策時。", "怨鶴驚猿辭舊隠，鞭鸞笞鳳總新知。", "早陳經國平邊策，歸領雲巢舊住持。"]'),
('4d158073-7ba8-4b16-a4fc-09955e434807','鄉禪嵩老集古人佳句成詩編成巨帙以示余欽歎不足輒賦二絕率然悚仄  其一','楊夢信','宋','宋诗','song-poetry','','[]','胸中歷歷古人詩，妙用縱橫自一機。',32,'全唐诗/poet.song.189000.json','["胸中歷歷古人詩，妙用縱橫自一機。", "管得杜韓驚且泣，斕斑要作百家衣。"]'),
('d15932d7-2a55-4ab2-b563-9439a09bfd55','鄉禪嵩老集古人佳句成詩編成巨帙以示余欽歎不足輒賦二絕率然悚仄  其二','楊夢信','宋','宋诗','song-poetry','','[]','學詩元不離參禪，萬象森羅總現前。',32,'全唐诗/poet.song.189000.json','["學詩元不離參禪，萬象森羅總現前。", "觸著見成佳句子，隨機飣餖便天然。"]'),
('ea5e2330-62c5-4688-bd0f-7ec87c5bfdab','番山','方信孺','宋','宋诗','song-poetry','','[]','城根片石久糢糊，圖記應須考國初。',32,'全唐诗/poet.song.189000.json','["城根片石久糢糊，圖記應須考國初。", "欲識番山真面目，至今東北號清虛。"]'),
('81ecaf30-abc2-424e-8158-9a949aa51ff8','禺山','方信孺','宋','宋诗','song-poetry','','[]','禺山何事作番山，空有陂陀迹已漫。',32,'全唐诗/poet.song.189000.json','["禺山何事作番山，空有陂陀迹已漫。", "今日升堂聽絲竹，沉香不見舊闌干。"]'),
('b3d4eb47-0d1e-47c0-9c8f-022c62439ffd','任囂城','方信孺','宋','宋诗','song-poetry','','[]','五星自是漢家符，忍死任囂亦太愚。',32,'全唐诗/poet.song.189000.json','["五星自是漢家符，忍死任囂亦太愚。", "今日朝臺猶百尺，荒城不記舊規模。"]'),
('0657b0cd-5ac7-4d95-83f5-85d3667a3ff0','三城','方信孺','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三城不斷鬰相望，千里長江勢渺茫。',32,'全唐诗/poet.song.189000.json','["三城不斷鬰相望，千里長江勢渺茫。", "蠻獠傳聞亦膽破，從知嶺外有金湯。"]'),
('bb99af09-bff6-4a2f-a1ab-b93aa7eda48b','清海軍樓','方信孺','宋','宋诗','song-poetry','','[]','睥睨旁圍百尺樓，翬飛縹緲接雲浮。',32,'全唐诗/poet.song.189000.json','["睥睨旁圍百尺樓，翬飛縹緲接雲浮。", "鯨波不動海山碧，彈壓東南十四州。"]'),
('728a67b7-a386-4ca4-afc0-e26b4afc456c','五仙觀','方信孺','宋','宋诗','song-poetry','','[]','蹁躚天上五仙人，羊駕何年到海濱。',32,'全唐诗/poet.song.189000.json','["蹁躚天上五仙人，羊駕何年到海濱。", "晉漢相傳半無有，觀中遺石自輪囷。"]'),
('71d1d67f-5673-4b9e-9706-7581e0e054be','廣平堂','方信孺','宋','宋诗','song-poetry','','[]','撤茅易瓦利無窮，盍種甘棠比召公。',32,'全唐诗/poet.song.189000.json','["撤茅易瓦利無窮，盍種甘棠比召公。", "大手斷碑何處覓，典型猶見此堂中。"]'),
('3184d377-62cb-405b-92e7-5f28c9112180','石屏堂','方信孺','宋','宋诗','song-poetry','','[]','月峽旁通玉液池，綵舟爭勝出宮閨。',32,'全唐诗/poet.song.189000.json','["月峽旁通玉液池，綵舟爭勝出宮閨。", "荒臺今日人相問，野草無言日自西。"]'),
('565aae57-c6e2-499c-a22f-47793a59d1a9','十賢祠','方信孺','宋','宋诗','song-poetry','','[]','晉唐相望已千年，香火如今數十賢。',32,'全唐诗/poet.song.189000.json','["晉唐相望已千年，香火如今數十賢。", "不見古人空再拜，祠堂西去有貪泉。"]'),
('dd362358-b5a6-45f9-afd9-980b34866c76','鐵柱','方信孺','宋','宋诗','song-poetry','','[]','崔嵬十二峙乾和，五柱何如馬伏波。',32,'全唐诗/poet.song.189000.json','["崔嵬十二峙乾和，五柱何如馬伏波。", "敗塹頹垣今日見，想曾荆棘漢銅駝。"]'),
('331e5131-a060-43b3-9e94-7bce4b071d93','藥洲','方信孺','宋','宋诗','song-poetry','','[]','沙邱遺臭茂陵空，何物能成九轉功。',32,'全唐诗/poet.song.189000.json','["沙邱遺臭茂陵空，何物能成九轉功。", "地下劉郎猶有媿，駕言聊作葛仙翁。"]'),
('e9497636-aef1-426b-951b-dfb3f313a43b','九曜石','方信孺','宋','宋诗','song-poetry','','[]','九峰參立倚空明，好事傳聞應列星。',32,'全唐诗/poet.song.189000.json','["九峰參立倚空明，好事傳聞應列星。", "運石早知能贖罪，上書何必待緹縈。"]'),
('8298b65f-144c-4776-a06b-a7b9ac97ff7c','越樓','方信孺','宋','宋诗','song-poetry','','[]','真珠市擁碧扶闌，十萬人家着眼看。',32,'全唐诗/poet.song.189000.json','["真珠市擁碧扶闌，十萬人家着眼看。", "獨恨登臨最高處，舉頭猶不見長安。"]'),
('a1b694b0-2c89-467d-b5d3-182eba591f21','南濠','方信孺','宋','宋诗','song-poetry','','[]','經營猶記舊歌謠，來往舟人趁海潮。',32,'全唐诗/poet.song.189000.json','["經營猶記舊歌謠，來往舟人趁海潮。", "風物眼前何所似，揚州二十四紅橋。"]'),
('97a32c12-0811-4995-a80b-9a675ac77914','法性寺','方信孺','宋','宋诗','song-poetry','','[]','金碧參差兜率天，曾煎訶子試新泉。',32,'全唐诗/poet.song.189000.json','["金碧參差兜率天，曾煎訶子試新泉。", "荒園廢宅無人問，門外桃花却是禪。"]'),
('3b771ae5-1770-4934-a96e-0ff4dd47fa9c','風幡堂','方信孺','宋','宋诗','song-poetry','','[]','碓頭一語便投機，若說風幡是落遲。',32,'全唐诗/poet.song.189000.json','["碓頭一語便投機，若說風幡是落遲。", "今日堂中容百衆，不知那箇可傳衣。"]'),
('3692ae1d-4a16-442f-926f-2bd82d4a0ea1','筆授軒','方信孺','宋','宋诗','song-poetry','','[]','制止遺蹤底處尋，相傳筆授此叢林。',32,'全唐诗/poet.song.189000.json','["制止遺蹤底處尋，相傳筆授此叢林。", "毗盧四萬八千卷，正要墨池如許深。"]'),
('d855aec8-45cd-4330-96ad-d8f604456c30','菩提樹','方信孺','宋','宋诗','song-poetry','','[]','庭前雙樹尚依然，何處猶參無樹禪。',32,'全唐诗/poet.song.189000.json','["庭前雙樹尚依然，何處猶參無樹禪。", "一自老盧歸去後，年年長結萬燈緣。"]'),
('3a6d5b7c-249f-4d4d-81b5-c476c25c3044','任囂墓','方信孺','宋','宋诗','song-poetry','','[]','枯墳曾閲幾興亡，行客徘徊古道傍。',32,'全唐诗/poet.song.189000.json','["枯墳曾閲幾興亡，行客徘徊古道傍。", "茅屋一間無處覓，可憐不似楚昭王。"]'),
('0d9817fb-6ea1-488b-b514-231464f65a90','浄慧寺千佛塔','方信孺','宋','宋诗','song-poetry','','[]','九井神光射斗牛，天開寶級鎮南州。',32,'全唐诗/poet.song.189000.json','["九井神光射斗牛，天開寶級鎮南州。", "客船江上東西路，常識嶙峋雲外浮。"]'),
('1f1ad22d-1f18-446c-b78c-bc142154840a','衆妙堂','方信孺','宋','宋诗','song-poetry','','[]','妙處常存道豈高，箇中得意自陶陶。',32,'全唐诗/poet.song.189000.json','["妙處常存道豈高，箇中得意自陶陶。", "空堂寂寞豐碑在，觀裏何人復種桃。"]'),
('c2f620f5-6c14-4f37-a709-83b5b6f86661','劉氏銅像','方信孺','宋','宋诗','song-poetry','','[]','霸業淒涼一炬休，鑄金爲像亦狂謀。',32,'全唐诗/poet.song.189000.json','["霸業淒涼一炬休，鑄金爲像亦狂謀。", "五湖但說鴟夷子，千古誰知恩赦侯。"]'),
('c367a332-5cfd-40ff-ab59-de84b6a17a98','劉氏雙闕','方信孺','宋','宋诗','song-poetry','','[]','雙闕岧嶢即是碑，天荒初破此娥眉。',32,'全唐诗/poet.song.189000.json','["雙闕岧嶢即是碑，天荒初破此娥眉。", "行人來往手加額，解說當年旌表時。"]'),
