('57679f06-1c38-4338-9e3b-8fb2c318c0d8','貪泉','方信孺','宋','宋诗','song-poetry','','[]','泉本無貪人自清，何須一酌始忘情。',32,'全唐诗/poet.song.189000.json','["泉本無貪人自清，何須一酌始忘情。", "回車勝母君知否，見說曾參亦好名。"]'),
('ad582888-f08a-48fc-9189-e023968e9071','沉香浦','方信孺','宋','宋诗','song-poetry','','[]','一飲千金事已非，那容更載此香歸。',32,'全唐诗/poet.song.189000.json','["一飲千金事已非，那容更載此香歸。", "若教到此方投去，早落人間第二機。"]'),
('c2b38a37-acac-47af-b997-b28a422c9018','鑒空閣','方信孺','宋','宋诗','song-poetry','','[]','右带靈洲左石門，何年飛閣倚晴雲。',32,'全唐诗/poet.song.189000.json','["右带靈洲左石門，何年飛閣倚晴雲。", "南遊不用看圖畫，曾向坡仙句裏聞。"]'),
('6124f6dc-9ec4-421f-846b-f51a1533ae30','靈洲','方信孺','宋','宋诗','song-poetry','','[]','東南佳氣盛衣冠，樓閣翬飛縹緲間。',32,'全唐诗/poet.song.189000.json','["東南佳氣盛衣冠，樓閣翬飛縹緲間。", "疑是落星灣上見，更須題作小金山。"]'),
('57bf1277-ce90-44ea-8c5e-ef4dbfbd399f','甘溪','方信孺','宋','宋诗','song-poetry','','[]','甘溪依約舊城東，陵谷遷移一夢中。',32,'全唐诗/poet.song.189000.json','["甘溪依約舊城東，陵谷遷移一夢中。", "春盡踏青人不見，桄榔老大木棉紅。"]'),
('d4d7b408-2cee-4859-946f-95b61e803069','馬蛟山','方信孺','宋','宋诗','song-poetry','','[]','耆老相傳亦可嗟，深山大澤自龍蛇。',32,'全唐诗/poet.song.189000.json','["耆老相傳亦可嗟，深山大澤自龍蛇。", "老蛟變化初何怪，天馬從來産渥洼。"]'),
('267ca7cf-0f51-494f-8b10-ecc1710d1ebd','雷洞','方信孺','宋','宋诗','song-poetry','','[]','疑冢崢嶸此不封，麒麟彷彿是山中。',32,'全唐诗/poet.song.189000.json','["疑冢崢嶸此不封，麒麟彷彿是山中。", "後人未識藏雷穴，踏破蒼苔古甃空。"]'),
('ead739a4-842a-4cd8-9d39-0cc636d5d71d','蒲澗','方信孺','宋','宋诗','song-poetry','','[]','拔宅誰能辨有無，澗邊空記舊丹爐。',32,'全唐诗/poet.song.189000.json','["拔宅誰能辨有無，澗邊空記舊丹爐。", "世間自是多凡骨，何處猶尋九節蒲。"]'),
('050d53c6-d52f-4523-9476-aa264d17f25e','滴水巖','方信孺','宋','宋诗','song-poetry','','[]','天半飛濤六月寒，蒼崖壁立互回環。',32,'全唐诗/poet.song.189000.json','["天半飛濤六月寒，蒼崖壁立互回環。", "從今好事能題品，列作南中第一山。"]'),
('249652ae-fb1d-44a0-a8d1-07cedb070f86','菖蒲觀覺真寺','方信孺','宋','宋诗','song-poetry','','[]','千載仙居已渺茫，道山佛屋自相望。',32,'全唐诗/poet.song.189000.json','["千載仙居已渺茫，道山佛屋自相望。", "春花秋草年年事，却作遊人歌舞場。"]'),
('0efb642e-3be8-4767-95d8-ac89a7e0723d','流杯池','方信孺','宋','宋诗','song-poetry','','[]','坳石天然印曲流，飛觴寂寞幾春秋。',32,'全唐诗/poet.song.189000.json','["坳石天然印曲流，飛觴寂寞幾春秋。", "山陰千古誇陳迹，此地何人記舊遊。"]'),
('42d66d39-922a-4de8-ac22-29cb54cab8b8','葛仙翁煉丹石','方信孺','宋','宋诗','song-poetry','','[]','見說刀圭已解仙，寧須丹竈半人間。',32,'全唐诗/poet.song.189000.json','["見說刀圭已解仙，寧須丹竈半人間。", "葛翁本是求勾漏，何意南來訪此山。"]'),
('cd945682-a8cf-4810-96a1-adcce5593c94','鮑姑井','方信孺','宋','宋诗','song-poetry','','[]','爲覓丹砂到海濱，空山廢井已生塵。',32,'全唐诗/poet.song.189000.json','["爲覓丹砂到海濱，空山廢井已生塵。", "不將一滴蘇焦槁，神艾虛傳解活人。"]'),
('0a210725-6fd8-4d74-b188-978ce155463f','懸鐘','方信孺','宋','宋诗','song-poetry','','[]','絕壁初無路可通，何人特地鑄金鐘。',32,'全唐诗/poet.song.189000.json','["絕壁初無路可通，何人特地鑄金鐘。", "神仙底處應難詰，彈落餘聲和澗松。"]'),
('aac95b70-0177-4c9a-a9b5-1196f28fed0b','刪柏','韓琦','宋','宋诗','song-poetry','','[]','翠柏枝繁鬰未伸，我來刪理務躬親。',64,'全唐诗/poet.song.19000.json','["翠柏枝繁鬰未伸，我來刪理務躬親。", "孤根得地雖經歲，逸勢參天不在人。", "先易工夫知取捨，後凋顔色長精神。", "環材自入他年用，莫厭因時翦擇頻。"]'),
('0ae6d659-b302-419f-a671-0f8763f92354','放泉','韓琦','宋','宋诗','song-poetry','','[]','緩带憑軒喜放泉，映花穿柳逗潺湲。',64,'全唐诗/poet.song.19000.json','["緩带憑軒喜放泉，映花穿柳逗潺湲。", "誰言勝境須崑閬，自有清音過管絃。", "赴海任遥終澤潤，灌園思足尚留連。", "衰翁日寄南窗傲，枕上時醒白晝眠。"]'),
('529b7cfd-1d18-41d0-9011-15729bb4bef5','冬至祀墳','韓琦','宋','宋诗','song-poetry','','[]','至日郊原擁節旄，先塋躬得奉特醪。',64,'全唐诗/poet.song.19000.json','["至日郊原擁節旄，先塋躬得奉特醪。", "霜威壓野寒方重，山色凌虛氣自高。", "衣錦不來夸富貴，報親惟切念劬勞。", "連村父老歡相迓，因勸勤耕候土膏。"]'),
('20d47dd2-0e14-4a24-8706-6e05a73eb121','燒煤戲成','韓琦','宋','宋诗','song-poetry','','[]','無臭含天德，資貧乃地珍。',48,'全唐诗/poet.song.19000.json','["無臭含天德，資貧乃地珍。", "羣陰徒肆暴，萬室自融春。", "豐黍輕鄒律，歌襦陋蜀民。", "何妨灰棄道，仁政不同秦。"]'),
('3231a6ee-42cc-453b-9ae6-68cab5296eee','悲二木','韓琦','宋','宋诗','song-poetry','','[]','偃蓋孤松挺北軒，亭亭雙柏寢堂前。',64,'全唐诗/poet.song.19000.json','["偃蓋孤松挺北軒，亭亭雙柏寢堂前。", "干霄夭矯蒼龍上，當戶陰森翠幄圓。", "百歲生成猶易枿，近時栽葺欲誰憐。", "居官好惡宜加謹，詩拙徒思警後賢。"]'),
('85e00004-392e-4f90-b483-44f0a2f5e3f6','喜雪','韓琦','宋','宋诗','song-poetry','','[]','昨夜同雲徹曉陰，雪牀輕襯六花深。',64,'全唐诗/poet.song.19000.json','["昨夜同雲徹曉陰，雪牀輕襯六花深。", "一開帝扆憂民慮，普慰農疇望歲心。", "天興酒徒張醉幕，家疑仙室盡瑶林。", "喜憑休逸臺西檻，羣玉高低聳萬岑。"]'),
('a8a45e3d-36dd-42f8-9cff-726d43242ad3','雪霽登休逸臺','韓琦','宋','宋诗','song-poetry','','[]','休逸臺頭雪乍晴，病眸雖澁亦增明。',64,'全唐诗/poet.song.19000.json','["休逸臺頭雪乍晴，病眸雖澁亦增明。", "幾年無此三農樂，萬物皆隨一氣清。", "修竹拒寒森晚節，垂楊偷潤裊春情。", "當軒欲繪西山景，巧筆何人似李成。"]'),
('a9e6afd2-9592-47bb-b187-49d594143da7','謝觀文趙尚書寄示集注老子','韓琦','宋','宋诗','song-poetry','','[]','公今重釋五千言，一法專求是要詮。',64,'全唐诗/poet.song.19000.json','["公今重釋五千言，一法專求是要詮。", "天道生成忘萬物，師人功業在羣賢。", "世塵甚擾吾何欲，謙柄常持彼任先。", "治國治身非異理，雨無心迹自安然。"]'),
('ea47db24-2c1f-4254-a60c-90042f2104c4','雙磑','韓琦','宋','宋诗','song-poetry','','[]','一渠遐引直千金，對激雙輪用智深。',64,'全唐诗/poet.song.19000.json','["一渠遐引直千金，對激雙輪用智深。", "本務愛民除歲患，且非爲政有機心。", "重羅撼雪收長利，嘉植成帷展舊陰。", "來者相沿知日盛，肯教前作入煙沈。"]'),
('6bae4b8f-e5c5-4068-9a63-896c1dfc0723','壕林','韓琦','宋','宋诗','song-poetry','','[]','鹿角科民歲甚勞，故栽榆柳匝城壕。',64,'全唐诗/poet.song.19000.json','["鹿角科民歲甚勞，故栽榆柳匝城壕。", "駢枝豈下笓籬密，聳幹將凌埤堄高。", "扞蔽莫先輕枳棘，森嚴無日挺干旄。", "霜斤謹勿窺微利，惜取金湯四面牢。"]'),
('16e15d10-b16d-4b55-95a0-94b09d382176','元日祀墳馬上','韓琦','宋','宋诗','song-poetry','','[]','三朝徧喜得晴和，歲美民康此驗多。',64,'全唐诗/poet.song.19000.json','["三朝徧喜得晴和，歲美民康此驗多。", "天運主生方啟戶，土膏乘暖已騰波。", "雪憑空闊高低在，風引韶妍次第過。", "霽靄正開先隴近，太行晡景上嵯峨。"]'),
('b3c258c5-3948-45de-bb60-6a48432a6ad1','栽花二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','名園嘗已植羣芳，更得新株補舊行。',32,'全唐诗/poet.song.19000.json','["名園嘗已植羣芳，更得新株補舊行。", "非欲後來傳好事，只圖芬馥滿吾鄉。"]'),
('445250d3-e187-4fcb-a29c-afe0c1ef5295','栽花二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','百品名花手種來，復尋嘉艷及時栽。',32,'全唐诗/poet.song.19000.json','["百品名花手種來，復尋嘉艷及時栽。", "主人便去心無恨，從向東風自在開。"]'),
('f06ff220-cfcf-449e-b3c7-34fa58006f65','次韻答并帥王仲儀端明以詩見寄','韓琦','宋','宋诗','song-poetry','','[]','退削嘗連上，清衷遂一開。',120,'全唐诗/poet.song.19000.json','["退削嘗連上，清衷遂一開。", "調元辭重任，殄寇倚非才。", "虎士方爭奮，羌雛已訴哀。", "遽馳金節覲，俄得錦衣回。", "雅契瞻并府，衰容病鄴臺。", "孤懷難託雁，芳信忽傳梅。", "瑇瑁遥賓席，蒲萄入醉杯。", "高談嗟阻闊，危榭幾徘徊。", "大鹵誠淹帥，中樞即貳台。", "三槐東第甲，還似相車來。"]'),
('eac59ff9-6400-43b6-b635-f41ba4e9ceb3','次韻答宮保張相公以長篇見寄','韓琦','宋','宋诗','song-poetry','','[]','睿師當亨會，真賢上貴途。',288,'全唐诗/poet.song.19000.json','["睿師當亨會，真賢上貴途。", "驥程輕歷塊，鵬運狹搶榆。", "大器方膺用，清風自少徒。", "危言忘世忌，直道得神扶。", "廩粟常周急，囊衣異弗婁。", "臨戎資遠略，進讀待名儒。", "位峻升中執，胡驕賴北狙。", "殊隣摧桀驁，正路屏榛蕪。", "機務參籌幄，恬波靜海隅。", "高名喬嶽重，勁節老松孤。", "眾望歸鈞席，羣生入化罏。", "幽遐通滯塞，愁鬰變怡愉。", "明哲咸推甫，深忠獨許壺。", "上樞俄任德，冢輔適容愚。", "清燕常陪論，丹誠得盡輸。", "協心安國本，罄宇保民蘇。", "知止頻思退，遺榮遂懇圖。", "連章傾悃愊，重責厭憂虞。", "物議皆嗟去，宸言勉賜俞。", "四朝全始卒，一代足師模。", "恣逐林泉樂，幾忘僕馬痡。", "韓城窮近賞，嵩谷喜深趨。", "飛溜星分派，奇峰笋迸株。", "買山兼勝得，卜宅與真俱。"]'),
('c9807fce-a0bd-478d-ba40-7f2d38a6d751','留題相州王珫推官園亭','韓琦','宋','宋诗','song-poetry','','[]','王氏名園枕子城，主人方壯便遺榮。',64,'全唐诗/poet.song.19000.json','["王氏名園枕子城，主人方壯便遺榮。", "栽花直欲春長在，愛客誰尤囊盡傾。", "萬景併歸閑日月，一身常寄小蓬瀛。", "吾居甚邇還空鎖，不退堪爲達士輕。"]'),
('e03b63d8-68c4-4407-b8c9-7efcd2db5834','次韻答王拱辰宣徽將交政惠詩','韓琦','宋','宋诗','song-poetry','','[]','適辭鄉邑入平川，春惱輕寒未禁煙。',64,'全唐诗/poet.song.19000.json','["適辭鄉邑入平川，春惱輕寒未禁煙。", "金印此時交大府，銀袍當日接英躔。", "清衷正渴攄賢藴，窳質前知在化甄。", "衰病早期還舊里，不循公迹住三年。"]'),
('3883c7b2-fec4-4519-8658-97caa26ce179','上巳屬疾','韓琦','宋','宋诗','song-poetry','','[]','去年修禊小龍池，醉席高吟盛一時。',64,'全唐诗/poet.song.19000.json','["去年修禊小龍池，醉席高吟盛一時。", "今日正逢春駘蕩，此身翻苦病支離。", "浮觴勝會人胥樂，閉閣衰悰自不知。", "御水有期猶半月，雨餘風景願遲遲。"]'),
('38528bf7-5325-48c0-8e31-8a01292de875','會食許公亭','韓琦','宋','宋诗','song-poetry','','[]','許公亭館壓通津，强率羸軀接會賓。',64,'全唐诗/poet.song.19000.json','["許公亭館壓通津，强率羸軀接會賓。", "萬隴得苗經飽雨，滿車餘粟有歸民。", "退花杏小驚春晚，繫馬蔬柔辨食珍。", "風伯入讒憎樂事，怒號終日走埃塵。"]'),
('7223d215-9e32-4e83-8522-2f68410a3ea6','扶溝宰周源來求二蘇兄弟留題于白鶴觀詩','韓琦','宋','宋诗','song-poetry','','[]','二蘇遺筆匿仙扃，賢宰來求爲發明。',64,'全唐诗/poet.song.19000.json','["二蘇遺筆匿仙扃，賢宰來求爲發明。", "字久半隨風雨剝，氣豪猶入鬼神驚。", "終疑鸞鳳騫雲去，不假江山到骨清。", "人對盛時須自勉，醉吟顛草尚垂名。"]'),
('40cb153a-dd93-4729-a538-f7f8c469cd3b','次韻答子淵趙學士','韓琦','宋','宋诗','song-poetry','','[]','再乞鄉邦遂志艱，十年方得見家山。',64,'全唐诗/poet.song.19000.json','["再乞鄉邦遂志艱，十年方得見家山。", "晝衣麗錦過前寵，秋逼衰蒲失舊顔。", "數月又遷當冗劇，一生曾未識安閑。", "故人千里無由愬，賴有詩筒去復還。"]'),
('1b309a99-7fe4-4468-a7cb-989045f05fc0','再答二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','從來交分擬金蘭，一紀前同陟道山。',64,'全唐诗/poet.song.19000.json','["從來交分擬金蘭，一紀前同陟道山。", "君畜高才終未偶，我居榮路獨何顔。", "鄴臺將卜全身退，洛宅先輸任意閑。", "感舊倚樓空自歎，不如飛翼倦知還。"]'),
('599d67bf-565e-4d9e-8e30-fe3cecf13d47','再答二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','退謀休洛勇難攀，性得清虛不在山。',64,'全唐诗/poet.song.19000.json','["退謀休洛勇難攀，性得清虛不在山。", "十畝足居應慕白，一瓢猶樂直師顔。", "誰論世路風波惡，漸見仙家日月閑。", "我亦安陽蝸舍就，羨君殊欲幅由還。"]'),
('b466af1e-d6af-47a2-86b8-634309313f36','寄致政趙少師','韓琦','宋','宋诗','song-poetry','','[]','雨曾擎日上高天，遽脫浮榮請退堅。',64,'全唐诗/poet.song.19000.json','["雨曾擎日上高天，遽脫浮榮請退堅。", "寵殿大邦方異禮，確申前懇甫踰年。", "三師共仰青宮貴，四海皆稱白傅賢。", "自顧衰殘歸未得，幾時平地接神仙。"]'),
('ff8dafe4-0243-49fe-89cf-e05562566146','又寄二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','月榭風亭勝雅名，主公閑適愈多情。',32,'全唐诗/poet.song.19000.json','["月榭風亭勝雅名，主公閑適愈多情。", "芳樽屢酌瀛洲上，誰聽霓裳散序聲。"]'),
('c07dfed7-8994-4254-9ea2-3fa31625e38e','又寄二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','到處園亭列畫屏，四時如只在仙扃。',32,'全唐诗/poet.song.19000.json','["到處園亭列畫屏，四時如只在仙扃。", "歸來便是無爲樂，不必重箋道德經。"]'),
('a1813757-5269-4276-97f9-2675bfc417a7','登望宸閣','韓琦','宋','宋诗','song-poetry','','[]','危閣輕裘陟望宸，欲逃蒸暑若憂焚。',64,'全唐诗/poet.song.19000.json','["危閣輕裘陟望宸，欲逃蒸暑若憂焚。", "清風自越兼金貴，真境都無數仞分。", "歸渚水禽明似雪，擾空沙燕鬧如蚊。", "憑軒眷闕羈魂斷，亂逐南飛送雨雲。"]'),
('8aa88b3f-6a3e-4027-8d6f-d8aa6234f0c6','登金銅門','韓琦','宋','宋诗','song-poetry','','[]','當暑思來坐北軒，俯看形勝在簷前。',64,'全唐诗/poet.song.19000.json','["當暑思來坐北軒，俯看形勝在簷前。", "樓臺突兀陵高木，城堞縈回際遠天。", "萬室正虞多暍者，一身慚獨御泠然。", "歊煩盡滌無心下，欲帳輕綃徹夜眠。"]'),
('eb575d51-7cda-41cc-bbf0-e8d2ba5f3dcb','立秋日後園','韓琦','宋','宋诗','song-poetry','','[]','亭館雖蕪勝勢存，病襟猶足滌冥昏。',64,'全唐诗/poet.song.19000.json','["亭館雖蕪勝勢存，病襟猶足滌冥昏。", "晚凉天氣秋風入，雨霽園林伏暑奔。", "古榭穩騎危岫翠，御流遥瀉曲池渾。", "河魚未獲山芎效，幾廢良辰命客樽。"]'),
('60a022c8-fe74-4058-b6c0-2f0ea393c979','己酉中元','韓琦','宋','宋诗','song-poetry','','[]','煩蒸求得到中元，餘酷侵人尚鮮歡。',64,'全唐诗/poet.song.19000.json','["煩蒸求得到中元，餘酷侵人尚鮮歡。", "病塞不能衝酒堰，氣清終已倒盂蘭。", "陳編就榻將開懶，危閣凌風欲下難。", "聞道禾弮盡踰尺，日西偏喜夕霞丹。"]'),
('4aeca907-c499-4f09-a2bc-c0a8c8f753fe','中秋席上','韓琦','宋','宋诗','song-poetry','','[]','去年西洛過中秋，正怯清光刺病眸。',64,'全唐诗/poet.song.19000.json','["去年西洛過中秋，正怯清光刺病眸。", "此夜北都逢好月，喜延嘉客上高樓。", "真居自與風塵絕，雅句須窮造化搜。", "但引流霞歌白雪，豈殊身在廣寒遊。"]'),
('fcb22ad6-d8b5-46bb-86ff-039f06bfe062','九日水閣','韓琦','宋','宋诗','song-poetry','','["\u5bb4\u996e", "\u8d5e\u7f8e", "\u91cd\u9633\u8282", "\u54c1\u683c", "\u8d4f\u82b1"]','池館隳摧古榭荒，此延嘉客會重陽。',64,'全唐诗/poet.song.19000.json','["池館隳摧古榭荒，此延嘉客會重陽。", "雖漸老圃秋容淡，且看寒花晚節香。", "酒味已醇新過熱，蟹黄先實不須霜。", "年來飲興衰難强，漫有高吟力尚狂。"]'),
('f9b79989-e352-4530-bc8d-6562930e984f','次韻和機宜强至都官喜雪','韓琦','宋','宋诗','song-poetry','','[]','繁雲凝結遠成堆，雪意應隨雅客來。',64,'全唐诗/poet.song.19000.json','["繁雲凝結遠成堆，雪意應隨雅客來。", "滿地粧梅知臘近，一天風絮誤春迴。", "玳欹賓席豪詩筆，珠沃歌喉滑醉杯。", "病叟有心萌酒戰，明轟鐘鼓不銜枚。"]'),
('f7b9fbf2-4921-4b5e-86c4-edfcc0668058','次韻再答','韓琦','宋','宋诗','song-poetry','','[]','天和人意共昏昏，飄擲繁霙助客樽。',64,'全唐诗/poet.song.19000.json','["天和人意共昏昏，飄擲繁霙助客樽。", "正會笙歌開醉目，忽驚珠玉得嘉言。", "已凌衰鬢爭霜采，更拂妖顔上粉痕。", "東閣有賢才調雅，媿無優禮紹公孫。"]'),
('47dca9d7-c839-4bff-b5eb-6f2593f41508','雅集堂','韓琦','宋','宋诗','song-poetry','','[]','過馬傳名事莫詳，我嚴賓集在更張。',64,'全唐诗/poet.song.19000.json','["過馬傳名事莫詳，我嚴賓集在更張。", "不資金石升堂樂，務接芝蘭入室香。", "農穫大豐歌滯穗，訟銷羣枉閴甘棠。", "時聞雅席延諸彥，病守心閒興亦長。"]'),
('f243cba2-b39e-48aa-bbd5-b256dba1dc80','望宸閣雪後','韓琦','宋','宋诗','song-poetry','','[]','重陰初釋六花殘，試倚危欄一望看。',64,'全唐诗/poet.song.19000.json','["重陰初釋六花殘，試倚危欄一望看。", "魂爽頓如居物外，句新難得上毫端。", "酒收豪席珊瑚碎，風刮仙盤沆瀣乾。", "化就兜羅綿世界，鷲宮高插白雲寒。"]'),
('36e49f4e-5e93-457f-888a-6d15c846b41d','己酉歲除夜雪','韓琦','宋','宋诗','song-poetry','','[]','故曆將除夜未晨，暖風輕送六霙勻。',64,'全唐诗/poet.song.19000.json','["故曆將除夜未晨，暖風輕送六霙勻。", "及時皆喜逢三白，伺曉何妨具五辛。", "一箭尚留終在臘，萬花潛發欲驚春。", "藏鬮令惡傳杯速，歡殺紅爐守歲人。"]'),
('00741436-08be-4a32-8436-d68c429a6c98','春陰席上','韓琦','宋','宋诗','song-poetry','','[]','臘寒初破作春陰，澌澁銅烏遠漏沉。',64,'全唐诗/poet.song.19000.json','["臘寒初破作春陰，澌澁銅烏遠漏沉。", "氣折笙簧聲易軟，澗勻梅柳色潛深。", "已催豪俠將狂興，更惱衰殘欲病心。", "任展輕銷誰畫得，霧昏樓閣半遥林。"]'),
('03877d08-58ea-401d-9a66-63edf6a5e109','龍興燈夕','韓琦','宋','宋诗','song-poetry','','[]','花雨交加墜寶坊，萬燈全掩玉蟾光。',64,'全唐诗/poet.song.19000.json','["花雨交加墜寶坊，萬燈全掩玉蟾光。", "幾時蓮與春風偶，此夜人如蠟日狂。", "欲樂一知趨壽域，路迷無處不仙鄉。", "當筵自是壺中景，莫訪金吾漏短長。"]'),
('badb546c-c609-4f00-955f-6ade9400184a','上元遇雨席上','韓琦','宋','宋诗','song-poetry','','[]','此夕濃陰送雨來，冥然天意可輕猜。',64,'全唐诗/poet.song.19000.json','["此夕濃陰送雨來，冥然天意可輕猜。", "欲催嘉卉乘時發，似抑妖蓮作僞開。", "强沸金絲終斷續，半濡羅綺尚徘徊。", "待前一任游人散，且聽新聲盡醉疊。"]'),
('e4125d68-1c35-4a03-9b52-93e6923ea38e','春雪','韓琦','宋','宋诗','song-poetry','','[]','幾陣風凝霰作牀，穩承花雪入春芳。',64,'全唐诗/poet.song.19000.json','["幾陣風凝霰作牀，穩承花雪入春芳。", "南園蝶舞都疑夢，北嶺梅開只欠香。", "氣暖不容冰笋就，潤深潛引麥針長。", "衰翁未得陽和助，且自宜城抵醉鄉。"]'),
('b3d8e16f-25c5-4085-8e71-17f4ba7189f4','中和節後園','韓琦','宋','宋诗','song-poetry','','[]','半銷殘雪在庭柯，寂寞園林試强過。',64,'全唐诗/poet.song.19000.json','["半銷殘雪在庭柯，寂寞園林試强過。", "正病寒威連月困，不知春色一朝多。", "小桃樓角香心動，百舌枝頭語意和。", "促理新聲加釀酒，只憂韶景去如梭。"]'),
('37e11ea6-9935-4eee-8091-d2ecfcde12d9','仲春釋奠','韓琦','宋','宋诗','song-poetry','','[]','明祀嚴先甲，喜辰歷上丁。',48,'全唐诗/poet.song.19000.json','["明祀嚴先甲，喜辰歷上丁。", "采芹因舊館，釋菜協前經。", "俎豆由斯學，粢盛信匪馨。", "欲知時祭重，百世仰儀刑。"]'),
('9c84b19c-03c7-466c-8022-58fe92f37b89','康戌二月十六日寒食會雅集堂','韓琦','宋','宋诗','song-poetry','','[]','百五嘉辰此命筵，中分春色極芳妍。',64,'全唐诗/poet.song.19000.json','["百五嘉辰此命筵，中分春色極芳妍。", "花遺嫩靨饒風地，雲坼輕陰半雨天。", "淑景萬容粧節物，勝游千路入神仙。", "酣杯莫顧歸時夜，藏火難逢月尚圓。"]'),
('4a9d8e41-2949-4a08-bee8-2be620421bc3','會壓沙寺觀梨花','韓琦','宋','宋诗','song-poetry','','[]','同賞利花過浄坊，壓沙幽閴面平岡。',64,'全唐诗/poet.song.19000.json','["同賞利花過浄坊，壓沙幽閴面平岡。", "孤園不治黄金界，醉筆徒誇白雪香。", "風急幾翻雲影亂，殿深全掩玉毫光。", "朝來經雨低含淚，競寫真妃寂寞粧。"]'),
('0e474c4f-549f-4101-8def-b7e12cd56922','次韻和宋適推官壓沙惠詩','韓琦','宋','宋诗','song-poetry','','[]','天知人意喜春娛，故作輕雲捲復舒。',64,'全唐诗/poet.song.19000.json','["天知人意喜春娛，故作輕雲捲復舒。", "風撼花飛鋪宴席，雨平沙穩助流車。", "蛾顰嫩葉初眠柳，馬茁柔椿未薦蔬。", "何必笙歌喧坐上，且延歡伯侍香裾。"]'),
('d405b500-a518-46d9-8767-92cca16acf62','過全福寺','韓琦','宋','宋诗','song-poetry','','[]','伊昔豪英襲將牙，更崇因果欲何加。',64,'全唐诗/poet.song.19000.json','["伊昔豪英襲將牙，更崇因果欲何加。", "精藍世自傳緇服，繪像塵誰障碧紗。", "詩好盈編堆錦組，字奇隨筆走龍蛇。", "空餘舊史高風在，衰替嗟吾外氏家。"]'),
('78386f2f-ba1d-4f7d-bca8-8ad1e5310b71','上巳會許公亭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','三月三來御水涯，古亭春色綠相遮。',64,'全唐诗/poet.song.19000.json','["三月三來御水涯，古亭春色綠相遮。", "牡丹已認冠叢葉，郁李真疑綬引花。", "侍妓寢歌成雅席，惡風吹酒入微沙。", "土囊終夕從飄怒，不障清歡祓禊家。"]'),
('4d6cd754-73dd-4436-a2b3-d32b4c385e3b','上巳會許公亭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','元巳乘閑到許亭，勝遊差遠幾開扃。',64,'全唐诗/poet.song.19000.json','["元巳乘閑到許亭，勝遊差遠幾開扃。", "尋春自失花顔素，愛客偏回柳眼青。", "曲水事遥存燕喜，甘棠人去想儀形。", "禊筵莫愬杯行數，歸轡迎風酒易醒。"]'),
('c85a0140-7867-41ed-b61b-aa2dee893da6','次韻和通判錢昌武郎中上巳許公亭惠詩','韓琦','宋','宋诗','song-poetry','','[]','亭館蕭然古岸頭，園林雖雅背清流。',64,'全唐诗/poet.song.19000.json','["亭館蕭然古岸頭，園林雖雅背清流。", "感時堪惜芳菲過，拖病須從祓禊遊。", "歸艦逆風乘醉去，落花隨水带香浮。", "貳車欲繼山陰事，立賦新篇不易酬。"]'),
('3ade2a26-f662-4f4d-9440-088ca1a8f36e','次韻和留守宋适推官遊宴御河二首  其一','韓琦','宋','宋诗','song-poetry','','[]','笳鼓齊喧泛御津，何妨同欲樂茲辰。',64,'全唐诗/poet.song.19000.json','["笳鼓齊喧泛御津，何妨同欲樂茲辰。", "中三節物初過五，八十春光未破旬。", "紅旆厭風收電脚，綠波傷櫂散魚鱗。", "欲知治世昇平象，請看熙熙兩岸民。"]'),
('eaad7876-c3e9-405f-8b5e-1ecf173fae35','次韻和留守宋适推官遊宴御河二首  其二','韓琦','宋','宋诗','song-poetry','','[]','三月春容駘蕩天，御流飛舸引雙旜。',64,'全唐诗/poet.song.19000.json','["三月春容駘蕩天，御流飛舸引雙旜。", "十分芳景無三二，四合游人有萬千。", "花任風殘猶逐水，酒隨歌半已空船。", "病夫且伴嘉賓醉，不過明朝卯尚眠。"]'),
('0b1293f4-a74e-4397-9ab3-b5f40f069d7b','三月十八日上水關','韓琦','宋','宋诗','song-poetry','','[]','河曲春遊得舊傳，使君從俗上蘭船。',64,'全唐诗/poet.song.19000.json','["河曲春遊得舊傳，使君從俗上蘭船。", "低篷密罩香羅綺，小艇交颺細管絃。", "有獻滿盤烘芍藥，競豪臨水落鞦韆。", "歸來夾岸民觀甚，望遠應疑李郭仙。"]'),
('9ce462ce-8612-48db-9bef-adbb3eda723d','三月十八日會望春亭','韓琦','宋','宋诗','song-poetry','','[]','此日傾城樂御河，作河生日語應訛。',64,'全唐诗/poet.song.19000.json','["此日傾城樂御河，作河生日語應訛。", "波涵祛服千花亂，風壯歡聲萬曲和。", "元巳嬉遊非俗尚，十洲光景得春多。", "衰翁欲盡都人興，醉弁歸同夕照俄。"]'),
('95278ca8-2790-4a95-971a-83b681d36b44','西園初暑','韓琦','宋','宋诗','song-poetry','','[]','可愛西園夏景長，南來風好拂襟凉。',64,'全唐诗/poet.song.19000.json','["可愛西園夏景長，南來風好拂襟凉。", "樓臺軒豁年殊舊，池沼乾枯雨未滂。", "羣鳥護雛時起鬭，眾花成子幾堪嘗。", "欲知逃暑芳樽味，似過林禽玉溜漿。"]'),
('61d66416-fbee-4027-88d3-9ad790d1ee0a','寄西臺子淵趙學士','韓琦','宋','宋诗','song-poetry','','[]','昔年瀛館接仙才，官路升沈孰可猜。',64,'全唐诗/poet.song.19000.json','["昔年瀛館接仙才，官路升沈孰可猜。", "直使庸駑叨上笏，却教賢傑老西臺。", "莫悲居處荒三徑，且把功名寄一杯。", "應笑位高歸去晚，謗多終日怒蚊雷。"]'),
('6ee35448-9fb5-47ad-b323-a802568e004e','苦熱未雨','韓琦','宋','宋诗','song-poetry','','[]','驕陽爲虐極煩歊，萬物如焚望沃焦。',64,'全唐诗/poet.song.19000.json','["驕陽爲虐極煩歊，萬物如焚望沃焦。", "舉世不能逃酷吏，幾時還得快凉飚。", "精祈擬責泥龍效，大索誰誅旱魃妖。", "翹首岱雲膚寸起，四方膏澤盡良苗。"]'),
('7b4d47e9-4d74-4417-adb0-b3af17d00c12','雨足晚晴','韓琦','宋','宋诗','song-poetry','','[]','掣電搜龍發怒雷，欲驅時旱滌民災。',64,'全唐诗/poet.song.19000.json','["掣電搜龍發怒雷，欲驅時旱滌民災。", "四溟滂澤三農足，萬宇愁襟一夕開。", "虹影漸從天外散，蟬聲初到枕邊來。", "高樓小酌清風滿，不勝當年避暑杯。"]'),
('f8279ab2-31c5-468c-8747-5d7ba0819959','庚戌秋分','韓琦','宋','宋诗','song-poetry','','[]','淅淅風清葉未凋，秋分殘景自蕭條。',64,'全唐诗/poet.song.19000.json','["淅淅風清葉未凋，秋分殘景自蕭條。", "禾頭無耳時微旱，蚊嘴生花毒漸消。", "錢迸嫩苔陳閣靜，字橫賓雁楚天遥。", "西園宴集偏宜夜，坐看圓蟾過麗譙。"]'),
('28bc3c9f-dbee-4fc7-a4a8-e827b952edd6','中秋遇雨','韓琦','宋','宋诗','song-poetry','','[]','待月中秋一肆筵，雨輕雲晦似無緣。',64,'全唐诗/poet.song.19000.json','["待月中秋一肆筵，雨輕雲晦似無緣。", "何須寒影摇杯面，且命高歌醉目前。", "莫向此宵空悵望，定應明夜亦嬋娟。", "憑欄可奈時人意，不愛清光只重圓。"]'),
('1e1a7b8f-6a52-4337-8b5a-8c168e6dba0e','次韻和通判錢昌武郎中中秋遇雨','韓琦','宋','宋诗','song-poetry','','[]','靈祠躬禱極伸虔，唯恐愆陽病晚田。',64,'全唐诗/poet.song.19000.json','["靈祠躬禱極伸虔，唯恐愆陽病晚田。", "不恨高樓空宴月，却欣豐澤入民天。", "且歌多稼將棲畝，莫賦嘉期動隔年。", "媿誤賓軒侵夜散，阻看銀界爛三千。"]'),
('03d1e276-d033-489f-9f59-431eeee07ff7','中秋筵散雨餘見月色','韓琦','宋','宋诗','song-poetry','','[]','正苦中秋暝雨侵，忽驚凉月綻雲深。',64,'全唐诗/poet.song.19000.json','["正苦中秋暝雨侵，忽驚凉月綻雲深。", "壺光未透冰涵玉，鑑影微昏蘚上金。", "彩筆怨吟幾絕望，巨觥酣戰欲重尋。", "孀娥似慰人心鬰，時放蟾輝漏薄陰。"]'),
('d4d0645c-9119-483b-a802-6bade2726257','重九會安正堂','韓琦','宋','宋诗','song-poetry','','[]','欲安衰朽敞虛堂，竊信孤忠敢自當。',64,'全唐诗/poet.song.19000.json','["欲安衰朽敞虛堂，竊信孤忠敢自當。", "本幸歲時同眾樂，適開樽俎遇重陽。", "黄花旋插香環坐，翠嶺新成妙出牆。", "留與鄴都爲故事，年年常占好風光。"]'),
('96f5688c-3026-4c2a-b192-34aba4393b2a','重九晚登騎山樓','韓琦','宋','宋诗','song-poetry','','[]','蕭疎嘉節得陽重，病守西園此又逢。',64,'全唐诗/poet.song.19000.json','["蕭疎嘉節得陽重，病守西園此又逢。", "且奉賓歡窮勝事，莫悲秋色動衰容。", "管喧銀字凌歌席，菊碎金鈴上醉鐘。", "何必更臨高處會，北樓深古近騎峯。"]'),
('4a8a454f-79ab-44ce-99c9-0538752f969c','壓沙寺梨','韓琦','宋','宋诗','song-poetry','','[]','壓沙千畝敵侯封，珍果誠非眾品同。',64,'全唐诗/poet.song.19000.json','["壓沙千畝敵侯封，珍果誠非眾品同。", "自得嘉名過冰蜜，誰知精別有雌雄。", "常滋沆瀣充肌脆，不假燕脂上頰紅。", "四海舉皆推美味，任從潘賦紀張公。"]'),
('11f64132-4c67-4e93-80b9-ea338cf49d8d','送卿師上人','韓琦','宋','宋诗','song-poetry','','[]','區區京轂幾經春，不退方能運法輪。',64,'全唐诗/poet.song.19000.json','["區區京轂幾經春，不退方能運法輪。", "欲舉筌蹄皆自達，縱羅寒暑豈吾辛。", "大千雖納寧多施，一切誰名得度人。", "我已心中了無物，重煩師說究微塵。"]'),
('62189e8b-1cc9-478b-b756-564eefbf1e93','送謝山人歸紫霄舊隱','韓琦','宋','宋诗','song-poetry','','[]','董君壇側杏林新，高卧雲霞獨一身。',64,'全唐诗/poet.song.19000.json','["董君壇側杏林新，高卧雲霞獨一身。", "已究丹經成大藥，更居仙府得長春。", "仁心務濟誰思報，道術逢知即示真。", "暫別山來應自笑，紫霄曾未識紅塵。"]'),
('72df93d5-8bd5-4fd8-b718-258af74bcccd','通判錢昌武代歸以詩見別次韻爲答','韓琦','宋','宋诗','song-poetry','','[]','衰病何堪治鄴臺，貳車猶喜得高才。',64,'全唐诗/poet.song.19000.json','["衰病何堪治鄴臺，貳車猶喜得高才。", "方資庖刃投虛利，忽愴瓜時及代回。", "別袂醉分雲共慘，去塗塵寂雪初培。", "劍光久已衝牛斗，力振沈埋尚愧雷。"]'),
('70d6c958-4eaa-448d-a377-4f22075b5eb5','屢雪','韓琦','宋','宋诗','song-poetry','','[]','欲識經冬氣倍和，高穹回矚念民瘥。',64,'全唐诗/poet.song.19000.json','["欲識經冬氣倍和，高穹回矚念民瘥。", "盡搜秋夏乘龍起，併與寰區瑞雪多。", "是處玉峯開璧府，幾番雲浪溢銀河。", "來牟定過前年麥，銷得衰翁醉又歌。"]'),
('4de0d73f-a830-4059-85b6-9c247bb8b874','雪十十韻','韓琦','宋','宋诗','song-poetry','','[]','天宇昏凝幕，星潢凍漏津。',240,'全唐诗/poet.song.19000.json','["天宇昏凝幕，星潢凍漏津。", "報豐推上瑞，散利浹無垠。", "皓彩生和燭，深仁出化鈞。", "乘時驅癘氣，幾日困疲民。", "滿慰三農望，潛基萬國春。", "道山誰辨玉，佛界普成銀。", "緩舞疑翻佩，徐來類積薪。", "盤高擎露蕊，隙細入駒塵。", "易掩妖顔嫮，難藏厚地珍。", "墜輕時斷續，勢猛忽紛綸。", "肯使瑕瑜見，惟思沃瘠均。", "歌妍皆似郢，璧碎不因秦。", "輈冷侵馴鹿，符光逼琢麟。", "充盈是谿壑，挺特有松筠。", "近嶺梅先發，瀕江練更勻。", "樓臺競環麗，蟾兔起精神。", "病骨驚心怯，書帷憶舊親。", "風流資醉目，豪放任詩人。", "陳閣方多暇，睢園喜命賓。", "宜城須大引，佳味過吳醇。"]'),
('06c78649-bd0b-4e27-a919-394323af2926','次韻和張宗益工部初到相臺書事','韓琦','宋','宋诗','song-poetry','','[]','園池開拓費經籌，雅意奚專自宴休。',64,'全唐诗/poet.song.19000.json','["園池開拓費經籌，雅意奚專自宴休。", "好事庶逢賢守繼，康時聊便里民游。", "一聞公暇閑無敵，頓激歸心浩不收。", "早晚再容懷綬樂，赤松高趣遂希留。"]'),
('b2374629-a8cd-4610-b351-e1f85a548123','再和','韓琦','宋','宋诗','song-poetry','','[]','銅雀臺邊事少州，名郎來守喜安休。',64,'全唐诗/poet.song.19000.json','["銅雀臺邊事少州，名郎來守喜安休。", "吾民正遂歌襦樂，我里甘忘衣錦游。", "詩筆入神春益健，宴杯窮賞夜方收。", "鳳池時復思豪奪，爭奈鄉人欲借留。"]'),
('574ce62d-6027-4c72-8b94-fccfa84ba71c','又次韻和題休逸臺','韓琦','宋','宋诗','song-poetry','','[]','昔年衣繡臨吾鄉，後圃力變池亭荒。',64,'全唐诗/poet.song.19000.json','["昔年衣繡臨吾鄉，後圃力變池亭荒。", "井梁生澁卧耕壤，螺榭岌嶪營高岡。", "易爲隅柱極增觀，下視眾嶺森成行。", "錦鱗遂落閑者釣，誰喧歌酒臺東堂。"]'),
('c6ff8290-857d-4a51-80bc-5ad25ecddb1b','再和','韓琦','宋','宋诗','song-poetry','','[]','臺前風景無時良，臺上之樂殊未荒。',64,'全唐诗/poet.song.19000.json','["臺前風景無時良，臺上之樂殊未荒。", "開筵真侶在蓬島，練句美玉生崑岡。", "銅壺報刻緩星箭，金釵送酒排花行。", "鈴齋長寂得吏隱，便是道家虛白堂。"]'),
('62e6cb8e-a147-465f-8d18-23755db059e0','次韻答張宗益工部','韓琦','宋','宋诗','song-poetry','','[]','昔忝臨漳守，娛心自退公。',144,'全唐诗/poet.song.19000.json','["昔忝臨漳守，娛心自退公。", "閑愁放天上，真境得壺中。", "燕處雖云適，規模惜未豐。", "恢園隳舊堞，困宇出新工。", "材品珍方用，花名異始充。", "泉分洹水堰，梁下鄴城宮。", "今始推良牧，褒辭借病翁。", "笙鏞諧廟瑟，珠玉滿郵筒。", "詎敢矜前政，徒知偃下風。", "北堂留衣錦，西巘峻維嵩。", "休逸簷梢月，榮歸浪襯虹。", "班條多暇日，清賞此何窮。"]'),
('b9fa42d0-1ce3-442f-86cb-8c2944390c62','殘臘','韓琦','宋','宋诗','song-poetry','','[]','北土嚴凝氣候偏，臘殘池館愈蕭然。',64,'全唐诗/poet.song.19000.json','["北土嚴凝氣候偏，臘殘池館愈蕭然。", "長河冰塞多寒地，密雪雲繁三白天。", "粧點瑶林連霧淞，沈埋茵草未羊眠。", "但知催釀宜城醞，終見春芳次第妍。"]'),
('8e8120d2-5487-4a8c-8073-f87a2de54056','次韻答致政宮師張相公','韓琦','宋','宋诗','song-poetry','','[]','早謝樞衡貴，逍遥哂眾愚。',48,'全唐诗/poet.song.19000.json','["早謝樞衡貴，逍遥哂眾愚。", "樂從黄卷得，游命赤松俱。", "風雅樽前事，雲山世外娛。", "何妨紫虛下，散髮伴樵蘇。"]'),
('d0d88e11-d70c-4f2b-bec4-2fc8165b1a15','次韻答相州張宗益工部','韓琦','宋','宋诗','song-poetry','','[]','處暗頻驚擲夜光，千金高價恨難償。',64,'全唐诗/poet.song.19000.json','["處暗頻驚擲夜光，千金高價恨難償。", "蟠桃入口知仙味，鈞奏醒魂認帝鄉。", "辯解重圍思亹亹，戰逢强陣怯堂堂。", "懷歸自是衰疲甚，不爲吾剛挫舊腸。"]'),
('8b2c66c7-5d7f-4f43-ad94-bee98bad18a3','又次韻答','韓琦','宋','宋诗','song-poetry','','[]','故人憐舊政，褒惜一何深。',96,'全唐诗/poet.song.19000.json','["故人憐舊政，褒惜一何深。", "營葺推勤治，優閑稱道心。", "池臺資勝事，風月入高吟。", "酒戶雖難角，詩盟已屢尋。", "詞豪甘自屈，氣銳敢輕侵。", "奇變雲霞爛，冥搜海嶽陰。", "暄和生嶰律，淡泊寄陶琴。", "但媿衰聾耳，安能別大音。"]'),
('94ea020c-23d5-4ccf-8804-b7bac1bd15d8','辛亥二月十五日','韓琦','宋','宋诗','song-poetry','','[]','倏忽韶光一半過，寒威猶尚壓暄和。',64,'全唐诗/poet.song.19000.json','["倏忽韶光一半過，寒威猶尚壓暄和。", "故摧春色歡終減，屢失花期日旋那。", "病骨不禁風料峭，衰悰難遏醉吟哦。", "憑欄更爲芳菲惜，重取輕苫擁舊科。"]'),
('e140fccd-e13c-4e97-a222-5702875c3034','辛亥寒食','韓琦','宋','宋诗','song-poetry','','[]','寒食春城是處花，唐賢詩好此難加。',64,'全唐诗/poet.song.19000.json','["寒食春城是處花，唐賢詩好此難加。", "柳眉拖霧舒還皺，日脚縈雲綻復遮。", "扢抓喜隨膏雨解，鞦韆閑任綵繩斜。", "芳辰只愧樽前淡，妓版停歌不振牙。"]'),
('2e6c553f-df44-41de-adde-ca3939c7c7e1','清明會壓沙寺','韓琦','宋','宋诗','song-poetry','','[]','時節清明府事閒，壓沙高會敞禪關。',64,'全唐诗/poet.song.19000.json','["時節清明府事閒，壓沙高會敞禪關。", "妓歌沈席摧鶯舌，花影摇樽衒粉顔。", "春色滿添膏澤後，人心和入醉遊間。", "坐中尤覺風來好，白雪飛香混博山。"]'),
('f1e2fa8a-1235-4c5f-93d2-801a71213068','同賞梨花','韓琦','宋','宋诗','song-poetry','','[]','興福梨珍號素封，千株花發此欣逢。',64,'全唐诗/poet.song.19000.json','["興福梨珍號素封，千株花發此欣逢。", "風開笑臉輕桃艷，雨带啼痕自玉容。", "蝶舞只疑殘靨墜，月明唯覺異香濃。", "尋春已恨來傷晚，莫厭頻揮瀲灧鐘。"]'),
('d2c5ad1e-3811-49a0-a207-1a907bb05d78','又一闋','韓琦','宋','宋诗','song-poetry','','[]','花下延賓啟宴杯，回頭香雪即成堆。',32,'全唐诗/poet.song.19000.json','["花下延賓啟宴杯，回頭香雪即成堆。", "主人自挈宜城釀，不爲青旗趁爾來。"]'),
('287178a2-0d88-4dfe-92bf-5f25ebe0424d','辛亥上巳會許公亭','韓琦','宋','宋诗','song-poetry','','[]','修禊園林枕御津，宴亭軒豁足娛賓。',64,'全唐诗/poet.song.19000.json','["修禊園林枕御津，宴亭軒豁足娛賓。", "羲皇治世舒長日，崑閬仙風爛熳春。", "脫俗且將詩送酒，縱吟須仗筆爭神。", "會餘俯仰皆陳迹，不醉山陰定笑人。"]'),
('8a141f2c-9f5e-4267-839d-170bf8b61efb','許公亭席上別鎮帥呂公孺諫議','韓琦','宋','宋诗','song-poetry','','[]','元日津亭景物嘉，喜留軒馭弭高牙。',64,'全唐诗/poet.song.19000.json','["元日津亭景物嘉，喜留軒馭弭高牙。", "棠陰共識思賢地，柳色偏傷贈別家。", "御水少陪乘興棹，潭園難趁及時花。", "杯深莫拒勤拳意，去路音輝日日賒。"]'),
('9929f278-ef89-4c3d-958d-7659b73ee3c7','同賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','國艷孤高豈自媒，寒鄉加力試栽培。',64,'全唐诗/poet.song.19000.json','["國艷孤高豈自媒，寒鄉加力試栽培。", "當時尚昧隨和貴，今日真逢左魏開。", "名品已先推洛譜，夢魂唯恐失陽臺。", "花王親視風騷將，中的方應賞巨杯。"]'),
('40419ce4-f224-4e84-9285-2499dd26a080','辛亥三月十八日遊御河二首  其一','韓琦','宋','宋诗','song-poetry','','[]','都人殫出集河湄，猶記從初放水時。',64,'全唐诗/poet.song.19000.json','["都人殫出集河湄，猶記從初放水時。", "三五已過修禊宴，浹旬行作送春詩。", "微波濺襪仙浮棹，曲岸當壚柳映旗。", "自笑遨頭衰復病，也同歡俗恣追隨。"]'),
('90c177cf-4476-4694-a0f5-05875196e48e','辛亥三月十八日遊御河二首  其二','韓琦','宋','宋诗','song-poetry','','[]','從俗沿流輒命筵，平沙經雨潤河壖。',64,'全唐诗/poet.song.19000.json','["從俗沿流輒命筵，平沙經雨潤河壖。", "百泉遥派初來日，三月深春欲去天。", "夾岸綺羅香未散，幾船弦管沸爭前。", "波間無限能泅者，不信迎潮絕技先。"]'),
('7993de1f-b27c-410a-a045-a6b5e953e6fb','遊河遇雨','韓琦','宋','宋诗','song-poetry','','[]','開席臨流雨驟侵，都人殊鬰勝遊心。',64,'全唐诗/poet.song.19000.json','["開席臨流雨驟侵，都人殊鬰勝遊心。", "侍娃不見塵生襪，農穀偏欣隴拔針。", "郢雪鬭高閑未接，峽雲爭去杳難尋。", "無過却下船中坐，豈廢衰翁醉又吟。"]'),
('bbb59e03-0347-489c-8a53-135e56c7a9f9','次韻答致政趙少卿','韓琦','宋','宋诗','song-poetry','','[]','登科常愧處盧前，敘齒於兄小十年。',64,'全唐诗/poet.song.19000.json','["登科常愧處盧前，敘齒於兄小十年。", "鶴不乘軒猶自若，鴻誰能弋已安然。", "山頭俗駕歸誠晚，湖外扁舟見獨先。", "惟有大鈞公道在，方圓隨物舊同甄。"]'),
('a31127db-08cf-4cfb-9214-9aa6cb7e2f4d','喜雨應禱','韓琦','宋','宋诗','song-poetry','','[]','運月愆陽作旱災，龍壇申禱潔三垓。',64,'全唐诗/poet.song.19000.json','["運月愆陽作旱災，龍壇申禱潔三垓。", "至誠始懼卑高隔，嘉應俄如影響來。", "喜闊農心歸擊壤，潤深人意不驚雷。", "大鈞廣播知難報，埏埴何嘗望一杯。"]'),
('d6d2fa45-6df8-4642-bf75-a0d303c01137','次韻答簽判沈唐太丞應祈雨足','韓琦','宋','宋诗','song-poetry','','[]','一雨滂沲過作霖，油雲隨禱極陰森。',64,'全唐诗/poet.song.19000.json','["一雨滂沲過作霖，油雲隨禱極陰森。", "微誠未必回天意，靈答潛知渴眾心。", "瑞絕莫先惟在穀，價高難擬不論金。", "朝來田畯更相賀，犁下侵淫二尺深。"]'),
('70860951-6489-4e92-8552-6e70bde15609','寄致政歐陽少師','韓琦','宋','宋诗','song-poetry','','["\u897f\u6e56"]','獨步文章世孰先，直聲孤節亦無前。',64,'全唐诗/poet.song.19000.json','["獨步文章世孰先，直聲孤節亦無前。", "欲知退足高千古，請視經猶疾五年。", "在我光陰長更樂，扶天功業去如捐。", "西湖風月誰爲伴，笑許當時處士賢。"]'),
('2e785946-8b1e-4758-8ec2-851bd90d4610','盛暑思接榮歸之游寄相守張工部','韓琦','宋','宋诗','song-poetry','','[]','伏暑如何散鬰陶，榮歸陪賞望空勞。',64,'全唐诗/poet.song.19000.json','["伏暑如何散鬰陶，榮歸陪賞望空勞。", "紅芳照檻蓮千頰，綠蔭環波柳萬條。", "趨第小車誰競挽，見山新址日增高。", "遥知賢守多娛地，詩筆雖豪酒未豪。"]'),
('bcebbc30-6ee5-451d-a20a-a6ef1876a2c0','辛亥七夕末伏','韓琦','宋','宋诗','song-poetry','','[]','二七今同末伏辰，初秋時候暑微熏。',64,'全唐诗/poet.song.19000.json','["二七今同末伏辰，初秋時候暑微熏。", "星橋舊說通靈匹，劍肉何人遺細君。", "瑩席冰寒心共爽，噪風蟬急耳欣聞。", "郢中新曲高難和，唯付珠喉任遏雲。"]'),
('23028540-8dec-47c3-b364-17f7da4c300f','七夕會關亭觀蓮','韓琦','宋','宋诗','song-poetry','','[]','陶暑娛賓次水西，滿塘蓮艷馥軒墀。',64,'全唐诗/poet.song.19000.json','["陶暑娛賓次水西，滿塘蓮艷馥軒墀。", "荷坳似學繖翻去，房曲如將盞倒垂。", "肯把風流欺儉幕，且憑歌調擬吳姬。", "從來拙宦老難巧，任過靈光醉不知。"]'),
('ec132350-5729-4cbc-955d-88bd8e724655','貽刑','韓琦','宋','宋诗','song-poetry','','[]','憶帥秦亭二紀餘，當時賓幕盛芙蕖。',64,'全唐诗/poet.song.19000.json','["憶帥秦亭二紀餘，當時賓幕盛芙蕖。", "椎牛共樂毬場宴，倚馬常資記室書。", "台席久從還綬退，月卿猶滯剖符居。", "樽前想解留連意，一笑難逢易摻袪。"]'),
('6f22dd02-8f35-4a93-81fd-5d98b5260ff6','元城埽行河','韓琦','宋','宋诗','song-poetry','','[]','怒河秋漲俯都城，縱嚙長堤豈易平。',64,'全唐诗/poet.song.19000.json','["怒河秋漲俯都城，縱嚙長堤豈易平。", "氣悍若從天上落，勢高難使地中行。", "筑垣居水雖危事，沈馬回波是至誠。", "故道幾時循禹迹，免教常歲害民生。"]'),
('c7bd2c26-e7a8-47bf-bac7-7399c4ff1c3e','行河道中','韓琦','宋','宋诗','song-poetry','','[]','鱗鱗郊隰引雙旌，頓豁塵襟病眼明。',64,'全唐诗/poet.song.19000.json','["鱗鱗郊隰引雙旌，頓豁塵襟病眼明。", "微靄際空隨日破，遥林環野接天平。", "捺弮禾重籠新雨，舐犢牛閑罷力耕。", "策馬故尋堤上路，移時欣在綠陰行。"]'),
('72fa1860-556d-427e-ae01-c2f7a768418e','辛亥八月十六日社始月望','韓琦','宋','宋诗','song-poetry','','[]','中秋不必拘三五，惟望時方月正圓。',64,'全唐诗/poet.song.19000.json','["中秋不必拘三五，惟望時方月正圓。", "已薦社壝通肸蠁，始開賓席對嬋娟。", "清光自喜今宵滿，俗會從輸一日先。", "樂事幾爲風雨破，直須歡飲倍常年。"]'),
('d90a98e7-d857-4a82-8e16-901aa975db2a','辛亥八月十六日夜復值陰晦','韓琦','宋','宋诗','song-poetry','','[]','舒輪方滿正中秋，報社神歆已降休。',64,'全唐诗/poet.song.19000.json','["舒輪方滿正中秋，報社神歆已降休。", "且共良農歌稔歲，何須明月照高樓。", "金絲自壯歡吟氣，風雨終爲樂事仇。", "酣飫野翁猶带斷，不爭豪飲亦堪羞。"]'),
('aec770de-2d4c-40d6-a154-fd3d5e3f4e70','中秋飲散始微見月','韓琦','宋','宋诗','song-poetry','','[]','待月中秋欲共歡，不堪陰晦阻羣觀。',64,'全唐诗/poet.song.19000.json','["待月中秋欲共歡，不堪陰晦阻羣觀。", "賓歸已徹青油幕，雲綻聊窺白玉盤。", "就榻酒狂平未歇，據鞍吟苦得應難。", "孀娥此夕潛何甚，專要人將別眼看。"]'),
('8f2cb279-cf1e-4955-8987-d04a6f4caf13','九月四日會安正堂','韓琦','宋','宋诗','song-poetry','','[]','秋光濃拂使君家，尚去重陽五日賒。',64,'全唐诗/poet.song.19000.json','["秋光濃拂使君家，尚去重陽五日賒。", "且育好詩成素飲，更先諸客對黄花。", "池萍漬雨錢錢密，塞雁書空字字斜。", "但縱高吟開醉膽，莫驚摇落動悲嗟。"]'),
('eb890bb1-c8d5-4974-a254-de71fa0bcf11','辛亥重九會安正堂','韓琦','宋','宋诗','song-poetry','','[]','斯堂曾許占風光，須到重陽復命觴。',64,'全唐诗/poet.song.19000.json','["斯堂曾許占風光，須到重陽復命觴。", "坐上半非前歲客，杯中無改舊花香。", "初晴已過登高水，散慮宜趨自得場。", "唯有一時詩酒戰，願開强戶振雄鋩。"]'),
('928a43ed-703e-4c05-8838-4ba76796012c','即席再賦','韓琦','宋','宋诗','song-poetry','','[]','蕪音逢節佐賓罍，屬和當筵盡雅才。',64,'全唐诗/poet.song.19000.json','["蕪音逢節佐賓罍，屬和當筵盡雅才。", "銅鉢一聲詩已就，金鈴千朵菊爭開。", "月明正有抽毫樂，夜永何妨秉燭回。", "無酒可嗤彭澤令，東籬空望白衣來。"]'),
('cfa301a8-1e7e-463a-b907-9bf88a4e87d0','辛亥重九登騎山樓','韓琦','宋','宋诗','song-poetry','','[]','西北樓高四望長，登臨還賞節辰良。',64,'全唐诗/poet.song.19000.json','["西北樓高四望長，登臨還賞節辰良。", "荀陳盛集星光動，相衛名山記字詳。", "瑇瑁不妨欹醉弁，茱萸誰自鬭香囊。", "病翁安敢當能賦，只俟英瑶作報章。"]'),
('211f7b92-a248-4770-b821-8e4badb502e2','和運判張端秘丞戲題安陽郡園','韓琦','宋','宋诗','song-poetry','','[]','垂楊陰裏百花開，誰記當是任意栽。',32,'全唐诗/poet.song.19000.json','["垂楊陰裏百花開，誰記當是任意栽。", "好事繼逢賢太守，算無心望主人來。"]'),
('d9dce80d-8196-4f07-ae0d-4f089b0630ca','代郡園見答','韓琦','宋','宋诗','song-poetry','','[]','晝錦輕拋又幾年，縱逢春色亦依然。',32,'全唐诗/poet.song.19000.json','["晝錦輕拋又幾年，縱逢春色亦依然。", "爭知臺榭笙歌外，盡是猿驚鶴怨天。"]'),
('1044b3ea-f4c8-4ff9-a791-2434334ee7e9','再戲郡園','韓琦','宋','宋诗','song-poetry','','[]','一辭康樂困喧囂，花笑鶯啼似借嘲。',32,'全唐诗/poet.song.19000.json','["一辭康樂困喧囂，花笑鶯啼似借嘲。", "日望君恩容病質，得歸應自解譊譊。"]'),
('a57c5c57-324a-41b3-8645-8fdfaac47bf0','再代答','韓琦','宋','宋诗','song-poetry','','[]','買臣素賤猶鄉守，莊舄雖榮尚越吟。',32,'全唐诗/poet.song.19000.json','["買臣素賤猶鄉守，莊舄雖榮尚越吟。", "已葺吾園似仙府，莫教歸信苦沈沈。"]'),
('0c21cde8-100d-4590-8ec3-9932b3269efe','御河舟中','韓琦','宋','宋诗','song-poetry','','[]','過慮先河備，輕舟造愜山。',48,'全唐诗/poet.song.19000.json','["過慮先河備，輕舟造愜山。", "驚鷗情自動，流水意長閑。", "村落多豐外，寒溫不定間。", "如何援民溺，搔首只空還。"]'),
('b9bf36eb-19cb-438d-886a-0ba3fdd5315a','視河愜山','韓琦','宋','宋诗','song-poetry','','[]','河决金堤在漢成，曾推延世此經營。',64,'全唐诗/poet.song.19000.json','["河决金堤在漢成，曾推延世此經營。", "安人爲愜當時意，立事因垂不朽名。", "誰鑿故山釃御水，却通新漕入都城。", "一疏一塞俱稱利，暫訪遺蹤豈易評。"]'),
('6666fa27-c91c-4816-8ef8-d099635c4219','至節筵間喜雪','韓琦','宋','宋诗','song-poetry','','[]','至節開樽就席前，六花飛舞助賓筵。',64,'全唐诗/poet.song.19000.json','["至節開樽就席前，六花飛舞助賓筵。", "颺空自勝重羅麫，引滿偏宜旋絮綿。", "合坐歡談霏屑地，幾聲橫笛落梅天。", "況逢陽復貞亨會，贏取笙歌爛醉眠。"]'),
('eab18428-a148-4b5e-a788-4f870b3ab953','元宵席上','韓琦','宋','宋诗','song-poetry','','[]','燈燭森森萬象羅，徹宵車馬罷誰何。',64,'全唐诗/poet.song.19000.json','["燈燭森森萬象羅，徹宵車馬罷誰何。", "追人好月嬋娟滿，带雪輕寒料峭多。", "佳節俯從河沴寢，羣心俄逐詔音和。", "乘春自欲開民鬰，不爲樽前笑與歌。"]'),
('700b3502-a5dd-46a7-a19e-3ed88950c0a9','次韻答致政歐陽少師退居述懷二首  其一','韓琦','宋','宋诗','song-poetry','','[]','日跂高風謝世紛，只思移疾卧漳濆。',64,'全唐诗/poet.song.19000.json','["日跂高風謝世紛，只思移疾卧漳濆。", "萬鐘糠粃常知慕，三徑蓬蒿欲自耘。", "忠義心誠終老合，仙凡岐路此時分。", "唯瞻天外冥鴻遠，會起卑飛及舊羣。"]'),
('d327e374-01c5-4909-ae74-fb204a8cace3','次韻答致政歐陽少師退居述懷二首  其二','韓琦','宋','宋诗','song-poetry','','[]','塵俗徒希勇退高，幾時投迹混耕樵。',64,'全唐诗/poet.song.19000.json','["塵俗徒希勇退高，幾時投迹混耕樵。", "神交不間川塗闊，直道難因老病消。", "魏境民流河抹岸，潁湖春早柳縈橋。", "相從誰挹浮邱袂，左在琴書酒滿瓢。"]'),
('6a2a7655-5085-47b5-b8d3-20177938e143','壬子上巳會許公亭','韓琦','宋','宋诗','song-poetry','','[]','來守留都第四年，年年元已此開筵。',64,'全唐诗/poet.song.19000.json','["來守留都第四年，年年元已此開筵。", "一春曾喜陳歌舞，三會皆逢去管絃。", "無樂只憂辭酒客，多寒誰辨惜花天。", "欲看郊外風光野，更上亭西祓禊船。"]'),
('1c53d02b-21ed-4e6b-8c08-4a819bc7750a','上巳視愜山新堤','韓琦','宋','宋诗','song-poetry','','[]','元巳西津禊飲中，筑防因視愜山雄。',64,'全唐诗/poet.song.19000.json','["元巳西津禊飲中，筑防因視愜山雄。", "調夫雖擾三農業，禦水猶希一簣功。", "曲突慮微方絕患，開門輕敵是招戎。", "岸邊觀者應相笑，遭賊徒彎過後弓。"]'),
('3796656d-1277-4de9-98f8-ddadb54181f0','壬子寒食會壓沙寺二首  其一','韓琦','宋','宋诗','song-poetry','','[]','踏沙徐人綠楊中，漸見祗園寶勢雄。',64,'全唐诗/poet.song.19000.json','["踏沙徐人綠楊中，漸見祗園寶勢雄。", "柏奮怒虬環古殿，花遺嬌靨散春風。", "娛心未放歌聲好，對目難窮幻術工。", "共醉一時寒食景，不須庭際牡丹紅。"]'),
('91196de2-fcae-4173-9d04-099f3d936968','壬子寒食會壓沙寺二首  其二','韓琦','宋','宋诗','song-poetry','','[]','一春光景速奔車，且趁良辰會壓沙。',64,'全唐诗/poet.song.19000.json','["一春光景速奔車，且趁良辰會壓沙。", "藏火未須傳蠟燭，感時空自把梨花。", "笙歌不作芳菲主，風雅終成冷淡家。", "歸路復疑霄漢上，御波舟穩襯雲霞。"]'),
('de640350-a543-49b5-b071-5a93a25551b0','同賞梨花','韓琦','宋','宋诗','song-poetry','','[]','寒食西藍賞素英，白毫光裏亂雲騰。',64,'全唐诗/poet.song.19000.json','["寒食西藍賞素英，白毫光裏亂雲騰。", "莊嚴金地三千界，顔色瑶臺十二層。", "后土瓊花漸我寡，唐昌玉蕊豈吾朋。", "雪香預約爲亭號，修創終逢好事僧。"]'),
('4f620531-946b-4bbb-b94c-44fe250fd080','落花','韓琦','宋','宋诗','song-poetry','','[]','萬點送春飛，人悲未足悲。',48,'全唐诗/poet.song.19000.json','["萬點送春飛，人悲未足悲。", "禪關無問理，溪曲過開時。", "鈿委津陽路，風回洛水湄。", "流年來自去，醉莫論空枝。"]'),
('ec94c665-dac5-441c-ab95-fb37fd7a27e1','壬子三月十八日游御河二首  其一','韓琦','宋','宋诗','song-poetry','','[]','寒食初過始及旬，魏都偏重此佳辰。',64,'全唐诗/poet.song.19000.json','["寒食初過始及旬，魏都偏重此佳辰。", "傾城盡作河生日，匝岸皆如蠟祭人。", "幾艦神仙疑駭俗，一川笳鼓任同民。", "東皇似助熙臺樂，併與千門萬戶春。"]'),
('50f6ba10-bdc8-408f-98da-87e29f9328d8','壬子三月十八日游御河二首  其二','韓琦','宋','宋诗','song-poetry','','[]','三月游河魏國風，愜山通日正暄融。',64,'全唐诗/poet.song.19000.json','["三月游河魏國風，愜山通日正暄融。", "壓沙寺古花殘雪，過馬橋高水飲虹。", "眾樂自深春色外，萬愁俱泯醉吟中。", "天公恐雨傷民意，只放輕雲暝碧空。"]'),
('7aa308c6-3fff-451f-9dc9-319a70a8949d','舟中再賦一闋','韓琦','宋','宋诗','song-poetry','','[]','畫艗雙雙掠水飛，一天雲重鎖春暉。',32,'全唐诗/poet.song.19000.json','["畫艗雙雙掠水飛，一天雲重鎖春暉。", "遨頭不與追鐃鼓，無限遊人寂寞歸。"]'),
('0d82a6ef-673d-4b88-a52f-92a293ccdcbc','安正堂觀牡丹','韓琦','宋','宋诗','song-poetry','','[]','何須風雨苦相催，自結東君不在媒。',64,'全唐诗/poet.song.19000.json','["何須風雨苦相催，自結東君不在媒。", "開晚要當三月盛，艷高宜作百花魁。", "好期天上香魂返，長對樽前醉玉頹。", "誰道元輿能體物，只教羞死刺玫瑰。"]'),
('7d75dc1b-d180-4335-864c-49365c2f03d1','致政宮師張相公遠惠佳篇謹次元韻爲答','韓琦','宋','宋诗','song-poetry','','[]','八十康寧極品榮，神仙居處足頤生。',64,'全唐诗/poet.song.19000.json','["八十康寧極品榮，神仙居處足頤生。", "風騷此日資高尚，事業當年有太平。", "酒量更從閑後長，禪心偏向靜中明。", "自嗟不及飛來鶴，能伴公遊稱道情。"]'),
('025a5c08-3398-437a-bbef-27edfe190fd5','又次韻和續成絕句','韓琦','宋','宋诗','song-poetry','','[]','醉卧嵩雲得句豪，豈知平地有風濤。',32,'全唐诗/poet.song.19000.json','["醉卧嵩雲得句豪，豈知平地有風濤。", "應嗤病驥鹽車重，終日長鳴只告勞。"]'),
('78f1d29f-247f-4100-a009-b12fd8b55b13','聞致政趙少師遠訪歐陽少師于潁川','韓琦','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一憶賢交動至誠，安車雖遠必勤征。',64,'全唐诗/poet.song.19000.json','["一憶賢交動至誠，安車雖遠必勤征。", "荀陳爲會還推象，嵇呂相思不問程。", "洛社成圖茲易合，越溪回櫂彼何情。", "西湖便是瀛洲上，莫接仙遊跨海鯨。"]'),
('6a509289-02c3-404b-a735-119f28319cb5','聞前都水王荀龍郎中將率二三知舊遊天平山寺','韓琦','宋','宋诗','song-poetry','','[]','天平高絕是家山，雨治安陽欲到難。',64,'全唐诗/poet.song.19000.json','["天平高絕是家山，雨治安陽欲到難。", "此日名郎真好事，直携嘉客遠同觀。", "峯擎寺脚重霄近，雹起潭心六月寒。", "遥想醉吟崑閬裏，亂飛珠玉出毫端。"]'),
('84303003-17b4-4e28-bfd8-b8f10e71c65b','次韻答致政趙少師感懷','韓琦','宋','宋诗','song-poetry','','[]','羨公朝夕挹浮邱，應笑吾曹窘若囚。',64,'全唐诗/poet.song.19000.json','["羨公朝夕挹浮邱，應笑吾曹窘若囚。", "塵外有誰攀逸駕，壺中何處著閑愁。", "心休已得天真樂，身退猶存國事憂。", "積善由來神所勞，坐膺全福不須求。"]'),
('ab5838e3-3373-420c-8e9d-5cb77338d95e','壬子中秋對月','韓琦','宋','宋诗','song-poetry','','[]','一輪徐出海東頭，皓彩全供白帝秋。',64,'全唐诗/poet.song.19000.json','["一輪徐出海東頭，皓彩全供白帝秋。", "桂跡自消安在斫，寶光無缺不因修。", "池心影撼金鱗碎，杯面波隨玉液流。", "此夜圓蟾看處好，何須偏上最高樓。"]'),
('8c34185c-fe7b-4682-8321-ffcc85cb3a35','登大安寺閣','韓琦','宋','宋诗','song-poetry','','[]','岧嶢飛閣聳晴空，此過層梯第幾重。',64,'全唐诗/poet.song.19000.json','["岧嶢飛閣聳晴空，此過層梯第幾重。", "四野風煙籠勝地，半天金碧護真容。", "浮圖逼檻抽雙笋，埤堄排雲矗萬峰。", "數刻飄然霄漢上，直疑超界脫塵蹤。"]'),
('e1bc2361-8688-4422-8da6-16648ae33360','八月十九日賞菊','韓琦','宋','宋诗','song-poetry','','[]','春英無不惜開遲，秋菊常懷素景悲。',64,'全唐诗/poet.song.19000.json','["春英無不惜開遲，秋菊常懷素景悲。", "慣負晚霜甘索寞，忽逢先閏促離披。", "欲移庭檻嫌傷早，擬泛賓罍未入時。", "自是寒花當守分，一違佳節速人嗤。"]'),
('6f20f600-a10e-4de0-a8a2-ad255b7f1afa','壬子九月七日會大安寺','韓琦','宋','宋诗','song-poetry','','[]','蕭辰禪宇展疎筵，才去登高二日前。',64,'全唐诗/poet.song.19000.json','["蕭辰禪宇展疎筵，才去登高二日前。", "欲識先期成雅會，要聞清論接英賢。", "何須白發喧歌板，自有黄花送酒船。", "危閣半空同倚檻，一般重九寂寥天。"]'),
('287f7c1b-d992-4aed-8207-b59042dc467f','壬子重九','韓琦','宋','宋诗','song-poetry','','[]','菊有黄花氣候移，重陽香萼已乾枝。',64,'全唐诗/poet.song.19000.json','["菊有黄花氣候移，重陽香萼已乾枝。", "金鈴後坼孤芳在，玉液輕浮一醉宜。", "煙渚去來鴻自適，霜叢飛遶蝶何知。", "風前客帽從吹落，且伴山翁倒接䍦。"]'),
('24dd8d96-6d17-4280-9127-4bbe7fa012fc','趙資政再尹西蜀','韓琦','宋','宋诗','song-poetry','','[]','坤維求尹此難才，重倚真賢出上懷。',64,'全唐诗/poet.song.19000.json','["坤維求尹此難才，重倚真賢出上懷。", "一去棠陰歌蔽芾，再來人樂似乖崖。", "新承綸綍從天別，舊過山川作畫排。", "莫候使星臨益分，郎回符采正三階。"]'),
('4e851755-dfc3-4669-9117-06936136b429','壬子冬至喜雪','韓琦','宋','宋诗','song-poetry','','[]','陽氣初升力尚微，雪花來促故陰歸。',64,'全唐诗/poet.song.19000.json','["陽氣初升力尚微，雪花來促故陰歸。", "潤滋柔荔乘時出，暖逐輕灰應律飛。", "彤筆喜豐書瑞諜，土圭收影侍靈暉。", "踐長班集應同賀，劒珮光寒拱殿闈。"]'),
('f144c2ce-5a74-4aa6-8f1f-621277d3b0d6','次韻答接伴夏倚少卿','韓琦','宋','宋诗','song-poetry','','[]','定幕雍容綠水濱，使軺今喜接光塵。',64,'全唐诗/poet.song.19000.json','["定幕雍容綠水濱，使軺今喜接光塵。", "當年不足稱良治，此日空慚問大鈞。", "鐘鼎已無前飲勝，笑言應認昔懷真。", "開樽莫惜俄歡弁，數刻相違易愴神。"]'),
('109e0d9b-5da3-43f3-ac8d-80472bbb9a6a','壬子十一月二十九日時雪方洽','韓琦','宋','宋诗','song-poetry','','[]','近臘猶慳六出繁，忽驚盈尺及民寬。',64,'全唐诗/poet.song.19000.json','["近臘猶慳六出繁，忽驚盈尺及民寬。", "萬方蒙澤人人賀，通夕無風陣陣乾。", "危石蓋深鹽虎陷，老枝擎重玉龍寒。", "欲知靈鷲銀爲界，試陟高樓一望看。"]'),
('5c01ac68-5294-4f77-ae8c-3964e51415dd','新移宴廳','韓琦','宋','宋诗','song-poetry','','[]','魏藩池館有唐風，宴宇耽然制尚雄。',64,'全唐诗/poet.song.19000.json','["魏藩池館有唐風，宴宇耽然制尚雄。", "歲月已深摧巨棟，庭除非舊逼離宮。", "稍遷基址囂塵外，適在園林掩映中。", "從此命賓何最盛，四時嘉景盡牢籠。"]'),
('b03e92fd-014f-4d21-bb56-ad0bbc3d00fc','癸丑燈夕','韓琦','宋','宋诗','song-poetry','','[]','爭放紅蕖燎紫沈，勝遊誰肯惜千金。',64,'全唐诗/poet.song.19000.json','["爭放紅蕖燎紫沈，勝遊誰肯惜千金。", "人和更有笙歌助，酒美應無巷陌深。", "化國光陰方甚永，洞天風物不難尋。", "如何可致吾民樂，長似熙熙此夜心。"]'),
('e706c2ef-8653-44a1-8f58-af6d944bf4a0','壬子春分方見迎春盛開以小詩嘲之','韓琦','宋','宋诗','song-poetry','','[]','迎得新春入舊科，獨先嘉卉占陽和。',32,'全唐诗/poet.song.19000.json','["迎得新春入舊科，獨先嘉卉占陽和。", "今年頓被寒摧朽，應爲尖頭送暖多。"]'),
('2e70a43d-e278-4009-a414-52e82146e9c9','癸丑初拜先墳','韓琦','宋','宋诗','song-poetry','','[]','晝錦三來治鄴城，古人無似此翁榮。',64,'全唐诗/poet.song.19000.json','["晝錦三來治鄴城，古人無似此翁榮。", "首過先隴心還慰，一見家山眼自明。", "釃酒故廬延父老，駐車平野問農耕。", "便思解綬從田叟，報國慙雖萬死輕。"]'),
('3686a7de-a909-4b7e-a767-5571b2d09791','次日早赴西墳','韓琦','宋','宋诗','song-poetry','','[]','風入旌旗撼曉光，兩塋親展喜非常。',64,'全唐诗/poet.song.19000.json','["風入旌旗撼曉光，兩塋親展喜非常。", "濃陰蔽野瞻喬木，逸勢橫天認太行。", "自歎重茵寧及養，縱垂三組敢夸鄉。", "路人或指榮雖甚，明哲何如漢子房。"]'),
('c57d3030-7219-49c8-9aca-689b9018b53c','墳北觀泉','韓琦','宋','宋诗','song-poetry','','[]','墳北清泉味至甘，寺僧渟蓄已成潭。',64,'全唐诗/poet.song.19000.json','["墳北清泉味至甘，寺僧渟蓄已成潭。", "躍魚靈感思追孝，酌水高懷不戒貪。", "萬草日滋珠競出，一天晴落鑒方函。", "暫延嘉客求新句，欲創幽亭即就龕。"]'),
('24af6b4d-2413-4fe2-8960-27d176a881e1','初會晝錦堂','韓琦','宋','宋诗','song-poetry','','[]','重向高堂舉宴杯，四年牽强北門回。',64,'全唐诗/poet.song.19000.json','["重向高堂舉宴杯，四年牽强北門回。", "故園風物都如舊，多病襟懷遂一開。", "白髮耻夸金絡騎，綠陰欣滿鐵梁臺。", "因思前彥榮歸者，未有三曾晝錦來。"]'),
('fb184d5f-c835-4027-962a-6965f02e09bc','次韻答提點醴泉張宗益工部喜還鄉郡','韓琦','宋','宋诗','song-poetry','','[]','倦飛垂翼奈勞何，喜向南枝得舊窠。',64,'全唐诗/poet.song.19000.json','["倦飛垂翼奈勞何，喜向南枝得舊窠。", "三治故鄉前世少，一思遺履上恩多。", "病魂醒處安閑枕，酒量衰來怯巨螺。", "復聽雅音清聵耳，愛居誰辨九韶和。"]'),
('4eb15ae0-fcfe-4a5b-b40b-fa47ef0feb42','初會榮歸堂','韓琦','宋','宋诗','song-poetry','','[]','當年嘗欲志榮歸，因建虛堂面北池。',64,'全唐诗/poet.song.19000.json','["當年嘗欲志榮歸，因建虛堂面北池。", "樽俎落成方自我，園林爲主已輸誰。", "重來故里前恩在，難報深仁舊老知。", "須俟安車時訪此，踐言人始信吾詩。"]'),
('71c88d8b-76ba-40ac-89ca-2b8a195dd7a0','再題狎鷗亭','韓琦','宋','宋诗','song-poetry','','[]','危亭初起俯清潯，只得當軒幾醉吟。',64,'全唐诗/poet.song.19000.json','["危亭初起俯清潯，只得當軒幾醉吟。", "一日鄉園傷驟別，四年宮闕動歸心。", "簷前好竹今成篠，波下修鱗舊種針。", "鷗識再來尤不懼，向人馴狎似家禽。"]'),
('af2affa3-e58e-4247-b493-ddf86530b15b','初登休逸臺','韓琦','宋','宋诗','song-poetry','','[]','休逸臺高復憑欄，依然風月喜生顔。',64,'全唐诗/poet.song.19000.json','["休逸臺高復憑欄，依然風月喜生顔。", "城頭仰視親栽柳，天外微分舊見山。", "草色且無歸後怨，禽飛同到倦時還。", "欲知恩許三來幸，錦爛輕裘白晝閑。"]'),
('b955fec1-8981-4498-abae-a242003a0840','榮歸觀蓮戲成','韓琦','宋','宋诗','song-poetry','','[]','風捲蓮香不斷頭，田田荷影動清流。',64,'全唐诗/poet.song.19000.json','["風捲蓮香不斷頭，田田荷影動清流。", "紅包密障魚鷹坐，綠蓋低容水馬遊。", "時折嫩梢供玉箸，更裁圓葉代金甌。", "何如滿艦傾醇酎，醉向花前打拍浮。"]'),
('4903ab79-40aa-4597-ab75-35e2791df5bb','再葺雙磑','韓琦','宋','宋诗','song-poetry','','[]','昔嗟官麴歲勞民，嘗引新渠激磑輪。',64,'全唐诗/poet.song.19000.json','["昔嗟官麴歲勞民，嘗引新渠激磑輪。", "若念經營存愛利，肯從隳朽貴因循。", "軒楹遇葺知還舊，花木欣來似見春。", "已作州人游觀地，即期同俗樂芳辰。"]'),
('b8b16378-e7b9-4321-8667-06b6c2f9f247','喜雨','韓琦','宋','宋诗','song-poetry','','[]','何假嗔雷擊怒桴，點傾嘉澤浹民區。',64,'全唐诗/poet.song.19000.json','["何假嗔雷擊怒桴，點傾嘉澤浹民區。", "經時亢隔羣心駭，數月焦熬一陣蘇。", "已發宋苗安在揠，再生莊鮒不虞枯。", "須叟慰滿三農望，却斂神功寂似無。"]'),
('8317ec9c-61ad-43de-bff8-f4d0a25f0d0c','再題康樂園','韓琦','宋','宋诗','song-poetry','','[]','舊拓名園壯鄴中，本思行樂興民同。',64,'全唐诗/poet.song.19000.json','["舊拓名園壯鄴中，本思行樂興民同。", "閭閻已慣春遊盛，花木誰矜半植功。", "愛客笙歌雖不定，稱時風月且無窮。", "三來縱賞人休訝，白髮蒼顔坐醉翁。"]'),
('e14ea0b9-2bf6-4f43-b01b-8cc22a35001c','次韻答安撫滕甫侍讀誕日惠詩','韓琦','宋','宋诗','song-poetry','','[]','椽筆親揮善祝詩，老顔筋骨逸如飛。',64,'全唐诗/poet.song.19000.json','["椽筆親揮善祝詩，老顔筋骨逸如飛。", "玉關尚抑動侯入，遼海先欣病鶴歸。", "顧眄已知增氣燄，夢魂猶想接容輝。", "宸襟一日懷忠藎，召節星馳出禁扉。"]'),
('8543d5cd-2a0f-41f7-b8ca-b911973bc620','癸丑七夕會北第','韓琦','宋','宋诗','song-poetry','','[]','荒居聊足奉賓娛，隘甚難希玉椀呼。',64,'全唐诗/poet.song.19000.json','["荒居聊足奉賓娛，隘甚難希玉椀呼。", "秋候俯新零白露，仙期還喜望黄姑。", "雲間誰識橋橫鵲，庭際方欣網掛蛛。", "天與性靈元自拙，却求星媛可回無。"]'),
('36f78b0d-a1f5-4296-8658-ee1eb6c86f21','中元病起','韓琦','宋','宋诗','song-poetry','','[]','中元時俗類秋嘗，病起躬行力未强。',64,'全唐诗/poet.song.19000.json','["中元時俗類秋嘗，病起躬行力未强。", "摖米乍炊知早熟，盂蘭方倒喜初凉。", "風摧豹脚蚊休拍，露逼雞毛菜已長。", "皮骨僅存心尚壯，猶思荷葉當蕉觴。"]'),
('cefcd213-59fa-43c9-a61e-c53d39b7b798','次韻答張宗益工部喜陳薦龍圖竇舜卿侍郎同至相臺','韓琦','宋','宋诗','song-poetry','','[]','嘉客非期會，如因病守邀。',48,'全唐诗/poet.song.19000.json','["嘉客非期會，如因病守邀。", "靜俱知道勝，隱不待文招。", "柳色堆瑶榭，荷得湊綺寮。", "幾回杯興逸，同欲御仙飚。"]'),
('681b72ad-cc89-4dd3-bf13-0aeefc86fb1d','次韻答陳龍圖述北第林泉之勝','韓琦','宋','宋诗','song-poetry','','[]','老顧菟裘欲退藏，一區營宅已過楊。',64,'全唐诗/poet.song.19000.json','["老顧菟裘欲退藏，一區營宅已過楊。", "林泉不較爲生厚，名節猶希到死香。", "麤葺蕭居忘湫隘，喜歸陶徑任荒凉。", "賴逢素舊時相樂，同入無何嘯傲鄉。"]'),
('772002fc-5bd9-4e65-b1f2-471fd332ad7b','題王荀龍郎中長興院新葺雙清堂','韓琦','宋','宋诗','song-poetry','','[]','禪宇初無好事名，君來殊欲稱高情。',64,'全唐诗/poet.song.19000.json','["禪宇初無好事名，君來殊欲稱高情。", "誅茅治屋忘多施，洗竹疏泉得二清。", "苦任雪霜凌勁節，靜和風月瀉寒聲。", "因知嘉號非虛美，翠擁流環豈易并。"]'),
('db1c3de3-36f4-4988-a110-c6d5780cd627','八月十四日留監牧張竚職方賞月','韓琦','宋','宋诗','song-poetry','','[]','待月清商欲半前，欣留嘉客啟踈筵。',64,'全唐诗/poet.song.19000.json','["待月清商欲半前，欣留嘉客啟踈筵。", "採蕭方釋三秋詠，應曆從虧一莢圓。", "密訝雲藏臺面柳，靜看珠出水中天。", "銀蟾影裏金樽倒，樂過陶琴不上絃。"]'),
('63c6a0de-ffb0-49fc-877b-73ed0996d333','中秋陰未見月','韓琦','宋','宋诗','song-poetry','','[]','雲惱中秋湊月昏，失明疑值老蟾吞。',64,'全唐诗/poet.song.19000.json','["雲惱中秋湊月昏，失明疑值老蟾吞。", "枉刪踈柳延孤影，肯晃芳樽滌醉魂。", "好射重陰開六幕，任均餘照及千門。", "便從到曉漫天黑，不禁詩家萬駟奔。"]'),
('2401eda8-bf9a-470b-b584-5f3d45585898','次韻答前水監王荀龍郎中重九感懷','韓琦','宋','宋诗','song-poetry','','[]','應厭偏州節物荒，重陽前忍去安陽。',64,'全唐诗/poet.song.19000.json','["應厭偏州節物荒，重陽前忍去安陽。", "雙清易感霜莖怨，三雅難留露蕊芳。", "不惜高吟來疾置，尚思衰叟會寒鄉。", "誰知衣弊京塵客，乃是南宮卧錦郎。"]'),
('78c502d8-a56c-4327-b973-a26851bf7f8b','重陽二首  其一','韓琦','宋','宋诗','song-poetry','','[]','崛起層基正面山，登高疑是出塵間。',64,'全唐诗/poet.song.19000.json','["崛起層基正面山，登高疑是出塵間。", "一天秋色清吟筆，萬蕊寒香發醉顔。", "與眾且同今日樂，相逢難遇此時閑。", "猶輸陶令歸來興，翩似冥鴻不可攀。"]'),
('4f791da1-3ce7-46b0-9761-1b60270c76c9','重陽二首  其二','韓琦','宋','宋诗','song-poetry','','[]','菊有花爭一日先，次逢佳節色增妍。',64,'全唐诗/poet.song.19000.json','["菊有花爭一日先，次逢佳節色增妍。", "任飄杯面黄金碎，好聽歌喉白雪圓。", "戲馬遺風應索寞，抱螺高興且留連。", "良辰俯仰嗟陳迹，莫惜歡吟爛醉眠。"]'),
('430f87a6-7506-4f1d-b494-765a80be47f0','次韻答提舉陳龍圖重陽感舊','韓琦','宋','宋诗','song-poetry','','[]','三邊伊昔喜延枚，每向良辰命宴杯。',64,'全唐诗/poet.song.19000.json','["三邊伊昔喜延枚，每向良辰命宴杯。", "幾遇雪天留兔苑，嘗因風賦重蘭臺。", "錦衣寬病恩何厚，琳館甘閑老未催。", "白首又同吹菊會，且將愁臆暫時開。"]'),
('ff3be098-9db6-461f-b2a3-5fb560760686','秋晚赴先塋馬上','韓琦','宋','宋诗','song-poetry','','[]','暫趨先隴弭旌旄，因卹吾民嗇事勞。',64,'全唐诗/poet.song.19000.json','["暫趨先隴弭旌旄，因卹吾民嗇事勞。", "穀實已傷嗟歲廩，麥根雖立望春膏。", "林踈山骨清彌瘦，天闊詩魂病亦豪。", "田舍罕逢車騎過，聚門村婦擁兒曹。"]'),
('48b29996-574b-4f85-89a3-0f292de8167b','初冬祀墳二首  其一','韓琦','宋','宋诗','song-poetry','','[]','曉乘輕凜上平岡，西欵親塋一舍强。',64,'全唐诗/poet.song.19000.json','["曉乘輕凜上平岡，西欵親塋一舍强。", "带靄遠峰時隱見，半霜殘葉雜青黄。", "來牟渴雨空成隴，賓雁衝雲自著行。", "此日初冬嚴祀事，只增悽惕不夸鄉。"]'),
('fba972e8-ea4b-44dd-872c-66a2b046e595','初冬祀墳二首  其二','韓琦','宋','宋诗','song-poetry','','[]','西享先墳已致誠，却嚴軒從指東塋。',64,'全唐诗/poet.song.19000.json','["西享先墳已致誠，却嚴軒從指東塋。", "鴻驚去旆參差起，馬避柔桑詰曲行。", "農寓兵來閑即教，牛無休日旱猶耕。", "病翁寡術蘇疲瘵，徒勸民心厚所生。"]'),
('eacd12a9-0aed-45be-8f77-0200952da660','次韻答判河陽文潞公述相洛所居之勝','韓琦','宋','宋诗','song-poetry','','[]','玉椀高居眾所誇，三川推甲一何嘉。',64,'全唐诗/poet.song.19000.json','["玉椀高居眾所誇，三川推甲一何嘉。", "前兼勝勢韓王第，右枕名區洛尹衙。", "此宅吾鄉聊庇族，悔違公語卜隣家。", "縱思却作招來戶，脚重難營老小車。"]'),
('f19171d7-0513-4c1e-ac81-e90311892661','題忘機堂','韓琦','宋','宋诗','song-poetry','','[]','昔再懷章遂錦遊，壞亭曾復此池頭。',64,'全唐诗/poet.song.19000.json','["昔再懷章遂錦遊，壞亭曾復此池頭。", "今歸舊里藏衰拙，更葺新堂便燕休。", "前檻月波清漲夜，後簷風竹冷吟秋。", "伊余本是無機者，因立嘉名近狎鷗。"]'),
('4590da7d-903a-453b-8598-670087f90fc7','屬疾','韓琦','宋','宋诗','song-poetry','','[]','邪氣潛攻隙，彌旬因伏牀。',48,'全唐诗/poet.song.19000.json','["邪氣潛攻隙，彌旬因伏牀。", "惡寒知肉緩，難睡覺更長。", "謾講添年藥，終無應病方。", "幾時辭厚祿，心泰百憂忘。"]'),
('d6aafb35-8031-470a-b16f-92064fada4be','再題觀魚軒','韓琦','宋','宋诗','song-poetry','','[]','重到觀魚面北軒，正當游泳晚凉天。',64,'全唐诗/poet.song.19000.json','["重到觀魚面北軒，正當游泳晚凉天。", "未歸陶令慚何甚，目識莊生樂亦然。", "幾認琴聲泉漱玉，數驚鈎影月沉弦。", "徐撐畫舫樽前看，必信吾曹是水仙。"]'),
('4506d307-3e3d-4bcc-878c-095c9dcb78f4','歲末省墳','韓琦','宋','宋诗','song-poetry','','[]','因趨先隴問耕桑，益見農家事可傷。',64,'全唐诗/poet.song.19000.json','["因趨先隴問耕桑，益見農家事可傷。", "種麥未生遭土澇，鬻禾無價值錢荒。", "陰風鼓怒資時旱，寒色催愁上夕陽。", "里俗漫矜吾太守，不知何術致民康。"]'),
('c19f009c-6be6-4f33-9e8c-7f851fd28329','元日祀墳','韓琦','宋','宋诗','song-poetry','','[]','寤寐先塋敢暫忘，元正親得奉肴觴。',64,'全唐诗/poet.song.19000.json','["寤寐先塋敢暫忘，元正親得奉肴觴。", "病襟不覺支離困，山勢頻瞻蜿蜒長。", "盡日風埃天黯淡，一冬田隴雪微茫。", "人思三白今無望，只覬春膏浹萬方。"]'),
('0ef5e156-25bd-4cd1-9c59-b3318b200efb','喜雪','韓琦','宋','宋诗','song-poetry','','[]','始駭經冬雪，時飛但斂塵。',48,'全唐诗/poet.song.19000.json','["始駭經冬雪，時飛但斂塵。", "誰知高厚意，頓與發生春。", "已慰三農望，何妨萬卉新。", "病翁聊一醉，歡喜過斯民。"]'),
('1aed01c0-dd0b-4fea-90c3-288cf6b7e947','甲寅燈夕會浄明寺','韓琦','宋','宋诗','song-poetry','','[]','元夕山樓撤舊層，荒年人必減歡朋。',64,'全唐诗/poet.song.19000.json','["元夕山樓撤舊層，荒年人必減歡朋。", "聊趨浄宇莊嚴地，一看通衢自在燈。", "慰俗不專樽俎適，開愁宜有管絃能。", "歌筵列把新詩代，環視應饒士女憎。"]'),
('255d2510-65ac-4d5a-880f-39a1d4c2bc8b','甲寅上元','韓琦','宋','宋诗','song-poetry','','[]','元夕雖荒欲罷難，羣情宜向此時看。',64,'全唐诗/poet.song.19000.json','["元夕雖荒欲罷難，羣情宜向此時看。", "官緣歲歉思從約，俗樂春遊肯自安。", "風引香塵人不斷，月和殘雪夜方寒。", "誰知病守憂民意，歌舞樽前是强歡。"]'),
('e577a5ca-4391-493f-b9a6-b1bda9b2dcae','次韻答王荀龍郎中旅次除夜','韓琦','宋','宋诗','song-poetry','','[]','故陰方向此宵窮，有客趨朝念禮容。',64,'全唐诗/poet.song.19000.json','["故陰方向此宵窮，有客趨朝念禮容。", "將獻未央稱賀酒，坐聽長樂欲明鐘。", "恩回品彙滋榮近，賞及孤平信息濃。", "早晚歸同鄉圃會，縱觀春色上危墉。"]'),
('9111ccd3-51aa-4ca9-8674-0fc6f43dd820','寄題致政李太傅園亭','韓琦','宋','宋诗','song-poetry','','[]','洛下名園比比開，幾何能得主人來。',64,'全唐诗/poet.song.19000.json','["洛下名園比比開，幾何能得主人來。", "爭如塞上抽身早，長向花前盡興回。", "九老儀形傳好事，十洲風景與仙才。", "無時嘯傲煙霞外，世務紛紛想厭咍。"]'),
('f85b8e56-974a-4b32-bb8e-0ea0b17b91c0','早春病起','韓琦','宋','宋诗','song-poetry','','[]','朝來殘雪盡，春意滿東郊。',48,'全唐诗/poet.song.19000.json','["朝來殘雪盡，春意滿東郊。", "嫩綠開池面，深紅點杏梢。", "山晴添遠靄，鴉暖認危巢。", "正是芳時病，吟鸎似見嘲。"]'),
('98e009c4-8076-4fc0-bc23-f3fcb2955d68','北第洛花新開','韓琦','宋','宋诗','song-poetry','','[]','移得花王自洛川，格高須許擅春權。',64,'全唐诗/poet.song.19000.json','["移得花王自洛川，格高須許擅春權。", "管絃圍簇生來貴，天地工夫到此全。", "絕艷好將金作屋，清香宜引玉飛錢。", "一聲舊幕行雲曲，醉斝爭揮不論船。"]'),
('7225a8c3-b3e3-46b5-b390-64ec39f6b5a8','郡圃春晚','韓琦','宋','宋诗','song-poetry','','[]','溶溶春水滿方塘，欄檻風微落蕊香。',64,'全唐诗/poet.song.19000.json','["溶溶春水滿方塘，欄檻風微落蕊香。", "盡日楊花飛又歇，有時林鳥見還藏。", "沈疔不爲閑來減，流景知從靜處長。", "欲戰萬愁無酒力，可堪三月去堂堂。"]'),
('1799e7b1-331c-4cb6-a90a-0b0796344e5c','寄院主浄慧大師','韓琦','宋','宋诗','song-poetry','','[]','祖風門法在坤維，早厭京塵杖錫歸。',64,'全唐诗/poet.song.19000.json','["祖風門法在坤維，早厭京塵杖錫歸。", "已大化緣興佛事，更窮真際得禪機。", "人觀相好咸生信，師顧莊嚴亦謂非。", "岡指牛眠今果驗，益知囊訣盡精微。"]'),
('08ecbd18-7c5f-4e2a-a459-f820260a7bcb','春寒呈提舉陳薦龍圖','韓琦','宋','宋诗','song-poetry','','[]','春寒入人骨，病肌尤見侵。',48,'全唐诗/poet.song.19000.json','["春寒入人骨，病肌尤見侵。", "芳園欲暫適，風惡不可禁。", "回身復擁爐，噤餘難發吟。", "幾日陽和恩，一開愁悴心。"]'),
('c4d4f87a-1710-4eee-99fc-d719ea10721c','癸丑再題康樂園','韓琦','宋','宋诗','song-poetry','','[]','曾拓名園壯鄴中，本思行樂興民同。',64,'全唐诗/poet.song.19000.json','["曾拓名園壯鄴中，本思行樂興民同。", "人安日見嬉遊盛，歲久誰知治葺功。", "幾席病春臺榭雨，一軒忘暑芰荷風。", "三來欲伴羣心適，勉强樽前作醉公。"]'),
('49800a5a-8d29-4077-8e9f-90b646b52aee','春日磑亭同會','韓琦','宋','宋诗','song-poetry','','[]','金湯西北綠陰中，雙磑當渠一派通。',64,'全唐诗/poet.song.19000.json','["金湯西北綠陰中，雙磑當渠一派通。", "人跡罕來花自老，利源常在水何功。", "事能如意嗟常少，春苦無情去又空。", "大抵相知難會合，且同樽酒醉春風。"]'),
('9b034c12-1b83-4ef6-bffa-24d7a045deb0','寒食祀墳二首  其一','韓琦','宋','宋诗','song-poetry','','[]','禁煙時重展先塋，今日躬爲拜掃行。',64,'全唐诗/poet.song.19000.json','["禁煙時重展先塋，今日躬爲拜掃行。", "撲面塵多嗟歲旱，得苗田少奈民生。", "二分春過寒猶峭，四合山來眼暫明。", "思奉松楸存寤寐，不國濡露始勤誠。"]'),
('a8cf0611-9972-408d-b324-e778285c130f','寒食祀墳二首  其二','韓琦','宋','宋诗','song-poetry','','[]','太行山下列兒孫，重疊千峰浪勢奔。',64,'全唐诗/poet.song.19000.json','["太行山下列兒孫，重疊千峰浪勢奔。", "近麓縈回藏勝地，先墳長遠得安村。", "雖榮不及豐親養，更病須來潔祭樽。", "欲使族中知盡力，各思忠孝大吾門。"]'),
('ac42dd4d-b583-4e57-bab2-a4c460a69ddc','寒食東墳','韓琦','宋','宋诗','song-poetry','','[]','萬株松柏筆鋒攢，塋在西岡落處安。',64,'全唐诗/poet.song.19000.json','["萬株松柏筆鋒攢，塋在西岡落處安。", "念祖力完先隴易，祀墳三作守臣難。", "農疇失稔煙徒禁，祭禮從風食尚寒。", "已事勿嗟歸甚速，要勤營奉合休官。"]'),
('98a89e73-4c9b-4507-bec3-1ad2c2781660','靈嶽道中','韓琦','宋','宋诗','song-poetry','','[]','東西岡遠截空橫，岡下村村聚落成。',64,'全唐诗/poet.song.19000.json','["東西岡遠截空橫，岡下村村聚落成。", "柳線略無經雨色，麥針微向近河生。", "龍鐘父老知迎拜，磽確田疇尚力耕。", "自古班春須卹患，我觀民病若爲平。"]'),
('3e08a32f-2b2e-4661-b452-e7c6b02d36ad','清明同上巳','韓琦','宋','宋诗','song-poetry','','[]','清明池館足遊人，祓禊風光共此辰。',64,'全唐诗/poet.song.19000.json','["清明池館足遊人，祓禊風光共此辰。", "晉俗浮觴存勝事，漢宮傳蠟寵隣臣。", "若云荒政宜蕃樂，是使熙臺失眾春。", "應候從來多甚雨，幾時膏澤慰斯民。"]'),
('e6a2e279-ad0a-4cf0-989d-cc868b8f1396','寒食開園','韓琦','宋','宋诗','song-poetry','','[]','名園民喜及時開，聊慰羣心共一杯。',64,'全唐诗/poet.song.19000.json','["名園民喜及時開，聊慰羣心共一杯。", "美酒眾忘深巷陌，好花生值惡風埃。", "遊人盡陟春臺去，尺雨宜蘇旱歲來。", "病守當筵誰會得，不聽鐘鼓只聽雷。"]'),
('1594866a-acd3-4212-b805-d8c16c02b049','晝錦堂同賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','牡丹親植錦堂前，回首光陰二十年。',64,'全唐诗/poet.song.19000.json','["牡丹親植錦堂前，回首光陰二十年。", "一見開顔如有舊，三來經賞豈無緣。", "競新品目應輸洛，獨守單平似信天。", "欲寄朝雲皆大筆，願搜豪句飾妖妍。"]'),
('bfbf3f30-b44c-49f8-b649-0838db7d602d','晝錦堂再賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','錦堂重賞牡丹紅，不惜殘英數日空。',64,'全唐诗/poet.song.19000.json','["錦堂重賞牡丹紅，不惜殘英數日空。", "嘉艷豈無來歲好，清歡難得故人同。", "誰言山下曾爲雨，只恐身輕去逐風。", "且共對花開口笑，莫持姚左較雌雄。"]'),
('25995e03-197f-42ed-90e0-a09d720029da','暮春書事','韓琦','宋','宋诗','song-poetry','','[]','榆莢空飛不算錢，韶光歸速置何緣。',64,'全唐诗/poet.song.19000.json','["榆莢空飛不算錢，韶光歸速置何緣。", "惜春情味過年少，戰酒英雄退日前。", "竹笋迸階抽兕角，楊花鋪水漲龍涎。", "妖妍萬變成凋謝，長養須資大夏權。"]'),
('bed22fdd-95e9-4a43-8c7d-8453933d5f55','暮春書事自和','韓琦','宋','宋诗','song-poetry','','[]','東君回轡肯流連，詩入衰情更易緣。',64,'全唐诗/poet.song.19000.json','["東君回轡肯流連，詩入衰情更易緣。", "荷葉如錢生水面，楊花飛雪滿階前。", "感時空濺傷春淚，殢酒思流見麴涎。", "殘景向人催上老，似推公道不容權。"]'),
('67040c41-f399-487c-b27c-6b63be3cd34d','北第同賞芍藥','韓琦','宋','宋诗','song-poetry','','[]','芍藥名高致亦難，此觀妖艷滿彫欄。',64,'全唐诗/poet.song.19000.json','["芍藥名高致亦難，此觀妖艷滿彫欄。", "酒酣誰欲張珠網，金鈿偏宜間寶冠。", "露裛更深雲髻重，蝶樓長苦玉樓寒。", "鄭詩已取相酬贈，不見諸經載牡丹。"]'),
('3f084e58-5a07-4cf5-a920-c16e70d469b6','狎鷗亭同賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','東亭嘗種廣陵花，美艷新增出舊芽。',64,'全唐诗/poet.song.19000.json','["東亭嘗種廣陵花，美艷新增出舊芽。", "小魏風標高洛品，大喬流徙得孫家。", "丹砂纈妙深難染，白玉冠危瑩絕瑕。", "肯與姚黄爲近侍，亦須稱后始無差。"]'),
('933a477b-9139-4576-a769-e63f9f6d6770','久旱喜雨','韓琦','宋','宋诗','song-poetry','','[]','旱災誠久歷三時，祠禱雖虔似不知。',64,'全唐诗/poet.song.19000.json','["旱災誠久歷三時，祠禱雖虔似不知。", "一夕雲雷施利澤，萬家溝壑復生期。", "禾苗立後收多早，天意回來此未遲。", "恩被無垠才數刻，盡思人力欲何爲。"]'),
('2a6e23fc-127e-4ba2-8c32-3fa1ae47bf0a','初伏避暑','韓琦','宋','宋诗','song-poetry','','[]','四序推遷理亦常，其間天意或難詳。',64,'全唐诗/poet.song.19000.json','["四序推遷理亦常，其間天意或難詳。", "將令炎暑收殘虐，何使清商預伏藏。", "幾日西風來拂袵，昔時中冀盛飛觴。", "無辭剩引南燕酌，鹽疊冰峰合坐凉。"]'),
('13e4b952-62f5-4a93-8766-0b42fe75cb5f','寄提舉劉思封','韓琦','宋','宋诗','song-poetry','','[]','連年河朔失時豐，將漕推能選擢公。',64,'全唐诗/poet.song.19000.json','["連年河朔失時豐，將漕推能選擢公。", "萬慮本期充歲計，一言思欲動宸衷。", "知難願易澄清寄，遂請俄司峻極宮。", "殿柱有題應不忘，肯容材哲便甘窮。"]'),
('ce85f493-7e3d-4c49-9710-fbe9d36f7e8f','七夕','韓琦','宋','宋诗','song-poetry','','[]','星潢今夕度仙輈，人世爭爲乞巧樓。',64,'全唐诗/poet.song.19000.json','["星潢今夕度仙輈，人世爭爲乞巧樓。", "萬室瞻迎皆欲得，一生孤拙未嘗求。", "緱山月白遺新曲，漢殿窗明識舊偷。", "若道營橋真浪說，如何飛鵲盡髠頭。"]'),
('f13e8dd9-65cb-4c20-9809-616a60478dde','次韻答文侍中寄示韓晉公村田歌舞圖顔魯公跋尾仍使題於後','韓琦','宋','宋诗','song-poetry','','[]','韓畫顔書世絕珠，鈴齋時足奉驩虞。',32,'全唐诗/poet.song.19000.json','["韓畫顔書世絕珠，鈴齋時足奉驩虞。", "跋題應命誠羞澀，不是跳龍卧虎徒。"]'),
('06230df2-d7c7-4425-9da5-40cdca033979','甲寅中秋對月二首  其一','韓琦','宋','宋诗','song-poetry','','[]','七寶成輪上海東，他圓爭與此時同。',64,'全唐诗/poet.song.19000.json','["七寶成輪上海東，他圓爭與此時同。", "須知一夜清光別，爲得三秋正色中。", "唐曲聽回雲作駕，鄴園游盛蓋飛鴻。", "古人只恨音塵闊，對賞樽樽願一空。"]'),
('7611c975-5b4d-4555-961c-b68bca1065c8','甲寅中秋對月二首  其二','韓琦','宋','宋诗','song-poetry','','[]','中秋侵夕啟賓罍，共看長空一鑑開。',64,'全唐诗/poet.song.19000.json','["中秋侵夕啟賓罍，共看長空一鑑開。", "四坐雪霜清耳目，萬家崑閬倚樓臺。", "波凉桂子從天落，陰極潮頭半海來。", "正好抽毫競高唱，當筵人勝仲宣才。"]'),
('96941863-9237-4cfe-8f71-dffbc4f3da5c','提舉陳龍圖遷居邢臺二首  其一','韓琦','宋','宋诗','song-poetry','','[]','鄉居新葺後，歸興邈難招。',48,'全唐诗/poet.song.19000.json','["鄉居新葺後，歸興邈難招。", "老去重離別，秋來添寂寥。", "雲橫初送雁，渡淺未成橋。", "千里猶思駕，封圻幸不遥。"]'),
('cff6e963-d579-4e79-9716-d654115a5c73','提舉陳龍圖遷居邢臺二首  其二','韓琦','宋','宋诗','song-poetry','','[]','多病襟懷易入憂，那堪驚別復驚秋。',64,'全唐诗/poet.song.19000.json','["多病襟懷易入憂，那堪驚別復驚秋。", "難追劉白樽前樂，尚約松喬世外遊。", "花發東籬誰共酌，草荒南浦只生愁。", "從茲冷落歡吟地，晝錦榮歸興狎鷗。"]'),
('d9c19e80-9648-4162-9782-0a41e54b0c05','甲寅重九','韓琦','宋','宋诗','song-poetry','','[]','勉同風俗燕重陽，可惜良辰值歲荒。',64,'全唐诗/poet.song.19000.json','["勉同風俗燕重陽，可惜良辰值歲荒。", "南畝流民方塞路，東籬嘉菊漫浮觴。", "雖無絃管追遊樂，賴有山川氣象强。", "自笑當筵陶靖節，幾時歸去傲羲皇。"]'),
('cb025223-172d-40ff-9891-9ce783e753a8','孟冬朔日祀墳二首  其一','韓琦','宋','宋诗','song-poetry','','[]','親塋來展祀，郊野未霜嚴。',48,'全唐诗/poet.song.19000.json','["親塋來展祀，郊野未霜嚴。", "古道日低削，高山時仰瞻。", "寒花雖在目，短穀不加鐮。", "多少幽閑趣，吾方事退潛。"]'),
('ba72f720-d085-4201-8fc6-b6c7d503f420','孟冬朔日祀墳二首  其二','韓琦','宋','宋诗','song-poetry','','[]','首冬齋潔展先塋，極目郊原一望清。',64,'全唐诗/poet.song.19000.json','["首冬齋潔展先塋，極目郊原一望清。", "無限人心蘇尺雨，有時天意活蒼生。", "遥林蓊鬰霜來晚，荒隴稀踈穗不成。", "何術濟民歸未得，媿偷官祿奉粢盛。"]'),
('e141f2a2-5e6b-47fa-9b29-6aff4634cd81','祀墳馬上','韓琦','宋','宋诗','song-poetry','','[]','二塋逢節展松楸，因嘆農疇薦不收。',64,'全唐诗/poet.song.19000.json','["二塋逢節展松楸，因嘆農疇薦不收。", "高穗有時存蜀黍，善耕猶惜賣吳牛。", "泉乾幾處閑機磑，雨過誰家用糞樓。", "首種漸生還自喜，尚憂難救赤春頭。"]'),
('5d38ea59-7a90-41ba-af3b-a7bb5018aa91','次韻答趙少師以南京永壽禪院主僧崇祐於新鐵鑄佛大殿後建堂寫真於其中','韓琦','宋','宋诗','song-poetry','','[]','懷德思人始繪容，不緣斯舉理難窮。',64,'全唐诗/poet.song.19000.json','["懷德思人始繪容，不緣斯舉理難窮。", "兔園何有安民迹，鷲嶺兼無護法功。", "名姓不傳勳閣上，儀形徒入梵祠中。", "願更此誤圖公像，公行宜居極樂宮。"]'),
('4c2797d7-b03a-4ffa-a8e2-0b9f79911027','次韻答提舉劉司封見訪','韓琦','宋','宋诗','song-poetry','','[]','琳館優閑祿隱郎，高懷存舊寵吾鄉。',64,'全唐诗/poet.song.19000.json','["琳館優閑祿隱郎，高懷存舊寵吾鄉。", "觀梁共且希魚樂，巢閣終應待鳳翔。", "囊疏一時驚慄慄，殿楹常記日堂堂。", "忠言非久回宸慮，坐見無爲拱舜廊。"]'),
('31ac43d4-6967-4798-95c8-2fc887a4c822','次韻和文潞公題王右丞維輞川圖','韓琦','宋','宋诗','song-poetry','','[]','輞川誠自好，人各愛吾園。',48,'全唐诗/poet.song.19000.json','["輞川誠自好，人各愛吾園。", "欲縱家山樂，終縻吏事繁。", "鴻飛思避弋，羝觸困羸籓。", "幾日歸陶徑，方知踐此言。"]'),
('995d15d8-0f5b-4ede-8ceb-81ecb2abe24e','次韻和文潞公題韓晉公村田歌舞圖','韓琦','宋','宋诗','song-poetry','','[]','升平胡可狀，歌舞入樵蘇。',48,'全唐诗/poet.song.19000.json','["升平胡可狀，歌舞入樵蘇。", "歲美人皆樂，朝和野共娛。", "心休無事擾，本固絕顛扶。", "我願明時治，長如此畫圖。"]'),
('6084499c-fd2d-491a-a7ce-3f2334e6c619','次韻答提舉王郎中','韓琦','宋','宋诗','song-poetry','','[]','病質衰來百事慵，遺榮心欲企高蹤。',64,'全唐诗/poet.song.19000.json','["病質衰來百事慵，遺榮心欲企高蹤。", "疲駑向老知無用，聖德矜愚諒有容。", "筋力豈能誇矍鑠，林泉終幸養孱庸。", "東籬秋晚黄花盛，陶令思歸興愈濃。"]'),
('1b81e629-692e-4a8e-aad9-5fcdb5985b5e','次韻答提舉王郎中歲除有感','韓琦','宋','宋诗','song-poetry','','[]','歲除詩筆復加勤，和寡辭高過郢人。',64,'全唐诗/poet.song.19000.json','["歲除詩筆復加勤，和寡辭高過郢人。", "可念風期千里闊，又看春態一年新。", "幾時鄰糴盈倉足，來濟吾民比戶貧。", "開道海艘將自押，使車應捨未須巾。"]'),
('437accde-80be-4f11-9a9e-cf8c5704710e','閔農','韓琦','宋','宋诗','song-poetry','','[]','仍歲農疇失夏秋，方春尤窘奈饑流。',64,'全唐诗/poet.song.19000.json','["仍歲農疇失夏秋，方春尤窘奈饑流。", "人無粒食何堪命，天作陰寒亦似愁。", "煮葉不遑爲木酪，翳桑惟日徯囊糇。", "幾時膏澤充民望，待看來年十倍收。"]'),
('70d543d2-c4ea-4f5b-b2bd-cedb31880a47','假竇侍郎安車元日祀墳','韓琦','宋','宋诗','song-poetry','','[]','小車聊假便衰殘，上冢都忘涉路難。',64,'全唐诗/poet.song.19000.json','["小車聊假便衰殘，上冢都忘涉路難。", "坐卧俏能伸手足，堅完誠可避風寒。", "搴帷自不希前躅，憑軾時還遂一觀。", "暫得容身終未穩，退歸乘此始爲安。"]'),
('552b46d9-1fdd-49e4-a734-18d32f237ea5','元日祀墳道中','韓琦','宋','宋诗','song-poetry','','[]','新元先隴遂伸虔，荒歲嗟逢眾食艱。',64,'全唐诗/poet.song.19000.json','["新元先隴遂伸虔，荒歲嗟逢眾食艱。", "比戶生涯皆墨突，幾家林木似牛山。", "三陽已泰春來懶，六幕雖昏雪尚慳。", "道殣寖多無力救，據鞍衰叟只慚顔。"]'),
('900ccce2-9742-4570-81ce-c2ee28a11c77','提舉陳龍圖春寒惠然見訪','韓琦','宋','宋诗','song-poetry','','[]','冒寒連驛促征輪，須信相思是故人。',64,'全唐诗/poet.song.19000.json','["冒寒連驛促征輪，須信相思是故人。", "頓似清風袪大暑，何嗟明月隔芳塵。", "雪隈簷角依微在，春著花稍次第新。", "不把一杯同一笑，此時幽憤興誰伸。"]'),
('43f0e39f-8c93-4181-8369-7c9fe35c153e','北第會陳龍圖','韓琦','宋','宋诗','song-poetry','','[]','重喜延松奉宴遊，只期軒從少遲留。',64,'全唐诗/poet.song.19000.json','["重喜延松奉宴遊，只期軒從少遲留。", "花移上闕看爭發，酒熟宜城可旋篘。", "正好一杯同撥悶，信應千古足銷愁。", "人生不是無交舊，難得相知到白頭。"]'),
('008886cf-6ec5-4ac0-806c-c9e096092f01','戇老庵會陳龍圖','韓琦','宋','宋诗','song-poetry','','[]','北第新成戇老庵，日期休此養無堪。',64,'全唐诗/poet.song.19000.json','["北第新成戇老庵，日期休此養無堪。", "地偏深得幽居興，景野難將俗好參。", "戶外鳴泉疑拊石，城頭叢薄當凝嵐。", "何須便挹浮邱袂，且奉高賢聽雅談。"]'),
('8b24a290-cd7d-4e4b-8a4e-f51739093d9d','浮醴亭會陳龍圖','韓琦','宋','宋诗','song-poetry','','[]','愛客筵當曲水開，肴觴交出任縈回。',64,'全唐诗/poet.song.19000.json','["愛客筵當曲水開，肴觴交出任縈回。", "歌聲直向梁間住，春色偏從洞裏來。", "不繫舟虛誰觸忤，無機鷗近絕驚猜。", "休論俛仰爲陳迹，且學山陰祓禊杯。"]'),
('f6a0ca85-b8a1-4862-ac74-ddbb5cbcf50d','提舉陳龍圖特垂顧遽促歸軒','韓琦','宋','宋诗','song-poetry','','[]','千里相思訪所知，昔人曾有此聞稀。',64,'全唐诗/poet.song.19000.json','["千里相思訪所知，昔人曾有此聞稀。", "方欣一見銷萌吝，便忍連章賦式微。", "早是衰年多感慨，不堪寒色挫芳菲。", "剡溪雪月光如晝，懊惱仙舟興盡歸。"]'),
('79522894-60d3-42d7-bcc4-d82c1bf878ed','乙卯巳會醴亭','韓琦','宋','宋诗','song-poetry','','[]','熙熙春色水溶溶，修禊臨流景倍濃。',64,'全唐诗/poet.song.19000.json','["熙熙春色水溶溶，修禊臨流景倍濃。", "物外風光占崑閬，洞中神變走魚龍。", "飄花任逐紅塵去，浮醴時看紫府供。", "欲學永和當日序，媿無奇筆紹前蹤。"]'),
('053e3a87-9092-4b72-9594-562378bc1543','三月五日會浮醴亭','韓琦','宋','宋诗','song-poetry','','[]','曲水春閑遂宴嬉，何須元巳始爲宜。',64,'全唐诗/poet.song.19000.json','["曲水春閑遂宴嬉，何須元巳始爲宜。", "且看真洞杯盤出，豈顧塵寰節序移。", "曳尾靈龜來可羨，乘槎仙客去難追。", "一觴一詠無絃管，恰似蘭亭列坐時。"]'),
('92de1d44-b0c9-490a-bc60-6e1c1f9cfa53','乙卯寒食祀墳','韓琦','宋','宋诗','song-poetry','','[]','鄉守三逢禁火天，每驅旌纛掃松阡。',64,'全唐诗/poet.song.19000.json','["鄉守三逢禁火天，每驅旌纛掃松阡。", "衰殘豈足酬恩遇，光寵徒知及祖先。", "望極西山饒勝氣，樂舒東戶革荒年。", "何時歸處墳廬下，不假蘇秦負郭田。"]'),
('4619e004-b90b-494d-86ff-26420939c05a','祀墳道中','韓琦','宋','宋诗','song-poetry','','[]','雖欣膏澤啟豐年，民病猶艱救目前。',64,'全唐诗/poet.song.19000.json','["雖欣膏澤啟豐年，民病猶艱救目前。", "闕祀丘墳無解裂，薦饑村落少鞦韆。", "雲梳隴麥千行直，粉淡牆花半臉妍。", "榆莢漸能供歉腹，何曾拋得買春錢。"]'),
('be20e5fa-0e71-4444-a28e-4157785657e3','祀墳遇風','韓琦','宋','宋诗','song-poetry','','[]','忽極暄融候莫窮，不爲膏澤却爲風。',64,'全唐诗/poet.song.19000.json','["忽極暄融候莫窮，不爲膏澤却爲風。", "氣蒸人腹成中熱，塵入花心作病蟲。", "欲望好峰迷遠目，正濃韶景失晴空。", "飄然終日俄收怒，歸送旌旗撼晚紅。"]'),
('26625b70-a1f2-4672-b763-2f6b6f34645b','北第同賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','正是花王穀雨天，此携尊酒一憑軒。',64,'全唐诗/poet.song.19000.json','["正是花王穀雨天，此携尊酒一憑軒。", "陽臺幾日徒驚夢，息國經年又不言。", "但得留連詞客醉，算難回避蜜蜂喧。", "自從標錦輸先手，羞見妖紅作狀元。"]'),
('d0ec295d-6ab6-4fcf-bc61-332efd764abe','觀王推官園牡丹','韓琦','宋','宋诗','song-poetry','','[]','風養花王接舜薰，始知仙圃別藏春。',64,'全唐诗/poet.song.19000.json','["風養花王接舜薰，始知仙圃別藏春。", "欣聞東道招來數，得見西京譜外新。", "九萼壓叢看易失，萬金邀客日須頻。", "羣芳面我應相識，便是宜輕不退人。"]'),
('0fcd6454-b3ad-48b8-a4c5-a5a045044d4e','乙卯晝錦堂同賞牡丹','韓琦','宋','宋诗','song-poetry','','[]','從來三月賞芳妍，開晚今逢首夏天。',64,'全唐诗/poet.song.19000.json','["從來三月賞芳妍，開晚今逢首夏天。", "料得東君私此老，且留西子久當筵。", "柳絲偷學傷春緒，榆莢爭飛買笑錢。", "我是至和親植者，雨中相見似潸然。"]'),
('2522dc91-73e9-4d1c-bede-0aa797c84afa','柳絮','韓琦','宋','宋诗','song-poetry','','[]','楊柳生花不戀枝，紛紛終日亦何依。',64,'全唐诗/poet.song.19000.json','["楊柳生花不戀枝，紛紛終日亦何依。", "聚來庭下爲毬輥，散向空中作雪飛。", "閒共落英浮遠水，靜和幽蝶舞斜暉。", "見君方惜春難住，忍縱輕狂攪擾歸。"]'),
('3dc8b382-2233-45cf-a288-f21681d377f6','乙卯北第同賞芍藥','韓琦','宋','宋诗','song-poetry','','[]','維揚嘉種發清和，灼灼吾園盛孰過。',64,'全唐诗/poet.song.19000.json','["維揚嘉種發清和，灼灼吾園盛孰過。", "紅玉鬭成樓突兀，白雲爭簇髻巍峩。", "仙容世必推茅嶺，醉豔人誰敵苧蘿。", "不是栽培功未至，年年何苦轉枝多。"]'),
('b53d3140-7d3e-4c0d-b9fd-14ed2707eb18','北第再賞芍藥','韓琦','宋','宋诗','song-poetry','','[]','廣陵花發信惟夭，已剪還開客重邀。',64,'全唐诗/poet.song.19000.json','["廣陵花發信惟夭，已剪還開客重邀。", "滿引莫辭金鑿落，盛觀何止玉逍遥。", "嬌紅鬧密輕多葉，醉粉欹斜奈軟條。", "且縱高吟賞真豔，侍姝羞匿不須招。"]'),
('fcdef848-d18d-4ee5-9fda-7e08577558d2','狎鷗亭同賞芍藥','韓琦','宋','宋诗','song-poetry','','[]','家園經賞復官園，芍藥多名兩共妍。',64,'全唐诗/poet.song.19000.json','["家園經賞復官園，芍藥多名兩共妍。", "醉白堂前淮海豔，狎鷗亭下鳳麟天。", "樓粧瑞玉千層密，冠縷真金半尺圓。", "不鬭詩豪開酒戶，是將傾國欲輕捐。"]'),
('d3a63c48-45a2-48fa-b4ab-61a708a45343','初會醉白堂','韓琦','宋','宋诗','song-poetry','','[]','因建新堂慕昔賢，本期歸老此安然。',64,'全唐诗/poet.song.19000.json','["因建新堂慕昔賢，本期歸老此安然。", "輕陰竹滿窗間月，倒影蓮開水下天。", "自向酒中知有德，更於琴外曉無絃。", "霓裳百指非吾事，只學醺酣石上眠。"]'),
('070dd741-fadd-486d-b84a-6de5e5c6c98a','章獻明肅皇太后挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','一紀禆鴻化，千齡從列仙。',48,'全唐诗/poet.song.19000.json','["一紀禆鴻化，千齡從列仙。", "至仁高協帝，厚德遠參乾。", "驗寡親嘗藥，恩深欲報天。", "爲殫臣庶淚，朝雨助潸然。"]'),
('ed8af6e0-632b-4b0d-ba7d-41ac9ebe3fe0','章獻明肅皇太后挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','璿駕方修祀，金波忽墜空。',48,'全唐诗/poet.song.19000.json','["璿駕方修祀，金波忽墜空。", "悲歌傳薤露，祕殿閴椒風。", "霧重昏軒曜，雲悽泣舜瞳。", "仙輿邈何在，天外蕊珠宮。"]'),
('b7c1b9c7-ce54-4c84-a179-56b2fa25fd51','章懿皇太后挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','外族傳仙系，中閨著德容。',48,'全唐诗/poet.song.19000.json','["外族傳仙系，中閨著德容。", "瑞符衣覆玉，懿範史編彤。", "天闊雲埋仗，秋高露泣松。", "宸心望歸駕，滄海晦三峰。"]'),
('7d1fc764-e80a-4b1f-832a-2410280bf8c8','章懿皇太后挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','夢日推祥舊，儀坤講禮新。',48,'全唐诗/poet.song.19000.json','["夢日推祥舊，儀坤講禮新。", "帝親無及養，天意此何仁。", "宮寢延嵩月，褘褕寓洛塵。", "欲知仁主孝，淚血送龍輴。"]'),
('37bca504-e13e-4656-9e06-0eae69e03dcf','章惠皇太后挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','椒掖遺芳在，龜臺別信空。',48,'全唐诗/poet.song.19000.json','["椒掖遺芳在，龜臺別信空。", "舊恩緣服重，新廟見慈同。", "殘月無多夜，餘花一向風。", "徽音從此斷，忍顧洛川東。"]'),
('3f852ecd-b6f4-4a77-9e9d-4251957070f6','章惠皇太后挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','柔順符坤德，興居監女箴。',48,'全唐诗/poet.song.19000.json','["柔順符坤德，興居監女箴。", "笥衣裙有練，殿壁带無金。", "外族疏恩薄，中宸結愛深。", "宮娥齊飲泣，誰副祝延心。"]'),
('4d750ea2-f597-46a5-a4ac-8f12713e8a48','仁宗皇帝揭辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','道久民胥化，幾先慮極深。',48,'全唐诗/poet.song.19000.json','["道久民胥化，幾先慮極深。", "勤邦循禹度，傳聖得堯心。", "生德齊天地，仁聲振古今。", "三山神藥在，滄海信空沉。"]'),
('e6a52c1d-5373-4dd6-81ad-528ddafaba61','仁宗皇帝揭辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','薄葬定隣邊，民安即舊廛。',48,'全唐诗/poet.song.19000.json','["薄葬定隣邊，民安即舊廛。", "大非空六馬，深不錮三泉。", "忍逐宮車出，翻隨玉輅旋。", "西都無限竹，淚色似湘川。"]'),
('d90e303f-c912-4037-8cff-83a98f8da518','仁宗皇帝揭辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','聖治方無事，仙遊遽不還。',48,'全唐诗/poet.song.19000.json','["聖治方無事，仙遊遽不還。", "心休黄屋外，鄉還白雲間。", "笳鼓悽寒月，旌旗卷暮關。", "孤臣期得殉，黄鳥願重刪。"]'),
('f5ee3195-c9fb-48e5-84e0-73ebc869d381','英宗皇帝挽辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','遽委飛乾運，應開出震符。',48,'全唐诗/poet.song.19000.json','["遽委飛乾運，應開出震符。", "子方批鳳尾，天已下龍胡。", "遏密思堯治，謳歌啟舜圖。", "只留勤儉德，千古亙三無。"]'),
('a1d8c196-f10f-4aa7-ab4f-f0219c1d6dd2','英宗皇帝挽辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','此日天無色，輴車下禁宸。',48,'全唐诗/poet.song.19000.json','["此日天無色，輴車下禁宸。", "悲風隨去仗，哀淚裛行塵。", "一閉皇堂夜，長閒御寢春。", "守陵來有幾，蕭索慶寧人。"]'),
('ecf138c5-7e3e-491a-ace7-df6adc5705a1','英宗皇帝挽辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','蜃駕雖停洛，飆輿已遡天。',48,'全唐诗/poet.song.19000.json','["蜃駕雖停洛，飆輿已遡天。", "空藏軒劍舄，不敢霸山川。", "挽揭秋聲外，旌翻夕照前。", "老臣非從死，何路答知憐。"]'),
('f4a8e5bf-f7be-43be-9366-b56da4e115d4','司徒侍中杜公挽辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','早退輕高位，孤風振昔賢。',48,'全唐诗/poet.song.19000.json','["早退輕高位，孤風振昔賢。", "上思終不已，民望日依然。", "榮寵三增秩，優游十換年。", "請看良史舊，德孰似公全。"]'),
('da222845-8cae-48c0-bbb3-1ae8ad719c3d','司徒侍中杜公挽辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','直道當年梗，清名萬世師。',48,'全唐诗/poet.song.19000.json','["直道當年梗，清名萬世師。", "身閒心在國，跡退德高時。", "警絕新詩雅，飛騰老筆奇。", "歸休何所樂，持此造希夷。"]'),
('670072d0-e7b9-4c06-b920-3ffeed32f50a','司徒侍中杜公挽辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','哲人何永逝，天理此難忱。',48,'全唐诗/poet.song.19000.json','["哲人何永逝，天理此難忱。", "子謹新遺札，家無舊賜金。", "可傳清白業，未足太平心。", "訃至悲尤動，忘年顧遇深。"]'),
('5ce0688b-d2c6-44d9-a68d-0682b2d347f4','僕射王公挽辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','早冠廉良選，尋專翰墨盟。',48,'全唐诗/poet.song.19000.json','["早冠廉良選，尋專翰墨盟。", "上知唯直道，人愛是純誠。", "樞極權無撓，台衡論必平。", "嗚呼今已矣，天不爲蒼生。"]'),
('b0ff54ab-0f19-4053-aba6-da742c471a76','僕射王公挽辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','公昔魁多士，予時託後塵。',48,'全唐诗/poet.song.19000.json','["公昔魁多士，予時託後塵。", "交因荷心照，義實過天倫。", "進始欣連茹，官終愧積薪。", "牙絃茲遂絕，不見賞音人。"]'),
('633c6f2f-3abe-4a95-9755-8e31e9a0a75c','僕射王公挽辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','相府陪高議，於時適共榮。',48,'全唐诗/poet.song.19000.json','["相府陪高議，於時適共榮。", "開懷敘疇昔，協力冀登平。", "幾日違言笑，何期隔死生。", "寢門長慟後，追愴不勝情。"]'),
('b1f532c2-7ee5-46d5-a896-3903da2dda86','張汝士寺丞挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','昔與君遊者，芝蘭永更芳。',48,'全唐诗/poet.song.19000.json','["昔與君遊者，芝蘭永更芳。", "高懷澄水月，和氣燠春陽。", "陳迹川流遠，嘉名歲景長。", "平生歐尹友，嘗歎善人亡。"]'),
('5a00f748-f91e-4778-92e9-922e3a6071c6','張汝士寺丞挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','滿腹康時業，丁年未一伸。',48,'全唐诗/poet.song.19000.json','["滿腹康時業，丁年未一伸。", "方從中洛掾，俄掩北邙塵。", "有子賢荀里，登科感孟鄰。", "新阡伊闕下，長得塞門春。"]'),
('6fa5b67f-94e4-4bb7-b701-a22025a66fc9','江西提點刑獄閻顒郎中挽辭一首','韓琦','宋','宋诗','song-poetry','','[]','昔忝中山帥，君時佐郡條。',48,'全唐诗/poet.song.19000.json','["昔忝中山帥，君時佐郡條。", "協心圖治俗，同榜喜爲僚。", "方卜門容駟，俄驚坐賦鴞。", "新阡思一慟，西蜀奈迢遥。"]'),
('4c156851-f2eb-41a4-8a47-8512e6437827','致政王子融侍郎挽辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','公昔求還事，年猶未縱心。',48,'全唐诗/poet.song.19000.json','["公昔求還事，年猶未縱心。", "軒裳輕俗累，水月瑩禪襟。", "樂任荒三徑，閒時戲一禽。", "陶然踰五閏，已矣世同欽。"]'),
('6d6dd759-7906-4798-82c7-13ca0221ffe8','致政王子融侍郎挽辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','伯氏勳名永，繇公左右然。',48,'全唐诗/poet.song.19000.json','["伯氏勳名永，繇公左右然。", "賢碑求帝篆，行錄廣時傳。", "餘範光門法，遺文粲史編。", "欲知天報厚，五福賜君全。"]'),
('d9893b65-23af-4c71-9cc8-e6cd19341902','致政王子融侍郎挽辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','昔貳淄川政，嘗依太守賢。',48,'全唐诗/poet.song.19000.json','["昔貳淄川政，嘗依太守賢。", "于門欽世德，阮巷忝親聯。", "僕始慙當軸，公方遂引年。", "音容俄永隔，抆泣望新阡。"]'),
('99751988-31da-4fc4-bad9-126326cc3c05','太尉侍中宋公挽辭三首  其一','韓琦','宋','宋诗','song-poetry','','[]','科等魁髦彥，文章壓縉紳。',48,'全唐诗/poet.song.19000.json','["科等魁髦彥，文章壓縉紳。", "大權更將相，優寵極人臣。", "還事至一品，享年踰七旬。", "請看今與昔，誰可望公鄰。"]'),
('dc927330-9d0c-49fb-9ebd-5e0044be0bc9','太尉侍中宋公挽辭三首  其二','韓琦','宋','宋诗','song-poetry','','[]','仁皇求治始，公出冠儒英。',48,'全唐诗/poet.song.19000.json','["仁皇求治始，公出冠儒英。", "仕路知卿相，時名獨弟兄。", "兩朝推重德，當世服純誠。", "身後傳家者，羣書但滿籝。"]'),
('e3cdf96f-b55f-422e-a9e1-b8710019c097','太尉侍中宋公挽辭三首  其三','韓琦','宋','宋诗','song-poetry','','[]','注想尊元老，云亡歎哲人。',48,'全唐诗/poet.song.19000.json','["注想尊元老，云亡歎哲人。", "恤章隆上衮，哀挽出中宸。", "史入經綸迹，文藏造化神。", "茄簫陽翟路，行者亦霑巾。"]'),
('eb418535-534c-4fd5-8d23-9be6f9613e3f','蘇洵員外挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','對未延宣室，文嘗薦子虛。',48,'全唐诗/poet.song.19000.json','["對未延宣室，文嘗薦子虛。", "書方就綿蕝，奠已致生芻。", "故國悲雲棧，英游負石渠。", "名儒升用晚，厚愧不先予。"]'),
('390ffd8c-f058-4289-85d0-a5cf5e0cbdae','蘇洵員外挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','族本西州望，來爲上國光。',48,'全唐诗/poet.song.19000.json','["族本西州望，來爲上國光。", "文章追典誥，議論極皇王。", "美德驚埋玉，環材痛壞梁。", "時名誰可嗣，父子盡賢良。"]'),
('ec89b9d2-0556-4484-a2e2-faeba0d302a1','太尉呂公挽辭二首  其一','韓琦','宋','宋诗','song-poetry','','[]','韋平傳慶裔，方召起隆名。',48,'全唐诗/poet.song.19000.json','["韋平傳慶裔，方召起隆名。", "塞上天聲遠，帷中廟算精。", "眾期調玉鉉，時忽喪金城。", "朝野悲何甚，邦家重老成。"]'),
('58711ede-9018-4e59-8bf0-9d308aeb2c5f','太尉呂公挽辭二首  其二','韓琦','宋','宋诗','song-poetry','','[]','要劇更中外，幾微照古今。',48,'全唐诗/poet.song.19000.json','["要劇更中外，幾微照古今。", "嘉謀增國重，和氣入人深。", "龍已須雲起，星俄向壘沉。", "得名非得壽，天報此難忱。"]'),
('22be9f37-de53-416a-a0c8-07f1822a7458','早夏  其一','韓琦','宋','宋诗','song-poetry','','[]','脫幘吏休後，憑軒風快餘。',24,'全唐诗/poet.song.19000.json','["脫幘吏休後，憑軒風快餘。", "瀑泉增瀨急，新葉補林疏。"]'),
('c85336c8-a654-4050-8718-416ddb5f2692','早夏  其二','韓琦','宋','宋诗','song-poetry','','[]','暑初天未熱，觀閣進輕涼。',24,'全唐诗/poet.song.19000.json','["暑初天未熱，觀閣進輕涼。", "果熟愁枝重，荷生覺渚香。"]'),
('053ff052-88a9-4107-8c5a-b9ff688811a0','早夏  其三','韓琦','宋','宋诗','song-poetry','','[]','十里溪源注北塘，貯成寬碧澹泱泱。',64,'全唐诗/poet.song.19000.json','["十里溪源注北塘，貯成寬碧澹泱泱。", "新蒲弱荇參差綠，去鶩來鳧斷續行。", "一纜輕波摇鷁舸，滿罾斜日晒魚梁。", "使君思拙無清夢，高柳陰成草自長。"]'),
('09b3d928-7a76-49ed-9e79-87a2aaefd253','次韻翁監再來館中','韓琦','宋','宋诗','song-poetry','','[]','歸老江湖久自盟，睡餘且復對空枰。',64,'全唐诗/poet.song.19000.json','["歸老江湖久自盟，睡餘且復對空枰。", "重來內閣人誰健，慣蹋天街馬不驚。", "已喜劉歆分七略，尚傳韓愈誨諸生。", "太平潤色須色等，應許吾兼吏隱名。"]'),
('c6764156-f205-41fb-aed7-676ba5e4b16a','初冬小園寓目','韓琦','宋','宋诗','song-poetry','','[]','獨樹翹寒色，閑雲淡落暉。',48,'全唐诗/poet.song.19000.json','["獨樹翹寒色，閑雲淡落暉。", "新霜黄橘重，久雨翠梧稀。", "暝雀鳴還啄，高鳥定更飛。", "敝貂猶故在，卒歲免無衣。"]'),
('60b26112-c96b-48f9-b8ec-95d4800a28ac','睢陽五老圖','韓琦','宋','宋诗','song-poetry','','[]','治道剛明老始閑，禮義曾著一朝冠。',64,'全唐诗/poet.song.19000.json','["治道剛明老始閑，禮義曾著一朝冠。", "觀農省歲知民瘼，退寇安邦建夏桓。", "法駕六龍親善御，吟遊五老薄時寒。", "清名邁古今人慕，稷契餘風後學看。"]'),
('78655513-b215-4f88-9395-9a655e608e00','句','韓琦','宋','宋诗','song-poetry','','[]','殷勤洗灌加培植，莫遣狂枝亂出牆。',19,'全唐诗/poet.song.19000.json','["殷勤洗灌加培植，莫遣狂枝亂出牆。", "種竹。"]'),
('ff045497-8c84-429d-9aba-95bdcfd66afb','題邛州文同判官五箴堂','趙抃','宋','宋诗','song-poetry','','[]','李唐韓吏部，矯矯文宗師。',168,'全唐诗/poet.song.19000.json','["李唐韓吏部，矯矯文宗師。", "立言作諸箴，勵世亦自規。", "游箴警惰廢，事業終光輝。", "言箴慎囁囁，張口觸禍機。", "行箴死所守，於義無乖違。", "好惡不悖理，戒或私是非。", "知名懼浮實，動主嫌怨隨。", "五者日踐履，要以君子歸。", "與可知道粹，期至嚴奧窺。", "誦已記所志，礲石鎸其辭。", "俾之揭堂上，使後亦忽隳。", "夫人貴且富，非得强自爲。", "入賢去不肖，在己不在時。", "希韓亦韓徒，中道無已而。"]'),
('27f9c051-c32d-4373-8dc4-baafb212ab7d','次韻樊祖安秀才連理木','趙抃','宋','宋诗','song-poetry','','[]','吾觀樊生者，氣燄凌雲霄。',216,'全唐诗/poet.song.19000.json','["吾觀樊生者，氣燄凌雲霄。", "逢人肆議論，芬馥蘭與椒。", "去年應秋詔，入貢天子朝。", "南宮擯不收，歸迹如蓬飄。", "長途病憔悴，舊里門蕭條。", "今時賤未用，無計逃誚嘲。", "昨日升吾堂，出詩振瓊瑶。", "自云世儒學，其胄來遥遥。", "異哉先冢上，有木名百僚。", "一根初兩幹，幹木仍駢交。", "茂育三十稔，曷爲風霜凋。", "材奇固得地，抱合勢已喬。", "連理古所瑞，於義尤昭昭。", "奚哉私門中，福壽不可邀。", "善祥既失效，嘆惋成長謠。", "吾言異於是，矧世逢虞堯。", "力爲君子儒，進道忽使消。", "積德慶厥後，斯木誠非妖。"]'),
('a0662870-bd2d-40a3-9319-ef572c032ee1','張景通先生書堂','趙抃','宋','宋诗','song-poetry','','[]','志士博古今，名賢口誦聖。',168,'全唐诗/poet.song.19000.json','["志士博古今，名賢口誦聖。", "通則施所有，致君翼時政。", "窮斯處巖穴，信道宗天命。", "富貴貧賤耶，烏與一息競。", "先生抱蜀奇，不爲席珍聘。", "學易到深處，研幾劇精靜。", "書屋數百椽，寒松夾幽徑。", "竹森瀟灑觀，泉逗潺湲聽。", "小人多謗訾，先生自吟詠。", "其徒識所歸，歸雅不歸鄭。", "今時自薄惡，先生自醇正。", "其徒知所入，入賢不入佞。", "憂弊以文捄，敵邪以道勝。", "先生終其爲，彼俗徒詬病。"]'),
('79e2a21d-e0dd-4ed6-9993-c7f2b955e45f','過胡元賓林亭','趙抃','宋','宋诗','song-poetry','','[]','我嘗輕歸轅，一息快心目。',72,'全唐诗/poet.song.19000.json','["我嘗輕歸轅，一息快心目。", "亭橋跨幽澗，廡砌森怪竹。", "榜句多老詞，襟風不韻俗。", "開卷味加永，照泉清可掬。", "先秋固爽塏，大夏失煩燠。", "樂哉於道外，視此樂豈足。"]'),
('c8372001-39e0-4c4c-8ae3-e1d53f6872f7','和范御史十一月三日見月','趙抃','宋','宋诗','song-poetry','','[]','有客冬還吳，孤舟暮停潁。',48,'全唐诗/poet.song.19000.json','["有客冬還吳，孤舟暮停潁。", "山收亂雲彩，天放新蟾影。", "呼童掛簾起，對此清夜景。", "橫琴弄流水，醉耳誰其醒。"]'),
('20067872-e566-49bb-abbe-a38f3e4dbe31','過濠州呈前人','趙抃','宋','宋诗','song-poetry','','[]','朝離石澗寺，暮泊香山夾。',48,'全唐诗/poet.song.19000.json','["朝離石澗寺，暮泊香山夾。", "揚帆復順流，快若兩翼插。", "濠洲舊風物，愚昔此承乏。", "重上莊生臺，如夢覺一霎。"]'),
('9d93c243-e4ee-4443-b310-c8288e26d007','鬰孤臺','趙抃','宋','宋诗','song-poetry','','[]','羣峯鬰然起，惟此山獨孤。',216,'全唐诗/poet.song.19000.json','["羣峯鬰然起，惟此山獨孤。", "筑臺山之巔，鬰孤名以呼。", "窮江足樓閣，危壓斗牛墟。", "直登四臨瞰，眾勢不可踰。", "贛川繚左右，庾嶺前崎嶇。", "望闕峙其後，北向日月都。", "人家雜烟水，原野周城郛。", "烜潤或晴雨，明晦或曉晡。", "春榮夏物茂，秋肅冬林枯。", "氣象日千變，一一如畫圖。", "比予去諫舍，乞此養慵愚。", "事訛得以正，俗瘵得以蘇。", "歲豐盜攘息，獄命寃繫無。", "熙然與民共，所喜朋僚俱。", "中淡有琴詠，外喧有歌歈。", "樽罍有美酒，盤餐有嘉魚。", "優游一臺上，四序不暫辜。", "乃知爲郡樂，況復今唐虞。"]'),
('f13e6cf8-737a-42e8-9ab7-0db8a87ac749','題周敦頤濂溪書堂','趙抃','宋','宋诗','song-poetry','','[]','吾聞上下泉，終與江海會。',156,'全唐诗/poet.song.19000.json','["吾聞上下泉，終與江海會。", "高哉廬阜間，出處濂溪派。", "清深遠城市，潔浄去塵埃。", "毫髮難遁形，鬼神縮妖怪。", "對臨開軒窗，勝絕甚圖繪。", "固無風波虞，但覺耳目快。", "琴樽日左右，一堂不爲泰。", "經史日枕藉，一室不爲隘。", "有蓴足以羹，有魚足以鱠。", "飲啜其樂真，靜正於俗邁。", "主人心淵然，澄徹一內外。", "本源孕清德，游詠吐嘉話。", "何當結良朋，講習取諸兌。"]'),
('ba73fe56-5a63-4668-911a-1993461ccf00','寄酬蔡州王陶正言','趙抃','宋','宋诗','song-poetry','','[]','自顧愚無堪，老大何所用。',96,'全唐诗/poet.song.19000.json','["自顧愚無堪，老大何所用。", "得郡江湖來，一意雲泉縱。", "驚此西南身，連夕東北夢。", "乃知故人念，許與明月共。", "荆書一紙賢，季諾千金重。", "寄我瓊瑶篇，使得長諷誦。", "寒松有唳鶴，高梧有鳴鳳。", "何日謝知音，爲鼓商絃弄。"]'),
('fb3b6aa2-1664-4812-8103-e31ce42e5f92','次韻江鉞都官凉軒','趙抃','宋','宋诗','song-poetry','','[]','執己剛玉性，誰得同趣向。',168,'全唐诗/poet.song.19000.json','["執己剛玉性，誰得同趣向。", "涕唾無所藉，歸居宅深曠。", "左右山林間，巑岏立屏障。", "坐期清風來，未許酷日晃。", "高棚立西軒，密葉覆其上。", "益爲晚宇廕，詎隔霞空望。", "聖書樂名教，俗事絕塵鞅。", "恬然寵辱驚，足矣庭闈養。", "下榻遲佳朋，盈樽倒新釀。", "藥劑矜有靈，神明助無恙。", "賢豪重出處，詞句大奔放。", "謂愚可與道，緘遺俾酬倡。", "忽如窮窘人，護發金玉藏。", "收儲篋笥光，孰顧貪惏謗。"]'),
('95763c00-aa5f-46a2-9fae-59db5131be98','題三輔院','趙抃','宋','宋诗','song-poetry','','[]','武陽夏侯氏，參立鼎峙足。',48,'全唐诗/poet.song.19000.json','["武陽夏侯氏，參立鼎峙足。", "秉鈞相三朝，仗鉞帥全蜀。", "茅土當時榮，照煥人耳目。", "事業申意氣，遺像儼壁屋。"]'),
('a7ea670c-9926-420b-b6e0-81e527421ea7','游南山宿盤龍寺','趙抃','宋','宋诗','song-poetry','','[]','盤龍得山名，寺占山之下。',84,'全唐诗/poet.song.19000.json','["盤龍得山名，寺占山之下。", "老師草庵居，後嗣廣精舍。", "禪流日益盛，寂照騰詩價。", "我來誨其徒，競以相誇詫。", "少林的的意，一語獨無暇。", "默然坐明窗，孤蟾徹清夜。", "遲曉登終南，行行與誰話。"]'),
('523df8f3-345f-492b-aa9c-af6bae12fcfe','留題劍門東園','趙抃','宋','宋诗','song-poetry','','[]','劍州古要害，重門搤開闔。',144,'全唐诗/poet.song.19000.json','["劍州古要害，重門搤開闔。", "隄防兩川地，喉吭此呀呷。", "在昔禦狂寇，如朽施巨拉。", "時平付良守，一與公論合。", "政成治東圃，於焉解賓榻。", "予方錦官去，邀我置壺榼。", "縱步車馬休，舉目蒼翠匝。", "攄懷談笑喧，傾車潺湲雜。", "不春亦芳菲，匪風自蕭颯。", "主賓飲興豪，量海川酒納。", "貳車臺中舊，題詩謂予盍。", "默默極佳處，茲俗何以答。"]'),
('c55ee0f8-7f77-4fd3-af33-1bd92e88f186','贈陽安徐邁表兄屯田','趙抃','宋','宋诗','song-poetry','','[]','少時所學苦，食蘗日自强。',144,'全唐诗/poet.song.19000.json','["少時所學苦，食蘗日自强。", "壯歲從宦清，飲冰中剛腸。", "陽安百里地，邈在天一方。", "惠政不鞭朴，斯民樂耕桑。", "念予昨守贛，與兄會家鄉。", "兄今歲已滿，余遽提蜀疆。", "一朝此邂逅，五載忘參商。", "且勿語離索，易老驚鬢霜。", "且勿較通塞，放懷把酒觴。", "上方聖政新，求賢坐明堂。", "兄道足施設，兄志彌頡頏。", "喜予外祖門，從此生輝光。"]'),
('6f255c1c-94c8-47b0-b7cc-a1dc0c411815','雙竹','趙抃','宋','宋诗','song-poetry','','[]','余家有故園，園中可圖錄。',168,'全唐诗/poet.song.19000.json','["余家有故園，園中可圖錄。", "天然一派根，一根生兩竹。", "一長復一短，比之如手足。", "長者似乃兄，短者弟相逐。", "我見人弟兄，少有相和睦。", "竹分長幼情，人豈無尊宿。", "將竹比人心，人殆類禽畜。", "常記五六歲，不見還呼哭。", "及至長大時，妻孥相親族。", "咫尺不相見，相踈何太速。", "不顧父母生，同胞又同腹。", "旦夕慕歌歡，幾能思骨肉。", "枉具人鬚眉，而食天五穀。", "靜思若斯人，爭及園中竹。"]'),
('2a806beb-3e08-48d6-a394-55499818fc20','次韻孫直言九日登龍門山','趙抃','宋','宋诗','song-poetry','','[]','皇祐二年秋九月，九日龍門遇佳節。',224,'全唐诗/poet.song.19000.json','["皇祐二年秋九月，九日龍門遇佳節。", "新都大夫孫隱之，報政優游共民悅。", "升山高會賓主俱，滿頭黄菊泛茱萸。", "遥開醉眼極千里，身高氣爽胸懷舒。", "逢時感物以次發，詩成落落傾璣珠。", "初言府政好太守，化行歲稔民力蘇。", "喜聲協氣遨以狂，稚子負老老者扶。", "又言登臨風景異，澄川秀野如披圖。", "殊方真賞到奇處，未來空只誇江湖。", "得之獨善不在己，遠遣遺我開煩紆。", "嗟我江原亦民長，周遭百里平如掌。", "簿書役役甚囚拘，聞有岷峨無計上。", "及聞治邑茲山奇，脚力不到神魄馳。", "誰知我亦好山者，篋中時復觀君詩。"]'),
('b6aebe5c-9577-4c26-86f4-9f623cf83ac0','送周穎之京師','趙抃','宋','宋诗','song-poetry','','[]','吾鄉伯堅真丈夫，氣剛色强言詞疎。',192,'全唐诗/poet.song.19000.json','["吾鄉伯堅真丈夫，氣剛色强言詞疎。", "胸中一物不使有，日儲月斂唯詩書。", "布裘落魄韋带緩，權門不肯低眉趨。", "朋游累百誰爾汝，人皆不與爭揶揄。", "掩關啜菽苦意氣，糞壤玉璧泥沙珠。", "宣慈中山我孤處，昨日走介貽我書。", "書云詔下籲俊乂，父兄命頴之京都。", "古人求養志擇祿，今而豈得逃馳驅。", "肩書手劍出門去，嚌咨肯復兒女如。", "我聞此語涕交下，人皆欲養繄我無。", "羨子之爲與道合，勸子亟往無踟躕。", "明年得志拜堂上，豈非人子榮親歟。"]'),
('3677ef73-1e73-411d-8419-4081dfcff331','贈沖妙李先生','趙抃','宋','宋诗','song-poetry','','[]','老君作經五千言，勤行大笑亡與存。',64,'全唐诗/poet.song.19000.json','["老君作經五千言，勤行大笑亡與存。", "先生有詩七百首，詔書三度來天門。", "年登八十齒髮壯，骨輕步武如雲奔。", "一琴一樽一爐藥，人間日月從朝昏。"]'),
('46f26478-9ea8-426c-b368-29b144f187c8','酬張唐英','趙抃','宋','宋诗','song-poetry','','[]','方予讞獄唐安歸，火雲熾日交炎威。',96,'全唐诗/poet.song.19000.json','["方予讞獄唐安歸，火雲熾日交炎威。", "爐烘炭赫幾千里，百鳥不能凌空飛。", "塵埃簿牒几前滿，膚汗如雨淋漓揮。", "俗官冗狀紛未省，胸腹堙鬰氣力微。", "蟾宮有客桂新折，忽遣詩筒慰慵拙。", "詞佳句好吟未窮，一坐涼飚奪炎熱。"]'),
('c11d7d2d-107b-4c08-84c3-b7cdd026b156','和范御史見贈','趙抃','宋','宋诗','song-poetry','','[]','我趨仕途三十春，矹矹求友難其人。',384,'全唐诗/poet.song.19000.json','["我趨仕途三十春，矹矹求友難其人。", "相逢探取百一二，變幾不泯磨功名。", "或言同途行異徑，或始卓犖終因循。", "或臨利害失趨向，或走勢利遺賤貧。", "或面盱睢背忌刻，或口仁義心頑嚚。", "或名公卿節屠隸，或實盜跖文孟荀。", "澄川倏忽起波浪，平地咫尺生嶙峋。", "薰蕕蘭芷逐蕭艾，玷纇瓊玖俄砆珉。", "茲事自古慎所與，傾蓋如舊白頭新。", "仲尼評友戒損益，故嘗佩服書諸紳。", "履中蹈道敢不勉，至愚所恃生逢辰。", "朝廷基扃要扶助，天子堯舜聖且仁。", "焦勞汲汲納讜議，風憲思得御史真。", "翰林鉅公不識面，誤以愚者名上陳。", "至和改元秋九月，詔書曉落長淮濱。", "孤貧自省預臺選，無意顧藉家與身。", "直期賢用不肖斥，忠邪路判如越秦。", "頻章累疏辨得失，上前往往嬰龍鱗。", "時吾貫之日聯句，玉樹欲使蒹葭親。", "爲憐出處共本末，未始氣味殊甘辛。", "忠言鯁議不我間，開誠待我逾天倫。", "螭頭連登拜白簡，豸角對拱朝紫宸。", "雕盤隼擊雪霜凜，豺狼奔北窮狐㕙。", "九重上報不惜死，豈復讒口防狺狺。"]'),
('1900848c-eb7e-46ec-89a0-64d7d94708db','順風呈前人','趙抃','宋','宋诗','song-poetry','','[]','濠州抵泗里數百，長淮波平曉如席。',192,'全唐诗/poet.song.19000.json','["濠州抵泗里數百，長淮波平曉如席。", "鳴鼙解纜楊柳堤，畫船中有東吳客。", "君恩得請許歸去，聊治里閭去咫尺。", "歲窮天遠心欲飛，念之汲汲事行役。", "豁如天意適我願，號令西北起風伯。", "初時淅淅以鼓動，布帆尚留十幅窄。", "孤檣得勢安以平，中流激箭巨浪劈。", "篙橫櫓閣力不用，疾若摯隼增羽翮。", "瞥然兩岸瞬霎過，木葉馳黄山走碧。", "拏舟月餘今日快，一樽自歌兩手拍。", "樽中酒空不自歌，順風好景如之何。", "毗陵太守同此樂，爲言無惜新詩多。"]'),
('4a4ee347-a864-4b9e-8223-e43580b718fc','入贛聞曉角有作','趙抃','宋','宋诗','song-poetry','','[]','江南歷盡佳山水，獨贛潺潺三百里。',96,'全唐诗/poet.song.19000.json','["江南歷盡佳山水，獨贛潺潺三百里。", "移舟夜泊惶恐灘，畫角烏烏曉風起。", "棲鷗宿鷺四散飛，夢魂驚入漁樵耳。", "三通迤邐東方明，又是篙工造行矣。", "橫波利石千萬層，板繩縛纍如山登。", "夷途終致險且升，自顧忠信平生憑。"]'),
('00a02239-11da-4869-bd11-9422377a0fad','將至太和寄蔡仲偃太博','趙抃','宋','宋诗','song-poetry','','[]','我憶去年仲冬月，夜醉離尊曉船發。',128,'全唐诗/poet.song.19000.json','["我憶去年仲冬月，夜醉離尊曉船發。", "鼕鼕畫鼓上窮江，章貢川源接南粵。", "虔州之民十萬家，下車公議亂如麻。", "去除煩苛養疲瘵，令嚴訟簡俗亦嘉。", "農事屢登稻粱積，獄犴空虛寇衰息。", "遠陬安堵幸實天，闕然自愧予何力。", "邇來被旨還神京，乘秋擊棹烟波行。", "夷猶入境奚所喜，故人樂土絃歌聲。"]'),
('bb040c21-e22e-40cc-8c87-22ddd07c5316','答閬州通判吳師孟職方','趙抃','宋','宋诗','song-poetry','','[]','閬州之景天下奇，嘗見老杜城南詩。',160,'全唐诗/poet.song.19000.json','["閬州之景天下奇，嘗見老杜城南詩。", "嘉陵江湍清且潔，錦屏山疊雄復巇。", "醉翁生鐘大峩秀，收拾氣象爲文詞。", "自從屏星副郡治，訟平事簡奚設施。", "幽潛穹大極所有，搜羅詠賦一不遺。", "州僚俊集嘉酬和，海濤洶湧洪波隨。", "顧余不鄙可語者，聯編累軸緘以貽。", "寸珠盈掬破冥晦，尺璧入手無瑕疵。", "窮搜囊篋暴侈富，開窺秘嗇心驚嬉。", "竟微一毫報佳況，臨紙復輟慚久之。"]'),
('f268ac35-fed3-4b5a-b231-be0ea39483fc','訪何若谷','趙抃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君愛仙源厭塵俗，高樓對起欄干曲。',64,'全唐诗/poet.song.19000.json','["君愛仙源厭塵俗，高樓對起欄干曲。", "朝霞灼灼浮晴暉，二十四峯照羣玉。", "樓下長江烟水綠，樓前有瀨歸艎促。", "主人借問何時還，回首崢嶸看不足。"]'),
('b320b82a-3579-4075-aa63-d4bc258327c9','次韻僧重喜聞琴歌','趙抃','宋','宋诗','song-poetry','','[]','我昔所寶真雷琴，絃絲軫玉徽黄金。',96,'全唐诗/poet.song.19000.json','["我昔所寶真雷琴，絃絲軫玉徽黄金。", "晝橫膝上夕抱寢，平生與我爲知音。", "一朝如扇逢秋捨，而今只有無絃者。", "無情曲調無情聞，浩浩之中都奏雅。", "我默彈兮師寂聽，清風之前明月下。", "子期有耳何處聽，自笑家風太瀟灑。"]'),
('8c01dc54-c4c0-44bb-8e90-1131b2e0746b','遊金華洞','趙抃','宋','宋诗','song-poetry','','[]','子房身乞辭大用，赤松伴遊世所重。',64,'全唐诗/poet.song.19000.json','["子房身乞辭大用，赤松伴遊世所重。", "高遠誰親弋外鴻，尊榮肯羨池中鳳。", "至今仙迹存金華，我來一日登三洞。", "回顧却笑長安人，辛苦登天憑鶴控。"]'),
('589e686d-4a23-4e80-b4ad-d2557646ecd2','題衢州唐臺山','趙抃','宋','宋诗','song-poetry','','[]','唐臺壓郡東北陲，勢旋力轉奔而馳。',192,'全唐诗/poet.song.19000.json','["唐臺壓郡東北陲，勢旋力轉奔而馳。", "偉哉造物誰其尸，一山中起高峩巍。", "羣峯環輔拱以立，背面肘腋相倚毗。", "怪石差差少媚色，長松落落無邪姿。", "巖隈有路數百仞，直登不悔形神疲。", "中間軒豁浮圖舍，棟宇綵錯金璧輝。", "寒泉一畝清可鑑，優游鱣鮪揚鱗鬐。", "猿閒鳥暇兩呼笑，老僧矍鑠趨且嬉。", "天風烈烈骨毛竦，更云六月無炎曦。", "攀緣絕頂下四顧，溪山百里如掌窺。", "我思宜有隱君子，放心不與時安危。", "巢由之行已高世，白雲卧此逃堯媯。"]'),
('0ccafddd-7a69-499c-980b-f7217d2ffc22','寄酬梓路運使趙諴度支','趙抃','宋','宋诗','song-poetry','','[]','喜君出使東川行，臘寒擁雪辭神京。',176,'全唐诗/poet.song.19000.json','["喜君出使東川行，臘寒擁雪辭神京。", "平生忠力晚愈固，萬山叱馭險亦平。", "青泥嶺惡白晝上，更逢落雪百尺盈。", "盤高折下寸寸進，馬蹄硉矹人膽驚。", "君懷初不阻艱險，却念疆土連錦城。", "謂予嘗有一日雅，豪吟縱筆高泉傾。", "三章落落字字好，開緘與雪爭瑶瓊。", "置郵亟來發以誦，齒牙冷切胸懷清。", "豈徒感服爲文字，所得風義推誠明。", "今君東轅我西守，去此止有數日程。", "兩川春物正爛漫，何時文酒親講評。"]'),
('bf712c15-9dcd-4205-8b37-2dc5c430ac78','謝曾魯公惠維摩居士真','趙抃','宋','宋诗','song-poetry','','[]','問答眾口徒紛紛，爭入菩薩不二門。',64,'全唐诗/poet.song.19000.json','["問答眾口徒紛紛，爭入菩薩不二門。", "金毛獅子不敢吼，不嘿不見維摩尊。", "維摩之尊無異相，潞州傳出毗耶像。", "相公村與知非子，掛向壁間看榜樣。"]'),
('d549edf7-7fb8-4830-af08-da8dd66889b3','暖風','趙抃','宋','宋诗','song-poetry','','[]','薄袂欹雲散，輕盤舞袖低。',48,'全唐诗/poet.song.19000.json','["薄袂欹雲散，輕盤舞袖低。", "簾疎蕩樓閣，塵暗逐輪蹄。", "絮亂垂楊道，香流種藥畦。", "春窗惱春思，一枕杜鵑啼。"]'),
('cfd4b75f-fcba-4cfd-8c69-cbb00b5a1f7e','芳草','趙抃','宋','宋诗','song-poetry','','[]','翠密馴文雉，叢深隱畫輪。',48,'全唐诗/poet.song.19000.json','["翠密馴文雉，叢深隱畫輪。", "離披金谷曉，寂寞茂陵春。", "古渡班荆客，長堤走馬人。", "芊芊似袍綠，一雨一番新。"]'),
('acba4ff5-3322-459c-94cb-062812748451','寒食郊園即事','趙抃','宋','宋诗','song-poetry','','[]','城郭青烟散，郊園彩日長。',48,'全唐诗/poet.song.19000.json','["城郭青烟散，郊園彩日長。", "鬭雞紅錦翅，游騎紫絲韁。", "有蝶俱含粉，無人不惜芳。", "儘拚花下飲，歸去醉成鄉。"]'),
('9fb4c57b-6852-46ad-a67d-ec7b7fa77d81','杜鵑','趙抃','宋','宋诗','song-poetry','','[]','響亂書窗外，人驚夢枕中。',48,'全唐诗/poet.song.19000.json','["響亂書窗外，人驚夢枕中。", "江城啼曉月，澤國愬春風。", "柳道盤飱綠，桃園躞蹀紅。", "年年來此地，留恨任西東。"]'),
('f9fc478b-44f6-4c88-9645-8f2043a31373','溪山晚目','趙抃','宋','宋诗','song-poetry','','[]','幽花連徑發，驚鳥避人啼。',48,'全唐诗/poet.song.19000.json','["幽花連徑發，驚鳥避人啼。", "雨過晴虹上，風清走馬嘶。", "灘平魚艇穩，村小酒旗低。", "誰及山翁樂，號呶醉似泥。"]'),
('8727cd17-9795-438e-a28a-dce0c58de201','村居','趙抃','宋','宋诗','song-poetry','','[]','午寢忘譏刺，閒居杜送迎。',48,'全唐诗/poet.song.19000.json','["午寢忘譏刺，閒居杜送迎。", "雨泥雙燕下，烟垅一犁耕。", "座入山光迥，門連野色平。", "吟餘仍兀坐，誰與戰楸枰。"]'),
('9a32025f-779a-4489-879c-0ead79ea9b8d','曲館','趙抃','宋','宋诗','song-poetry','','[]','日華烘玉甃，烟縷亙雕甍。',48,'全唐诗/poet.song.19000.json','["日華烘玉甃，烟縷亙雕甍。", "棗熟房櫳暝，花妍院落明。", "醉輕春有味，夢短晝無情。", "欲識愔愔意，回文織已成。"]'),
('34e5ddbb-0d04-4967-a1cf-bc953ac6f5ca','題九仙寺','趙抃','宋','宋诗','song-poetry','','[]','墜果春三徑，蒸雲晚一軒。',48,'全唐诗/poet.song.19000.json','["墜果春三徑，蒸雲晚一軒。", "廊腰回戰蟻，山腹合啼猿。", "泉淡禽窺影，苔深屐印痕。", "自慚名利者，聊免世紛喧。"]'),
('be013fe1-5c7a-4e14-97fa-263e5f4e8d03','贈吉安院主','趙抃','宋','宋诗','song-poetry','','[]','學佛之徒眾，難能是向文。',48,'全唐诗/poet.song.19000.json','["學佛之徒眾，難能是向文。", "唯師獨奇尚，於我故慇懃。", "詩遇知音誦，琴防俗子聞。", "虛亭對明月，長許到宵分。"]'),
('0176474d-69df-4e7d-b386-efbf98bebef5','先與祠嶽續以權市征弗克往呈通判沈侯','趙抃','宋','宋诗','song-poetry','','[]','裝懷成倥傯，從事愧風流。',48,'全唐诗/poet.song.19000.json','["裝懷成倥傯，從事愧風流。", "且榷征門利，甘同倚市羞。", "摇心隨使旆，極目望仙舟。", "青玉靈壇遠，終朝接上遊。"]'),
('d402f98c-228b-43c9-a6e8-b5cf8f5a5002','沈侯見和再次前韻','趙抃','宋','宋诗','song-poetry','','[]','舉目皆仙迹，齋心遠俗流。',48,'全唐诗/poet.song.19000.json','["舉目皆仙迹，齋心遠俗流。", "江山入詩助，蘋藻爲神羞。", "去矣登危嶠，歸仍泛穩舟。", "何勞嘆蕭索，無惜話真遊。"]'),
('adceb477-10d3-48da-a092-23085926ae83','和沈侯敘別往祠嶽','趙抃','宋','宋诗','song-poetry','','[]','席上歌驪闋，風前嘶馬驕。',48,'全唐诗/poet.song.19000.json','["席上歌驪闋，風前嘶馬驕。", "怱怱傾桂醑，一一上蘭橈。", "破浪欣無恙，依蓮愧不憀。", "踟躕重回首，雲翼自扶摇。"]'),
('a4afefab-5e1a-4d16-b676-f763c8c97782','言懷寄三兄','趙抃','宋','宋诗','song-poetry','','[]','沿牒非吾土，逢春憶故園。',48,'全唐诗/poet.song.19000.json','["沿牒非吾土，逢春憶故園。", "于今佐犀帳，經歲別鴒原。", "訟簡仍開卷，時平且屬鞬。", "江鄉去千里，凝睇一銷魂。"]'),
('81997455-f3eb-4c90-aca5-190f11343474','送石秘校','趙抃','宋','宋诗','song-poetry','','[]','擊汰泛輕艎，離懷莫共傷。',48,'全唐诗/poet.song.19000.json','["擊汰泛輕艎，離懷莫共傷。", "去投方朔牘，歸曳老萊裳。", "在昔名尤重，于今道已光。", "此行有新集，一一錦裁囊。"]'),
('45761f1e-422e-4b9c-9f21-92ea9a3659dc','和何節判觀水','趙抃','宋','宋诗','song-poetry','','[]','澄江抵練長，極目路蒼茫。',48,'全唐诗/poet.song.19000.json','["澄江抵練長，極目路蒼茫。", "烟芷差差綠，風荷柄柄香。", "西流終古恨，南浦鎮時忙。", "擬待傳辭意，離人在楚鄉。"]'),
('6ba8bf36-79c1-4c56-adcb-06ceec6067fe','和蔡黄裳節推外邑見貽二首  其一','趙抃','宋','宋诗','song-poetry','','[]','只應登雪嶠，疑是有丹梯。',48,'全唐诗/poet.song.19000.json','["只應登雪嶠，疑是有丹梯。", "雨後千山秀，風前一笛嘶。", "平時空執弭，樂土不鳴鼙。", "目斷依蓮客，君東我自西。"]'),
('110960aa-80d5-4090-a31d-078ce0ceb8d8','和蔡黄裳節推外邑見貽二首  其二','趙抃','宋','宋诗','song-poetry','','[]','冉冉成輕別，遲遲想倦遊。',48,'全唐诗/poet.song.19000.json','["冉冉成輕別，遲遲想倦遊。", "去應寬蕙带，行亦佩吳鈎。", "訪隱逢三徑，尋真認十洲。", "有人頻倚望，何日人刀頭。"]'),
('efc01152-8adb-4af7-899a-67e8181a6a6a','和三兄見寄','趙抃','宋','宋诗','song-poetry','','[]','棣萼遥南國，蘇萱種北堂。',48,'全唐诗/poet.song.19000.json','["棣萼遥南國，蘇萱種北堂。", "雪音何處斷，風翼自回翔。", "送目吳天闊，傳辭楚水長。", "通宵識歸路，惟夢到吾鄉。"]'),
('f8d95bc7-1fa7-4dcd-b368-3cf4e3d29345','江上白樂天祠','趙抃','宋','宋诗','song-poetry','','[]','我愛白司馬，有言來謁祠。',48,'全唐诗/poet.song.19000.json','["我愛白司馬，有言來謁祠。", "才名千古照，忠義一生奇。", "諫切寧思祿，讒行却罪詩。", "如何江上客，惟道琵琶詞。"]'),
('b81fdc29-570a-4590-a3f7-90686ff91e37','有虎','趙抃','宋','宋诗','song-poetry','','[]','有虎競磨牙，逢人事攫拏。',48,'全唐诗/poet.song.19000.json','["有虎競磨牙，逢人事攫拏。", "夜聲聞別塢，曉跡印平沙。", "迫路奔驚犬，藏林噪亂鴉。", "過舟無可奈，極目是蒹葭。"]'),
('a9b701da-ec22-4960-901a-42d071096297','罾魚','趙抃','宋','宋诗','song-poetry','','[]','生涯罾一架，深浦勢并兼。',48,'全唐诗/poet.song.19000.json','["生涯罾一架，深浦勢并兼。", "張目因知密，游鱗不漏纖。", "急收防力跳，輕語怕驚潛。", "持去全家樂，盈盤鱠縷甜。"]'),
('38baedad-8a01-429c-a771-74f554df8f16','歲暮感懷','趙抃','宋','宋诗','song-poetry','','[]','早是窮冬逼，那堪客思兼。',48,'全唐诗/poet.song.19000.json','["早是窮冬逼，那堪客思兼。", "事嗟流水遠，年愧入春添。", "與雪幸同操，驚霜忽到髯。", "晚舟前浦泊，何處有青帘。"]'),
('8ef053a9-795a-4d2f-a8a8-e7b7529e2e7c','寄任大中秀才','趙抃','宋','宋诗','song-poetry','','[]','今我歲將暮，過橈鸚鵡洲。',48,'全唐诗/poet.song.19000.json','["今我歲將暮，過橈鸚鵡洲。", "憶君人少與，買舍瀫江頭。", "客路書多絕，吾鄉夢半遊。", "明年誰到蜀，能寄好書不。"]'),
('32847267-2a48-4722-859c-ff71159bcf04','向晚','趙抃','宋','宋诗','song-poetry','','[]','向晚立汀沙，人閒目更賒。',48,'全唐诗/poet.song.19000.json','["向晚立汀沙，人閒目更賒。", "林踈僧屋露，風轉客帆斜。", "幽白孤飛鳥，橫紅數抹霞。", "漁翁偶相問，憐我宦天涯。"]'),
('ec8121ad-9e7f-49f3-9f8f-a327d3dad869','又和三兄見寄','趙抃','宋','宋诗','song-poetry','','[]','鄭重流芳信，慇懃慰遠官。',48,'全唐诗/poet.song.19000.json','["鄭重流芳信，慇懃慰遠官。", "已欣懷袖滿，仍覺齒牙寒。", "置速傳辭易，人遐結會難。", "側身東望久，離緒轉盤桓。"]'),
('434c0ae2-0cdd-4425-964c-c345821a9380','送鄒舜咨回鄉','趙抃','宋','宋诗','song-poetry','','[]','經歲別親闈，于今詠式微。',48,'全唐诗/poet.song.19000.json','["經歲別親闈，于今詠式微。", "捐繻成後約，拭袂重言歸。", "脫葉迷官道，酸風中客衣。", "新文滿珍笥，去去有餘輝。"]'),
('29ce857e-d4e1-4b44-80fc-29f839b6c71a','送余林二生赴舉','趙抃','宋','宋诗','song-poetry','','[]','並遊攀逸軌，兩喜擅佳聲。',48,'全唐诗/poet.song.19000.json','["並遊攀逸軌，兩喜擅佳聲。", "鵠志一千里，鵬圖九萬程。", "青雲今共上，白水舊齊盟。", "聖主君堪羨，連鑣去策名。"]'),
('f0982e42-cbb1-4d26-8d79-48cfa1859e25','送李運使學士赴闕十詠  其一','趙抃','宋','宋诗','song-poetry','','[]','懿識本天資，長才繼者誰。',48,'全唐诗/poet.song.19000.json','["懿識本天資，長才繼者誰。", "漕舟逾萬計，實廩近千斯。", "入境喧輿頌，還鄉結主知。", "上方思柄用，何惜告謀惟。"]'),
('9af206dd-2552-4086-9a49-6e594b5982cc','送李運使學士赴闕十詠  其二','趙抃','宋','宋诗','song-poetry','','[]','下士無虛坐，摛文有話言。',48,'全唐诗/poet.song.19000.json','["下士無虛坐，摛文有話言。", "鎮浮賢者業，襲慶相君門。", "在郡行車樂，瞻天被詔溫。", "只應朝請日，三接渙宸恩。"]'),
('b123367f-b255-47cb-a86d-62c3e4cca34f','送李運使學士赴闕十詠  其三','趙抃','宋','宋诗','song-poetry','','[]','睿簡從朝議，僉俞協帝疇。',48,'全唐诗/poet.song.19000.json','["睿簡從朝議，僉俞協帝疇。", "受釐延賈傅，給饋美酇侯。", "會府居功最，朝廷錫命優。", "思皇今在旦，歸去贊宸猷。"]'),
('d359e6b4-6e10-433e-86fe-72ed88340d07','送李運使學士赴闕十詠  其四','趙抃','宋','宋诗','song-poetry','','[]','壓境號民蘇，連甍競樂輸。',48,'全唐诗/poet.song.19000.json','["壓境號民蘇，連甍競樂輸。", "萬桑豐歲計，一節赴朝趨。", "安穩舟無恙，雍容騎甚都。", "贈言聊紀盛，爲頌愧非夫。"]'),
('3b31873b-1df2-433f-b8a4-b09242fb6f00','送李運使學士赴闕十詠  其五','趙抃','宋','宋诗','song-poetry','','[]','傳姻聯世美，振玉擅家聲。',48,'全唐诗/poet.song.19000.json','["傳姻聯世美，振玉擅家聲。", "南楚聊均逸，東臯亦勸耕。", "察廉無遁物，刺舉有能名。", "宣室今前席，寧庸羨賈生。"]'),
('26e4c623-df1f-48f0-90c5-5d2cb7facf74','送李運使學士赴闕十詠  其六','趙抃','宋','宋诗','song-poetry','','[]','早擅雲間譽，嘗登月裏名。',48,'全唐诗/poet.song.19000.json','["早擅雲間譽，嘗登月裏名。", "十輪門襲慶，萬石世傳榮。", "待繼開賓閤，聊爲擁使旌。", "績成今第一，歸作漢公卿。"]'),
('da602e14-5d74-4e1f-8c5d-0335655f49af','送李運使學士赴闕十詠  其七','趙抃','宋','宋诗','song-poetry','','[]','荆衡此駕軺，封郡去相遼。',48,'全唐诗/poet.song.19000.json','["荆衡此駕軺，封郡去相遼。", "國廩矜流衍，農疇喜富饒。", "幾時無協氣，何處不讙謠。", "漢室通糧道，論功最後蕭。"]'),
('04ff715c-3fee-4294-81e7-3227e24224db','送李運使學士赴闕十詠  其八','趙抃','宋','宋诗','song-poetry','','[]','南榮來漢詔，北闕近堯天。',48,'全唐诗/poet.song.19000.json','["南榮來漢詔，北闕近堯天。", "懿績隆三歲，豐儲備九年。", "威嚴多摘伏，薦籍幾登賢。", "去去民思甚，銷魂盡黯然。"]'),
('3bafbeac-dcba-4790-9531-b9a0f78de7b2','送李運使學士赴闕十詠  其九','趙抃','宋','宋诗','song-poetry','','[]','歌闋散雕筵，膺舟是謫仙。',48,'全唐诗/poet.song.19000.json','["歌闋散雕筵，膺舟是謫仙。", "秦亭臨斷岸，楚水浸遥天。", "魏闕瞻湖上，長安指日邊。", "綵旍隨目遠，一向立風前。"]'),
('8eee5160-e45f-40f6-9660-a03073687a94','送李運使學士赴闕十詠  其一○','趙抃','宋','宋诗','song-poetry','','[]','供帳楚江濱，瞻言淚滿巾。',48,'全唐诗/poet.song.19000.json','["供帳楚江濱，瞻言淚滿巾。", "如何從事客，曾作受恩人。", "再顧溝中物，尤慚席上珍。", "異時調鼎鼐，應許與陶鈞。"]'),
('2d03f172-490c-4d1b-a668-b02f187e0dc6','和戴天使重陽前一夕宿長沙驛二首  其一','趙抃','宋','宋诗','song-poetry','','[]','詰旦逢佳節，今宵寓遠鄉。',48,'全唐诗/poet.song.19000.json','["詰旦逢佳節，今宵寓遠鄉。", "且欣賓榻解，休歎客亭長。", "黄葉臨風亂，紅萸浥露香。", "酒徒何處所，空自憶高陽。"]'),
('3d41fc7c-25b8-4c21-845f-a6fcfe60ef7c','和戴天使重陽前一夕宿長沙驛二首  其二','趙抃','宋','宋诗','song-poetry','','[]','楚館夜衾涼，離人念故鄉。',48,'全唐诗/poet.song.19000.json','["楚館夜衾涼，離人念故鄉。", "遠吟只覺苦，歸夢不成長。", "壁有寒蛩怨，鄰聞綠蟻香。", "登高在何處，明日宴山陽。"]'),
('9e38252c-0dbc-498a-8a94-2e0e0c96d4ae','聞楊畋病愈','趙抃','宋','宋诗','song-poetry','','[]','湖南楊叔武，消息有人傳。',48,'全唐诗/poet.song.19000.json','["湖南楊叔武，消息有人傳。", "連歲征蠻徼，經秋卧瘴烟。", "爲時天未喪，勿藥病還痊。", "雲水溶溶去，憑詩寄此篇。"]'),
('569f28e5-4f7e-4ccf-939a-fc9d547bbf38','入蜀舟中逢春','趙抃','宋','宋诗','song-poetry','','[]','春到依覉旅，懷開似發緘。',48,'全唐诗/poet.song.19000.json','["春到依覉旅，懷開似發緘。", "野禽鳴勝管，春草綠於衫。", "水暖風微碎，山明日半銜。", "巴西寒極地，冰雪尚千巖。"]'),
('1bd6ca40-51ff-41d9-ba02-d3642319fb1c','入蜀江上對月','趙抃','宋','宋诗','song-poetry','','[]','照不私毫髮，波光上下浮。',48,'全唐诗/poet.song.19000.json','["照不私毫髮，波光上下浮。", "明餘到琴淡，清極入詩幽。", "忽認江湖晝，渾疑天地秋。", "閒雲勿輕蔽，有客坐孤舟。"]'),
('264d8c6e-95d1-443d-867f-6a29c8b2f10a','春日陪宴會春園亭','趙抃','宋','宋诗','song-poetry','','[]','爲怕三春過，因謀數刻狂。',48,'全唐诗/poet.song.19000.json','["爲怕三春過，因謀數刻狂。", "醉輕欣射中，歡甚惜歌長。", "驕馬花間繫，啼鶯柳下藏。", "前旌歸去晚，十里淡風光。"]'),
('43fc9a43-4f84-415d-be1f-fc29e790c694','月夜聽僧化宜彈琴','趙抃','宋','宋诗','song-poetry','','[]','蜀國有良工，孫枝斵古桐。',48,'全唐诗/poet.song.19000.json','["蜀國有良工，孫枝斵古桐。", "逢師寫流水，爲我益清風。", "淡恐時心厭，幽蘄世耳聰。", "坐來明月滿，無語訟庭空。"]'),
('d4d1fe3b-1fc2-4f0a-95d9-64bd54781db4','送蜀守賈昌朝水部赴闕','趙抃','宋','宋诗','song-poetry','','[]','召節下英藩，歸轅望帝閽。',48,'全唐诗/poet.song.19000.json','["召節下英藩，歸轅望帝閽。", "中和刺史政，教友相君門。", "去聽塗歌美，留瞻壁像尊。", "欲知春色好，元是百城恩。"]'),
('cc3cc827-43e7-414b-b5a4-f687eb8f1a22','送曾交屯田赴闕','趙抃','宋','宋诗','song-poetry','','[]','治多祥氣感，名可信書褒。',48,'全唐诗/poet.song.19000.json','["治多祥氣感，名可信書褒。", "詩有千篇富，才爲兩蜀豪。", "任誠時少與，敦義世推高。", "劍棧芳菲地，公行我亦勞。"]'),
('8d81fc6b-d440-4575-92f4-2bbb8b42ee33','和范御史初出都門','趙抃','宋','宋诗','song-poetry','','[]','牘奏辭三院，鄉榮領百城。',48,'全唐诗/poet.song.19000.json','["牘奏辭三院，鄉榮領百城。", "帝恩山嶽重，臣命羽毛輕。", "風月隨人好，江湖照膽清。", "須公贈金玉，光照重行行。"]'),
('0c6b7fd0-9f8e-4a4a-b1d2-57c380f75a86','和韻前人初出銷頭','趙抃','宋','宋诗','song-poetry','','[]','奏懇初無飾，天恩亦重違。',48,'全唐诗/poet.song.19000.json','["奏懇初無飾，天恩亦重違。", "一麾新命下，兩槳故關歸。", "淮木林林脫，霜鴻陣陣飛。", "賢朋詩酒樂，行矣自相依。"]'),
('be0c9ccb-2344-4cf9-83c0-9f234ff9c5db','和石澗寺龍潭','趙抃','宋','宋诗','song-poetry','','[]','一遇湯王旱，須爲傅說霖。',48,'全唐诗/poet.song.19000.json','["一遇湯王旱，須爲傅說霖。", "只應蟠澗底，濟物是初心。", "昔歲苗將槁，陽驕不和陰。", "農夫望膏澤，徒蟄爾何深。"]'),
('6dcd79e2-6f41-4044-83f5-dce56694a0a4','和通判范都官不赴賞春','趙抃','宋','宋诗','song-poetry','','[]','幽郡少叢事，名園邀上賓。',48,'全唐诗/poet.song.19000.json','["幽郡少叢事，名園邀上賓。", "逢花有深意，拚醉欲酬春。", "僚友同年舊，郎官拜命新。", "不來無此樂，還似姓車人。"]'),
('4f2a2a88-3c48-4163-92f9-d0b82558195b','續夢中作','趙抃','宋','宋诗','song-poetry','','[]','邊寄今儒弁，帷籌得將才。',48,'全唐诗/poet.song.19000.json','["邊寄今儒弁，帷籌得將才。", "甘辛均士卒，號令走風雷。", "驚曉城鼙急，吹秋隴笛哀。", "先聲羌膽碎，聞道漢兵來。"]'),
('9791011c-f78c-4b89-b936-2c83db965bdb','次韻吳充學士齋居冬夜書事','趙抃','宋','宋诗','song-poetry','','[]','輪奐相輝映，嚴扉聳畫楹。',48,'全唐诗/poet.song.19000.json','["輪奐相輝映，嚴扉聳畫楹。", "霜空夜月午，齋冷湛冰清。", "縟禮行神廟，星華下禁城。", "瀛洲有才士，佳句見交情。"]'),
('a6e6f7a0-2782-4de0-bbeb-8b1c820b8289','和六弟抗江上書懷','趙抃','宋','宋诗','song-poetry','','[]','一失已戚戚，誠哉勿爾爲。',48,'全唐诗/poet.song.19000.json','["一失已戚戚，誠哉勿爾爲。", "因知賢者事，不與眾人期。", "別浦客帆卸，隔江漁笛吹。", "同行兄弟樂，還免動鄉思。"]'),
('25f6470b-b26e-4b52-8be2-4e5d168516b0','驚濤','趙抃','宋','宋诗','song-poetry','','[]','路半狂飚起，江心巨浪橫。',48,'全唐诗/poet.song.19000.json','["路半狂飚起，江心巨浪橫。", "蒼茫舟子叫，匍匐稚兒驚。", "古岸移時入，新醪薄暮傾。", "此宜無足道，大抵似人生。"]'),
('24f04c61-2da5-4015-9bda-af2ac1f52c5a','別後寄表弟李定','趙抃','宋','宋诗','song-poetry','','[]','之官雖異數，行棹欲同仙。',48,'全唐诗/poet.song.19000.json','["之官雖異數，行棹欲同仙。", "忽覺清風遠，因驚俗累牽。", "子留書得後，我愧約乖前。", "境上依依過，江南水拍天。"]'),
('0c0f8cc3-e35e-42ce-bcce-91f3cd2430f6','彭澤狄梁公祠','趙抃','宋','宋诗','song-poetry','','[]','賢正屯蒙日，陰邪會用時。',48,'全唐诗/poet.song.19000.json','["賢正屯蒙日，陰邪會用時。", "人從萬死過，誰肯一言危。", "毒意回天后，忠誠薦柬之。", "復唐三百載，留得枕江祠。"]'),
('b3a3775f-1eb8-49ba-819b-1c4d87168a57','經鄱陽湖','趙抃','宋','宋诗','song-poetry','','[]','捨陸事川程，霜天曉色明。',48,'全唐诗/poet.song.19000.json','["捨陸事川程，霜天曉色明。", "長波萬頃闊，大舸一帆輕。", "靜唱村漁樂，斜飛渚鴈驚。", "雲披見樓閣，隱隱豫章城。"]'),
('e61edacd-c335-4bca-9ed0-e7f1bbfb9866','次韻何若谷賞花即席','趙抃','宋','宋诗','song-poetry','','[]','朋心照舊明，寧比蓋初傾。',48,'全唐诗/poet.song.19000.json','["朋心照舊明，寧比蓋初傾。", "共惜花兼酒，誰論利復名。", "與君如有約，不醉似無情。", "更遇詩勍敵，周旋未易輕。"]'),
('ba48a81b-9cec-4435-9d00-c1440704f81e','紀雨','趙抃','宋','宋诗','song-poetry','','[]','歲始三日雨，恩隨萬井春。',48,'全唐诗/poet.song.19000.json','["歲始三日雨，恩隨萬井春。", "如何至和氣，先被遠方人。", "洗濯山川秀，霑濡草木新。", "堯仁際天地，調燮有臣鄰。"]'),
('64e3e5b4-acb4-4159-9d4b-3455e13a3d63','次韻提刑蔡挺度支見贈','趙抃','宋','宋诗','song-poetry','','[]','歷章初請外，亡狀愧瘝官。',48,'全唐诗/poet.song.19000.json','["歷章初請外，亡狀愧瘝官。", "爲郡恩尤重，斯民治素難。", "訟稀逢薄稔，詩倡得清歡。", "況復仁封接，焉依簟與菅。"]'),
('9a5e7408-a70b-4f12-8ff8-7b47455fe1ed','次韻何若谷中隱堂觀棊','趙抃','宋','宋诗','song-poetry','','[]','春晝僧房靜，楸枰戰氣豪。',48,'全唐诗/poet.song.19000.json','["春晝僧房靜，楸枰戰氣豪。", "斜飛沙塞鴈，奔怒海門濤。", "決勝周旋久，陰謀計較勞。", "豈知中隱士，心不掛纖毫。"]'),
('5107ab48-cc5f-46b3-9811-b77e6e7b1850','送興國令徐師回殿丞','趙抃','宋','宋诗','song-poetry','','[]','報政方山下，分携贛水濱。',48,'全唐诗/poet.song.19000.json','["報政方山下，分携贛水濱。", "人蒙百里惠，花見四年春。", "親志樂戲綵，家聲高縉紳。", "還期逢慶節，慈宴拱嚴宸。"]'),
('21073043-4055-4d19-b059-0fdde7eb3a45','登章貢臺','趙抃','宋','宋诗','song-poetry','','[]','章貢東西派，并流作贛川。',48,'全唐诗/poet.song.19000.json','["章貢東西派，并流作贛川。", "奔湍出城曲，離合向臺前。", "把酒來憑檻，鳴鼙見放船。", "滔滔歸底處，滄海路三千。"]'),
('aa3fe9cb-41be-4076-a72b-9e9e1295d07b','次韻周敦頤國博重陽節近見菊','趙抃','宋','宋诗','song-poetry','','[]','爲僚初自喜，邀客亦逢嘉。',48,'全唐诗/poet.song.19000.json','["爲僚初自喜，邀客亦逢嘉。", "把酒須同樂，分襟莫預嗟。", "未成登畫舸，好共賞黄花。", "試向東籬看，秋叢映晚霞。"]'),
('a6042dd4-a501-4a79-8e2e-ac239daad8b7','題張果老洞','趙抃','宋','宋诗','song-poetry','','[]','洞老壽松椿，高名古絕羣。',48,'全唐诗/poet.song.19000.json','["洞老壽松椿，高名古絕羣。", "亂山泉㶁㶁，舉世事紛紛。", "使者持丹詔，先生卧白雲。", "方今莫招隱，君德正華勛。"]'),
('3ca53acd-6701-4af6-b556-8576e6e31986','贈琴臺僧正','趙抃','宋','宋诗','song-poetry','','[]','寺古傍郊坰，門無車馬聲。',48,'全唐诗/poet.song.19000.json','["寺古傍郊坰，門無車馬聲。", "我來聞眾妙，人少到師清。", "錦水金波靜，銀蟾一指明。", "幽琴徐發響，真不負臺名。"]'),
('3e5c1b34-e351-4a77-bfbe-5fea3fdb95c1','留題修覺山','趙抃','宋','宋诗','song-poetry','','[]','按行車暫尼，身得止崢嶸。',48,'全唐诗/poet.song.19000.json','["按行車暫尼，身得止崢嶸。", "江喜淙淙聽，雲疑步步生。", "春鄰花縣好，晴遠劍關明。", "買石鎸豪句，高哉老杜名。"]'),
('ee44f3fd-c440-47b5-944b-e8852a6576a7','次韻孔憲山齋','趙抃','宋','宋诗','song-poetry','','[]','訟簡歲豐盈，鈴齋竟日清。',48,'全唐诗/poet.song.19000.json','["訟簡歲豐盈，鈴齋竟日清。", "窗排羣石怪，簷擁遠山明。", "古木風千葉，新髭雪數莖。", "開樽向幽處，餘論見高情。"]'),
('f6e00a7b-bd57-4254-98bd-40675052c971','送前人赴闕','趙抃','宋','宋诗','song-poetry','','[]','正性歸忠誼，名談見本原。',48,'全唐诗/poet.song.19000.json','["正性歸忠誼，名談見本原。", "中丞有賢子，宣聖得真孫。", "解職留民惠，還朝拜主恩。", "東方要安堵，一爲上前論。"]'),
('67f22850-ba59-4565-9c2e-b355ffbed636','次韻吳中復龍圖題長橋鋪','趙抃','宋','宋诗','song-poetry','','[]','山東去蜀右，不憚客程遥。',48,'全唐诗/poet.song.19000.json','["山東去蜀右，不憚客程遥。", "酒酌杯中醁，琴携爨下焦。", "故人題大筆，佳句刻長橋。", "快讀離懷解，如冰暖日消。"]'),
('a64d0c31-9960-4393-ad29-5c183ba16fea','寄衢僧惟簡','趙抃','宋','宋诗','song-poetry','','[]','南禪眾所稱，簡老是真僧。',48,'全唐诗/poet.song.19000.json','["南禪眾所稱，簡老是真僧。", "法器聞雖古，清風見未曾。", "洪爐中點雪，大海裏孤燈。", "七十休官近，歸歟我得朋。"]'),
('8766cb0b-2d45-4840-be8b-0a0a8f7211e7','寄謝毛憲','趙抃','宋','宋诗','song-poetry','','[]','去贛八千里，於今十二年。',48,'全唐诗/poet.song.19000.json','["去贛八千里，於今十二年。", "無緣久東浙，有命再西川。", "吏散庭空訟，僧高寺欲禪。", "老來思舊治，尤喜獲佳篇。"]'),
('da727b2d-39e9-447b-a76a-aa0a87b1043c','送范憲百祿赴闕','趙抃','宋','宋诗','song-poetry','','[]','泥書下紫宸，公議協朝紳。',48,'全唐诗/poet.song.19000.json','["泥書下紫宸，公議協朝紳。", "真主正圖治，諫官今得人。", "從容陪國論，憔悴恤天民。", "大對如晁董，公嘗素所陳。"]'),
('b5bc1173-f3a4-4591-830a-23cbcd2d0457','和榮諲學士按部過長濆關所寄詩','趙抃','宋','宋诗','song-poetry','','[]','叱馭窮邊壘，還轅賞驛梅。',48,'全唐诗/poet.song.19000.json','["叱馭窮邊壘，還轅賞驛梅。", "微香心旋吐，清詠意尤瓌。", "誨墨蒙兼貺，郵筒喜屢開。", "錦官花更好，翹望臘前回。"]'),
('47d6c17c-95c8-4483-a39f-d9fbcc8c7767','閔雨','趙抃','宋','宋诗','song-poetry','','[]','閔雨詔復下，傷農今四春。',48,'全唐诗/poet.song.19000.json','["閔雨詔復下，傷農今四春。", "潭龍從號懶，廟鬼詎能神。", "苗槁塵生久，雲空電轉頻。", "天公誠可問，誰與主陶鈞。"]'),
('8e95c0cc-df95-4c06-a962-0485f3d22b55','次韻李元方秀才秋日旅懷','趙抃','宋','宋诗','song-poetry','','[]','節物奚爲感，秋懷不自任。',48,'全唐诗/poet.song.19000.json','["節物奚爲感，秋懷不自任。", "曉寒侵遠夢，秋力助高吟。", "薄脫驚風葉，疎舂隔水砧。", "商絃調一曲，惟子定知音。"]'),
('753e405c-ee3b-4804-9695-56b6cd679aa5','題靈山寺','趙抃','宋','宋诗','song-poetry','','[]','我爲靈山好，登留到日曛。',48,'全唐诗/poet.song.19000.json','["我爲靈山好，登留到日曛。", "巖幽餘暑雪，鐘冷入秋雲。", "篇詠惟僧助，塵煩與俗分。", "明朝入東棹，因得識吾文。"]'),
('55e28b7a-0751-4de8-b6ad-acacc44b4155','寄題致政周洙屯田如詔亭','趙抃','宋','宋诗','song-poetry','','[]','誥出義方語，亭更發詔名。',48,'全唐诗/poet.song.19000.json','["誥出義方語，亭更發詔名。", "爲郎拜天寵，有子擅家聲。", "健羨鄉評美，光輝野史榮。", "綵衣官亦重，門外擁雙旌。"]'),
('01daceb6-13e2-4327-b773-10fcff12574d','致政都官宋兄言歸舊隱贈行','趙抃','宋','宋诗','song-poetry','','[]','休官鎮浮俗，眉壽冠同年。',48,'全唐诗/poet.song.19000.json','["休官鎮浮俗，眉壽冠同年。", "恬養八十歲，苦吟三百篇。", "乘秋迓杖屨，終日隱林泉。", "我羨歸歟樂，高蹤不可肩。"]'),
('6a67f914-243e-4134-8cfb-66c99a4d1c8f','游海雲山','趙抃','宋','宋诗','song-poetry','','[]','縹緲齊雲閣，遥聞摸石池。',48,'全唐诗/poet.song.19000.json','["縹緲齊雲閣，遥聞摸石池。", "物華春已盛，人意樂無涯。", "羅綺一山遍，旌旗十里隨。", "花棚夾歸道，驍騎看星馳。"]'),
('18bf3b61-5438-4e72-b9e6-c4e4111dc7ec','次韻程給事赴越任過杭相會','趙抃','宋','宋诗','song-poetry','','[]','已久論交契，何妨醉別筵。',48,'全唐诗/poet.song.19000.json','["已久論交契，何妨醉別筵。", "君宜歸大用，我獨倦高年。", "郡印今分治，科名昔共鎸。", "離懷雖一水，言遠似三川。"]'),
('eba4d119-0abb-4c3b-87e6-2a2a061668fb','題杭州雙竹寺','趙抃','宋','宋诗','song-poetry','','[]','粉籜雙雙脫，修篁兩兩高。',48,'全唐诗/poet.song.19000.json','["粉籜雙雙脫，修篁兩兩高。", "同心齊管鮑，並節漢蕭曹。", "寒歲霜威禦，炎天暑氣逃。", "此君真可異，吟遶不知勞。"]'),
('3367f5ea-9436-42d9-9b32-132541732fb3','送章岵少卿提舉洞霄宮二首  其一','趙抃','宋','宋诗','song-poetry','','[]','秘館紅塵外，瑶京白日邊。',48,'全唐诗/poet.song.19000.json','["秘館紅塵外，瑶京白日邊。", "樽中不空酒，琴面已無絃。", "曉上朝真閣，春耕負郭田。", "優游大自在，何處更神仙。"]'),
('d4c8dc75-0824-4fdc-a149-4dbf2fa8af7d','送章岵少卿提舉洞霄宮二首  其二','趙抃','宋','宋诗','song-poetry','','[]','使節忠罄勤，東南兩見春。',48,'全唐诗/poet.song.19000.json','["使節忠罄勤，東南兩見春。", "清宵多假寐，白髮半憂民。", "金闕遥辭寵，琳宮去謁真。", "羨公誰最甚，我是欲歸人。"]'),
('b0cb04c8-b86b-471d-ba84-3ff10707b03e','次韻趙少師寄別程給事','趙抃','宋','宋诗','song-poetry','','[]','人生難會合，天與此階緣。',48,'全唐诗/poet.song.19000.json','["人生難會合，天與此階緣。", "逸駕來艱遠，孤颿映後前。", "吳江阻潮汐，越嶠望雲烟。", "敘別情何厚，新詩兩燦然。"]'),
('6bafb24e-0fe2-4be6-8ca7-81c8926a94bb','送六弟隨子之官毗陵','趙抃','宋','宋诗','song-poetry','','[]','鴈序暫分飛，毗陵動所思。',48,'全唐诗/poet.song.19000.json','["鴈序暫分飛，毗陵動所思。", "廉能真有子，清白素聞詩。", "船泛西州遠，山尋北蕩奇。", "明春復歸會，還是隔年期。"]'),
('59cf2101-ce95-4479-8d74-77aa96b306a1','覽先祖太傅留題國清寺繼和','趙抃','宋','宋诗','song-poetry','','[]','得謝殊狂客，無言愧浄名。',48,'全唐诗/poet.song.19000.json','["得謝殊狂客，無言愧浄名。", "心觀潭月白，梵聽海潮聲。", "曉色開華頂，秋暉照赤城。", "公詩播人口，冰玉未爲清。"]'),
('db9907e6-9e98-4fd6-bff3-3242ea48ffdf','抵永嘉題謝公巖','趙抃','宋','宋诗','song-poetry','','[]','嶺路與巖坰，池樓古郡城。',48,'全唐诗/poet.song.19000.json','["嶺路與巖坰，池樓古郡城。", "千年溫俗意，四榜謝公名。", "寄傲留佳句，遺思出至誠。", "滔滔慎江水，東注等休聲。"]'),
('54ab9ec7-afa6-4c8b-91ec-52ef541bea29','贈鄭賡高士','趙抃','宋','宋诗','song-poetry','','[]','易有幽人象，天垂處士星。',48,'全唐诗/poet.song.19000.json','["易有幽人象，天垂處士星。", "知音辭相府，歸養爲親庭。", "閒和碧雲句，深窮白首經。", "惟賢二千石，優顧眼尤青。"]'),
('1da3a9a9-03cd-4ac1-8974-34639e91d4c1','早離溫江夜泊白沙步','趙抃','宋','宋诗','song-poetry','','[]','曉與諸孫別，依然頗動懷。',48,'全唐诗/poet.song.19000.json','["曉與諸孫別，依然頗動懷。", "去乘蘭棹穩，行得綵衣偕。", "漁父遥連市，村扉半掩柴。", "夜來溪上宿，夢已在高齋。"]'),
('66235e33-ba94-40bb-a659-3afeecd95d67','次韻寄致政石牧之大夫','趙抃','宋','宋诗','song-poetry','','[]','予退喜同休，翻思慎水遊。',48,'全唐诗/poet.song.19000.json','["予退喜同休，翻思慎水遊。", "閒雲披遠岫，明月在高樓。", "送日千餘里，離懷三度秋。", "爭如禪客子，截斷眾江流。"]'),
('97b05345-97aa-458e-9145-db28d54e6186','寄酬吳天常中散','趙抃','宋','宋诗','song-poetry','','[]','仕契最敦厚，夤緣絕夤倫。',48,'全唐诗/poet.song.19000.json','["仕契最敦厚，夤緣絕夤倫。", "同登甲戌第，俱是戌申人。", "把酒曾四老，分携又五春。", "新詩光篋笥，珠寶未爲珍。"]'),
('af0d6092-c7bc-4c74-9596-b3049c55dce1','送毛寬任清流主簿','趙抃','宋','宋诗','song-poetry','','[]','輕舟離曉岸，涼氣滿秋空。',48,'全唐诗/poet.song.19000.json','["輕舟離曉岸，涼氣滿秋空。", "鸞枳從官況，蟾宮繼父風。", "榮塗終頡頏，清節愈磨礲。", "今我所期子，名當徹舜聰。"]'),
('5566fbf0-f020-42b7-8567-75025a555a0c','西湖吳中允墳生芝草','趙抃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','中允壽齡尊，人亡德尚存。',48,'全唐诗/poet.song.19000.json','["中允壽齡尊，人亡德尚存。", "無根彼芝草，爲瑞此松墳。", "往行稱鄉井，遺榮付子孫。", "靈苗豈虛設，所應在高門。"]'),
('6b88ab64-3d95-4a51-9d9c-3fcb3e7708f8','送吳栢節推赴闕','趙抃','宋','宋诗','song-poetry','','[]','簡刑憂俗困，一境被恩私。',48,'全唐诗/poet.song.19000.json','["簡刑憂俗困，一境被恩私。", "清極人知勸，誠先吏不欺。", "席觴徒眷戀，岸菊漸離披。", "薦鶚有餘表，橫飛去指期。"]'),
('74a1ee2f-9c68-4c01-85ec-7c4f345e41f9','宿故梁子正得意堂有感示諸梁英少','趙抃','宋','宋诗','song-poetry','','[]','遺訓素諄諄，先生冢尚新。',48,'全唐诗/poet.song.19000.json','["遺訓素諄諄，先生冢尚新。", "門風競蘭玉，鄉譽動簪紳。", "戶牖宵排燭，琴書晝拂塵。", "子孫爲學盛，宜有起家人。"]'),
('aae990f1-af06-48aa-86e8-3f34f020d6d2','外弟李定少卿輓詩三首  其一','趙抃','宋','宋诗','song-poetry','','[]','子舍競詵詵，號天日月昏。',48,'全唐诗/poet.song.19000.json','["子舍競詵詵，號天日月昏。", "有綃傳秀像，無藥反英魂。", "右棘官虛位，西山墓閉門。", "遣余衣上淚，時復有啼痕。"]'),
('2d015166-0864-4f60-bd16-cd746a257f4a','外弟李定少卿輓詩三首  其二','趙抃','宋','宋诗','song-poetry','','[]','少列吾姑子，懷能負俊良。',48,'全唐诗/poet.song.19000.json','["少列吾姑子，懷能負俊良。", "歌詩追李杜，筆札出鐘王。", "道指三千遠，年踰六十亡。", "嗟哉長已矣，冠劍失威光。"]'),
('3d71c795-9089-4f1e-87e4-a5cbd7b1e1af','外弟李定少卿輓詩三首  其三','趙抃','宋','宋诗','song-poetry','','[]','福地生奚似，喪人送幾何。',48,'全唐诗/poet.song.19000.json','["福地生奚似，喪人送幾何。", "環環山水秀，蟄蟄子孫多。", "情悼魂兮些，辭憑挽者歌。", "嗟余身在越，西首淚滂沱。"]'),
('3f9cf686-c7e2-4293-a829-693ce58e9252','故吳丞相充輓詩三首  其一','趙抃','宋','宋诗','song-poetry','','[]','富貴三朝老，公忠百辟師。',48,'全唐诗/poet.song.19000.json','["富貴三朝老，公忠百辟師。", "躋民復仁壽，與國繫安危。", "聖意加優注，榮途亦屢辭。", "人嗟五福內，獨不享期頤。"]'),
('4a29290f-04f9-42e4-b5e0-579a506cc6b6','故吳丞相充輓詩三首  其二','趙抃','宋','宋诗','song-poetry','','[]','論道尊三事，登庸歷十年。',48,'全唐诗/poet.song.19000.json','["論道尊三事，登庸歷十年。", "舜嘗咨爾岳，說已濟斯川。", "太史書清德，高門繼象賢。", "都人瞻繪像，衮服冠貂蟬。"]'),
('cc2bddc8-7e2a-4381-9640-7377ae963da1','故吳丞相充輓詩三首  其三','趙抃','宋','宋诗','song-poetry','','[]','純誠先德行，餘事著文章。',48,'全唐诗/poet.song.19000.json','["純誠先德行，餘事著文章。", "所予維中壽，難謀彼上蒼。", "旌銘籠曉月，挽鐸訴秋霜。", "自愧居田里，無緣奠柩觴。"]'),
('2b511ca6-fc21-4787-974a-2a3908e95dcb','寄開化余遵道','趙抃','宋','宋诗','song-poetry','','[]','野老余遵道，人微德義尊。',48,'全唐诗/poet.song.19000.json','["野老余遵道，人微德義尊。", "家居青嶂底，身在白雲根。", "盛事傳閭里，昌期付子孫。", "不煩迂步遠，此去自高門。"]'),
('3fc01e2e-45a0-4519-8031-08c5a8cddda8','謝賜飛白御書晏羣玉殿','趙抃','宋','宋诗','song-poetry','','[]','朝野歡和際，君臣愷樂時。',144,'全唐诗/poet.song.19000.json','["朝野歡和際，君臣愷樂時。", "聖謨天地久，睿藻日星垂。", "內閤羣編啟，靈函眾寶披。", "光華頒帝翰，密勿寵官師。", "雨露神毫灑，風雲上意綏。", "翱翔轉鸞鳳，夭矯奮龍螭。", "侍宴聆清問，銜杯拱睟儀。", "御香蒙領袖，和氣入肝脾。", "言念宸恩重，曾非賤士遺。", "天顔瞻咫尺，臣職愧箴規。", "補闕難言衮，傾心竊比葵。", "養賢兼養正，所願易求頤。"]'),
('7df316d6-e079-4671-84aa-cda33701bfdc','同天節','趙抃','宋','宋诗','song-poetry','','[]','土宇歡呼日，天家慶誕辰。',72,'全唐诗/poet.song.19000.json','["土宇歡呼日，天家慶誕辰。", "虹光流渚異，電彩遶樞頻。", "物與薰風浹，祥并協氣臻。", "庭除交玉帛，宴衎列簪紳。", "丹穴來儀鳳，華封祝聖人。", "小臣叨下列，鼓舞頌堯仁。"]'),
('8f9d455f-c107-4d69-993c-434162bbaf85','送韓丞相琦出鎮陜右','趙抃','宋','宋诗','song-poetry','','[]','羌狄方懷德，朝家正右文。',72,'全唐诗/poet.song.19000.json','["羌狄方懷德，朝家正右文。", "邊城輕舉動，天子爲憂勤。", "公位三朝重，威名萬里聞。", "聊煩鎮西夏，盡得護諸軍。", "賜第仍開燕，傳觴命極醺。", "陜民如望旱，一雨壓塵氛。"]'),
('e6154b40-2ca1-469c-b151-6a90b6c53969','急帆','趙抃','宋','宋诗','song-poetry','','[]','江闊北風長，高帆盡幅揚。',72,'全唐诗/poet.song.19000.json','["江闊北風長，高帆盡幅揚。", "勢能分巨浪，力恐拔危檣。", "鷗鷺頻驚迫，魚龍相助忙。", "峯巒旋岸碧，木葉走汀黄。", "快似登仙去，輕於傅羽翔。", "一程三百里，晚泊未斜陽。"]'),
('54cc845b-6279-46db-b283-2c0e8cabea91','初入荆江','趙抃','宋','宋诗','song-poetry','','[]','迢遞辭宸闕，遷延換歲華。',120,'全唐诗/poet.song.19000.json','["迢遞辭宸闕，遷延換歲華。", "舟纔入荆渚，人覺在天涯。", "浪激多推岸，流濡足沸沙。", "勢盤帆小便，漲淺路頻差。", "橫艇叉魚浦，摇旗賣酒家。", "山微思念越，江窄止通巴。", "烟色汀蕪淡，風光野燒斜。", "蠻歌朝競唱，祠鼓暮連撾。", "渡口初逢柳，林邊未見花。", "前程春始盛，一一待詩誇。"]'),
('348669f4-4f5b-4535-8d36-ac8287858810','送昭文劉少卿移知南海','趙抃','宋','宋诗','song-poetry','','[]','世緒傳英德，時才播令名。',240,'全唐诗/poet.song.19000.json','["世緒傳英德，時才播令名。", "錦裀終襲慶，桂籍舊升榮。", "仕路登優績，朝閨服俊聲。", "風猷著臺閣，操尚冠簪纓。", "墳衍方謀學，冰霜未底清。", "分憂膺閫寄，頒教洽輿情。", "會府資謀計，中闈念篤誠。", "漢庭當繼好，戎帳去修盟。", "通幣旋君節，飛芻擁使旌。", "舟車勤轉漕，倉廩慶豐盈。", "廉士祈甄用，貪官愧竄驚。", "鳳書來輦轂，熊軾鎮荆衡。", "壓境無喧訟，連疇近力耕。", "騰謠聞五袴，行樂護千兵。", "道路纖塵絕，人家協氣生。", "渙恩飛睿詔，華序拜名卿。", "更直羣書府，于宣百粵城。", "祖筵徒戀戀，仙舸重行行。", "預想歌來暮，前期報政成。", "上心方簡注，元鼎佇和羹。"]'),
('bed98cb5-722e-4662-b089-4736b3142652','送同年何推官','趙抃','宋','宋诗','song-poetry','','[]','浹恩頒漢檢，沿牒別熊川。',96,'全唐诗/poet.song.19000.json','["浹恩頒漢檢，沿牒別熊川。", "免作徒勞嘆，聊爲從事賢。", "貯文囊製錦，贊畫幕依蓮。", "志尚心非石，標儀骨是仙。", "贈言驚去矣，携手覺淒然。", "遠目渾疑斷，離腸已似煎。", "馬嘶楓葉道，人醉菊花天。", "到日成優績，宸綸佇九遷。"]'),
('b64133b9-a95c-4460-a28c-239692e7472c','庭楠','趙抃','宋','宋诗','song-poetry','','[]','彼美庭楠植，基培幾十年。',96,'全唐诗/poet.song.19000.json','["彼美庭楠植，基培幾十年。", "夜來全庇月，曉去薄生烟。", "萬葉光齊動，雙株影共圓。", "幽樓疑有鶴，清響爲留蟬。", "飲對傳三雅，琴依按七絃。", "河陽花自媚，彭澤柳空眠。", "勢翳門闌靜，陰清几案鮮。", "不才逢訟簡，吟遶强成篇。"]'),
('9a4d4f37-2852-45c8-aa0c-4ceeab8a799f','蜀倅楊瑜邀罨畫池','趙抃','宋','宋诗','song-poetry','','[]','占勝芳菲地，標名罨畫池。',72,'全唐诗/poet.song.19000.json','["占勝芳菲地，標名罨畫池。", "水光菱在鑑，岸色錦舒帷。", "風碎花千動，烟團柳四垂。", "巧才吟不盡，精筆寫徒爲。", "照影摇歌榭，分香上酒巵。", "主人邀客賞，和氣與春期。"]'),
('5277feea-1f14-47fa-be51-a63ae5887a80','寄謝雲安知軍王端屯田','趙抃','宋','宋诗','song-poetry','','[]','舊邦逢朐䏰，靈地接岷峨。',192,'全唐诗/poet.song.19000.json','["舊邦逢朐䏰，靈地接岷峨。", "住嶺排烟火，懸巖引薜蘿。", "雨花疑錦濯，晴水甚藍挼。", "遠地之官去，孤舟走嶮拕。", "出麾無一事，傾蓋首相過。", "幸不愚煩外，欣承議論多。", "春光千騎駿，天色百城和。", "賞物樓新構，鎸文石旋磨。", "爲時即慷慨，得友盛吟哦。", "世重黄金諾，人傳白雪歌。", "投壺傾立馬，飛鏑屢鳴鼉。", "局戰犀敲玉，杯歡亂酌螺。", "坐來風入袂，歸去月流波。", "我愧才疏拙，生微術揣摩。", "主容勤勞徠，行色覺蹉跎。", "匪用詩爲好，離懷可奈何。"]'),
('0925bd81-8683-489c-9e70-6f9f3c7d98cc','江上遇雪','趙抃','宋','宋诗','song-poetry','','[]','凍雲交四隅，飛雪滿江湖。',72,'全唐诗/poet.song.19000.json','["凍雲交四隅，飛雪滿江湖。", "急勢團風轉，閒容到水無。", "並遊漁喜唱，失侶雁驚呼。", "客棹沿灣泊，村醪覓徑酤。", "去程方數蜀，歸思正遥吳。", "得句同諸弟，余懷幸不孤。"]'),
('5e0eab79-f90f-4a22-9747-2444d7791236','登望闕臺','趙抃','宋','宋诗','song-poetry','','[]','江外三千里，城頭百尺臺。',72,'全唐诗/poet.song.19000.json','["江外三千里，城頭百尺臺。", "神都瞻寶闕，星斗切瑶魁。", "風闊春襟快，雲披曉月開。", "山川增氣象，欄檻出塵埃。", "天際橫歸鴈，林梢露出槐。", "喜逢冠蓋客，半是日邊來。"]'),
('1074a5c9-cc04-4579-a583-6d696947a4cd','次韻何若谷別後見寄','趙抃','宋','宋诗','song-poetry','','[]','言念分符日，來逢別乘賢。',120,'全唐诗/poet.song.19000.json','["言念分符日，來逢別乘賢。", "瘡痍求俗去，風教爲民宣。", "吏獄都無擾，農疇屬有年。", "歡嘗陪射的，清不廢鳴絃。", "避俗尋蕭寺，遊春醉畫船。", "文楸坐帷幄，詩敵肆戈鋋。", "邂逅窮江地，淒涼落葉天。", "代還公去矣，佇立我依然。", "久契誠彌固，離憂不暫蠲。", "高臺倚章貢，時一誦佳篇。"]'),
('77207844-2d07-458e-b475-65355f358996','成大卿宅矮槐','趙抃','宋','宋诗','song-poetry','','[]','手植踰三紀，年隨矮勢增。',72,'全唐诗/poet.song.19000.json','["手植踰三紀，年隨矮勢增。", "枝盤多蠖屈，根轉欲虬騰。", "密覆周遭地，孤撐最上層。", "風條低偃蹇，烟葉碎鬅鬙。", "顧我來雖羨，如公退未能。", "溪園饒樂事，時此會佳朋。"]'),
('31744600-561e-4037-9c3e-63be92824078','遊青城山','趙抃','宋','宋诗','song-poetry','','[]','三十六峯峻，維岷在蜀奇。',96,'全唐诗/poet.song.19000.json','["三十六峯峻，維岷在蜀奇。", "方行刺史部，重款丈人祠。", "凍雪諸蕃隔，晴雲六面披。", "訪山窮寶洞，敕鬼覘豐碑。", "泉落寒崖響，蘿依古木垂。", "良工存舊筆，老叟琢新詩。", "陟險齊雙屐，逢幽鼓七絲。", "盤桓不忍去，還作更來期。"]'),
('bf260977-6869-4d47-96dd-0bb054badd71','喜雨','趙抃','宋','宋诗','song-poetry','','[]','火官施酷令，曦馭肆炎威。',96,'全唐诗/poet.song.19000.json','["火官施酷令，曦馭肆炎威。", "魃虐詩嘗刺，巫焚禮舊譏。", "神將明德應，人用至誠祈。", "有幸真天與，先期不汝違。", "四郊雲靉靉，三日雨霏霏。", "色動田園喜，聲無里巷欷。", "終圖實倉廩，已足賤珠璣。", "報彼民咨者，恩斯帝力歸。"]'),
('3ee5ede3-cbcb-4201-908a-0cbbbd602311','引年自喜','趙抃','宋','宋诗','song-poetry','','[]','乾坤報不得，犬馬戀無緣。',72,'全唐诗/poet.song.19000.json','["乾坤報不得，犬馬戀無緣。", "請有再三瀆，生踰七十年。", "雲山充素志，霜雪滿華巔。", "遠矣日邊地，歸歟春暮天。", "灘長釣臺客，棋久爛柯仙。", "去樂林泉下，何勞一指禪。"]'),
('798e097e-12cc-41e9-868e-888046f3cc06','次韻程給事會稽懷古即事','趙抃','宋','宋诗','song-poetry','','[]','東南杭與越，形勢夾長川。',288,'全唐诗/poet.song.19000.json','["東南杭與越，形勢夾長川。", "地占一方秀，天生萬象全。", "兩城俱卓爾，列郡豈加焉。", "異世稱無間，同時較有偏。", "厥民如貴簡，彼國實居先。", "大海收淮瀆，羣山冠幅員。", "古人蹤欲見，遊客目先穿。", "況自醇風俗，從來省朴鞭。", "有年人既庶，樂教志彌堅。", "每得前朝事，嘗由眾口傳。", "土疆歸闕下，州宇闢湖邊。", "未苦秦來幸，先經霸擅權。", "有賢思避世，擇地效高眠。", "盤屈稽山勢，嵯峨玉笥巔。", "茂林侵碧漢，修竹掛青烟。", "東浙潮聲近，西陵草色鮮。", "四明登陸顯，五泄夾溪沿。", "漁浦從舟楫，仙居遠市廛。", "山青難入畫，花灼正如燃。", "石傘陰遮徑，松潭韻寫絃。", "千峯雲靉靆，雙澗水潺湲。", "靈迹曾遊處，清風可坐延。", "龜浮山出浪，龍去井迷年。", "泉湧尋源出，蘿繁附木纏。"]'),
('89f072b2-aa24-4f17-b24f-394dafc987e9','次韻程給事同孫覺學士楊憲景略天衣謁禹廟夜歸','趙抃','宋','宋诗','song-poetry','','[]','梵守近靈祠，偕遊薄晚歸。',144,'全唐诗/poet.song.19000.json','["梵守近靈祠，偕遊薄晚歸。", "雲疎通日影，風景作霜威。", "博約詩情健，盤桓酒力微。", "旌麾分頡頏，戈戟聳光輝。", "左右車帷徹，周連燭炬圍。", "湖流平杳杳，泉派濺霏霏。", "却念觀珪劍，仍欣賞鉢衣。", "廟樓臨浩渺，寺閣倚峩巍。", "燈火還城市，烟波遠石磯。", "鼓鐘初警動，騶馭始分飛。", "勝槩同時遇，賢朋共樂稀。", "佳章蒙寄貺，隣愧得仁依。"]'),
('8464fa1e-51fc-4242-bcf0-dc80a67e060f','次韻林希喜趙少師概遊杭','趙抃','宋','宋诗','song-poetry','','[]','維嶽生台輔，於時正典刑。',192,'全唐诗/poet.song.19000.json','["維嶽生台輔，於時正典刑。", "我嘗同政府，公早謝明廷。", "官貴躋三少，身閒越八齡。", "所難惟壽算，豈易是康寧。", "求舊心猶壯，尋幽足未停。", "宋都俄暫別，吳語喜重聽。", "宗契今逾厚，交情久可銘。", "摛辭工詠物，吐屑妙談經。", "嵐色迎紅旆，湖光動綵舲。", "游名多寫壁，燕席旋張屏。", "忽遇瀛洲客，新辭使者星。", "承恩來玉陛，涖事傍沙汀。", "厭賞塵中景，思登野外亭。", "愛忘嘉意重，溢美雅章形。", "敘遠才超絕，搜奇思杳冥。", "道山寧久去，歸路入雲青。"]'),
('0b461d34-b121-4254-9bba-f92a0ed9e6bc','麓山十詠 真身湖','趙抃','宋','宋诗','song-poetry','','[]','曉光澄水月，秋影顫風幡。',24,'全唐诗/poet.song.19000.json','["曉光澄水月，秋影顫風幡。", "宛是真如地，荷花獲翠軒。"]'),
('666a569d-9ee0-404c-bbcb-6674dd7ac4ba','升中古柏','趙抃','宋','宋诗','song-poetry','','[]','雪挫更霜摧，寒心未易回。',24,'全唐诗/poet.song.19000.json','["雪挫更霜摧，寒心未易回。", "庭前皆古意，何必問西來。"]'),
('d7bc87d9-3eaa-4f5d-bb6f-d189374be9b0','書院','趙抃','宋','宋诗','song-poetry','','[]','雨久藏書蠹，風高老屋斜。',24,'全唐诗/poet.song.19000.json','["雨久藏書蠹，風高老屋斜。", "鄰居盡金碧，一一梵王家。"]'),
('52dad72c-990d-4c8c-935c-294d7a0c8cd4','四絕堂','趙抃','宋','宋诗','song-poetry','','[]','千燈傳靜剎，四絕號虛堂。',24,'全唐诗/poet.song.19000.json','["千燈傳靜剎，四絕號虛堂。", "已是金銀界，仍爲翰墨場。"]'),
('c44e41ed-aab7-4477-bc43-3445a13a84a2','洞真觀','趙抃','宋','宋诗','song-poetry','','[]','木老巖坰冷，泉飛月殿寒。',24,'全唐诗/poet.song.19000.json','["木老巖坰冷，泉飛月殿寒。", "栖真無一事，清嘯倚欄干。"]'),
('1cd4e345-f350-4d24-a4be-4c4abb74df1b','抱黄洞','趙抃','宋','宋诗','song-poetry','','[]','靈洞古壇基，烟蘿接翠微。',24,'全唐诗/poet.song.19000.json','["靈洞古壇基，烟蘿接翠微。", "日西春又晚，不見羽人歸。"]'),
('ee247a1d-1836-4f04-a33a-bf0731e4ac44','嶽麓寺','趙抃','宋','宋诗','song-poetry','','[]','古木與雲齊，門前百丈梯。',24,'全唐诗/poet.song.19000.json','["古木與雲齊，門前百丈梯。", "我來煩想滌，疑是過靈溪。"]'),
('e453b50d-b22b-457d-91bd-1ec98c7a316a','白鶴泉','趙抃','宋','宋诗','song-poetry','','[]','靈派本無源，因禽潄玉泉。',24,'全唐诗/poet.song.19000.json','["靈派本無源，因禽潄玉泉。", "自非流異稟，誰識洞中僊。"]'),
('f28add97-17a0-4134-a641-177f3be8f1a0','法華堂','趙抃','宋','宋诗','song-poetry','','[]','峯頂已崔嵬，因高更筑臺。',24,'全唐诗/poet.song.19000.json','["峯頂已崔嵬，因高更筑臺。", "夜分僧定起，咫尺見雲雷。"]'),
('5ebb26f2-fdda-441c-9273-48f7d9c24a91','拜嶽石','趙抃','宋','宋诗','song-poetry','','[]','片石倚中天，雲深鳥道間。',24,'全唐诗/poet.song.19000.json','["片石倚中天，雲深鳥道間。", "人多祝堯壽，登此拜南山。"]'),
('b2759248-7aa6-483f-89cd-78690a2800d4','過雲安軍下巖僧舍','趙抃','宋','宋诗','song-poetry','','[]','幽寺倚巖阿，雲扉掩薜蘿。',24,'全唐诗/poet.song.19000.json','["幽寺倚巖阿，雲扉掩薜蘿。", "老僧中燕息，誰問世風波。"]'),
('938046a1-4877-4d51-9a91-96c5574580b1','橫溪洞飛泉','趙抃','宋','宋诗','song-poetry','','[]','寒瀑落春巖，天垂百丈縑。',24,'全唐诗/poet.song.19000.json','["寒瀑落春巖，天垂百丈縑。", "更疑仙客宴，不捲水晶簾。"]'),
('c7fcc288-d061-4ff6-80e8-6e8ac78bcde8','和范御史過陳州','趙抃','宋','宋诗','song-poetry','','[]','灣盡疑無路，堤回忽見橋。',24,'全唐诗/poet.song.19000.json','["灣盡疑無路，堤回忽見橋。", "冬空仍水後，物物稱蕭條。"]'),
('c5251df8-7e73-4659-a1f3-b30d2a88618b','題魚關','趙抃','宋','宋诗','song-poetry','','[]','奔流出萬山，亂石銷孱顔。',24,'全唐诗/poet.song.19000.json','["奔流出萬山，亂石銷孱顔。", "彼躍龍門者，何嘗懼此關。"]'),
('6acd0841-dc9a-48a9-884d-9131f071019f','男㞦生日','趙抃','宋','宋诗','song-poetry','','[]','重九登高節，陽秋稟氣和。',24,'全唐诗/poet.song.19000.json','["重九登高節，陽秋稟氣和。", "家家懽會日，祺壽所宜多。"]'),
('f3ea85cb-1697-4be0-84c6-6fcc9375fa2a','次韻吳天常','趙抃','宋','宋诗','song-poetry','','[]','塵事不留毫，誰云夢寐勞。',24,'全唐诗/poet.song.19000.json','["塵事不留毫，誰云夢寐勞。", "因思四老會，今復數年高。"]'),
('763ebe90-1d71-409c-959f-e82b90647fc3','書琴壇','趙抃','宋','宋诗','song-poetry','','[]','制動必原靜，治人先正心。',24,'全唐诗/poet.song.19000.json','["制動必原靜，治人先正心。", "風乎晝壇上，退食鳴瑶琴。"]'),
('94681dfa-ae62-4fc5-a11c-7c70474c2739','和范御史石倉晚泊','趙抃','宋','宋诗','song-poetry','','[]','天迥旅懷闊，風長野叫來。',24,'全唐诗/poet.song.19000.json','["天迥旅懷闊，風長野叫來。", "滄波清可愛，先爲濯京埃。"]'),
('81eb8527-c067-4234-952a-f0a229f5ac4e','覺林寺','趙抃','宋','宋诗','song-poetry','','[]','古寺無碑刻，僧云不記年。',24,'全唐诗/poet.song.19000.json','["古寺無碑刻，僧云不記年。", "自餘安所問，惟是愛林泉。"]'),
('0210ef92-f551-4425-9865-47018ec8a6fe','禁籞見牡丹仍蒙恩賜','趙抃','宋','宋诗','song-poetry','','[]','校文春殿籥天關，內籞千葩放牡丹。',64,'全唐诗/poet.song.19000.json','["校文春殿籥天關，內籞千葩放牡丹。", "風捲異香來幕帟，日披濃艷出欄干。", "芳菲喜向禁中見，憔悴憶曾江外看。", "剪賜從臣君意重，數枝和露入金盤。"]'),
('b268cd39-d984-4f29-8a6c-49a902d866cb','次韻三司蔡襄蘆鴈獐猿二首  其一','趙抃','宋','宋诗','song-poetry','','[]','省宇屏圖哲匠成，寫傳蘆鴈筆尤精。',64,'全唐诗/poet.song.19000.json','["省宇屏圖哲匠成，寫傳蘆鴈筆尤精。", "斜依風葦叢叢裊，遠颺烟波渺渺平。", "弋者定嗟何所慕，鵬摶莫怪不能鳴。", "公看羽翼飛勝處，有意青雲萬里程。"]'),
('558a2833-d006-4735-be98-2e9f68800299','次韻三司蔡襄蘆鴈獐猿二首  其二','趙抃','宋','宋诗','song-poetry','','[]','獐狎猿馴遂性情，恍然疑不是丹青。',64,'全唐诗/poet.song.19000.json','["獐狎猿馴遂性情，恍然疑不是丹青。", "豈憂夜獵林中去，只欠秋吟月下聽。", "舉目便同臨澗谷，此身全恐寄郊坰。", "山容野態窮微妙，造化爭功六幅屏。"]'),
('28ee26fb-8e17-4649-a466-058ebcbf9ac2','憶信安五弟拊','趙抃','宋','宋诗','song-poetry','','[]','臘殘鸚鵡洲邊過，憶汝東吳住舊廬。',64,'全唐诗/poet.song.19000.json','["臘殘鸚鵡洲邊過，憶汝東吳住舊廬。", "誦聖窮愁千卷外，覓官留滯十年餘。", "也知失意能平氣，底事多時不寄書。", "兄在松溪我荆楚，別懷三處一欷歔。"]'),
('c4e9fb56-1005-4e29-83b7-aab125ee86af','飲酒','趙抃','宋','宋诗','song-poetry','','[]','江頭落寞窮冬日，天末崎嶇薄宦身。',64,'全唐诗/poet.song.19000.json','["江頭落寞窮冬日，天末崎嶇薄宦身。", "休問世途千態巧，且貪杯酒十分醇。", "顔間戚戚成何事，醉裏熙熙即是真。", "梅雪半殘烟柳吐，一番消息又青春。"]'),
('2001c280-28d5-45af-be5e-ceca5a2b4d2f','和十二弟揚臘月立春','趙抃','宋','宋诗','song-poetry','','[]','二十四日立春節，六七千里孤舟行。',64,'全唐诗/poet.song.19000.json','["二十四日立春節，六七千里孤舟行。", "呼兒倒酒迎春醉，忽爾持詩屬我賡。", "海上去年賓燕樂，江頭今歲客心情。", "興來極目尋春色，岸柳汀蕪綠未成。"]'),
('d2079bdb-62b4-4098-9910-8901de2ee7e8','除夜泊臨江縣言懷','趙抃','宋','宋诗','song-poetry','','[]','縣封蕭索楚江澄，旅況吟懷冷似冰。',64,'全唐诗/poet.song.19000.json','["縣封蕭索楚江澄，旅況吟懷冷似冰。", "漏促已交新歲鼓，酒蘭猶剪隔宵燈。", "立身從道思無愧，得路由機患不能。", "未報君恩踰四十，青春還是一番增。"]'),
('fd446cf8-ae74-425f-80b3-aac12e1babbc','泊巴陵聞曉角','趙抃','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','五更鐘後斗沈杓，畫角三番塞角調。',64,'全唐诗/poet.song.19000.json','["五更鐘後斗沈杓，畫角三番塞角調。", "青草湖平無俗籟，岳陽樓迥有寒飚。", "酒腸喚醒維舟靜，夢眼驚回去國遥。", "我愛清餘起傾耳，欲吟情思已飄飄。"]'),
('f9b11bb4-fceb-4ee5-9762-7a2ce504d959','憶輦下寄同年楊子卿','趙抃','宋','宋诗','song-poetry','','[]','一思平日禁城春，直上青霄步步雲。',64,'全唐诗/poet.song.19000.json','["一思平日禁城春，直上青霄步步雲。", "在月香名欣共得，掞天綵藻愧相聞。", "滿頭競插花千柄，沒案誰辭酒十分。", "蓮水今爲從事樂，伊予無復嘆離羣。"]'),
('ed0cb115-106c-4a7f-bb53-98c7e0f6f730','送交代楊推官','趙抃','宋','宋诗','song-poetry','','[]','三載從軍績用成，代還京闕黯離情。',64,'全唐诗/poet.song.19000.json','["三載從軍績用成，代還京闕黯離情。", "亭長且作班荆飲，江迥愁聞唱棹聲。", "前席去當回帝問，初筵今已號賓榮。", "交承參袂宜敦好，莫惜殷勤重報瓊。"]'),
('863562d9-9aa4-45fa-8c5b-1bbd12a9ca34','早霧','趙抃','宋','宋诗','song-poetry','','[]','山光全暝水光浮，數里霏霏曉未收。',64,'全唐诗/poet.song.19000.json','["山光全暝水光浮，數里霏霏曉未收。", "露彩乍凝迷漢殿，日華不透掩秦樓。", "豈饒文豹遲留隱，應有靈蛇取次遊。", "聖世妖氛已銷盡，結成佳氣滿南州。"]'),
('75e2b0c3-0793-4ac0-91c7-b4c7a7d1a3e6','寄里中親友','趙抃','宋','宋诗','song-poetry','','[]','記得城南數刻懽，破歡爲別淚闌干。',64,'全唐诗/poet.song.19000.json','["記得城南數刻懽，破歡爲別淚闌干。", "間關遠道初隨牒，寂寞長亭一據鞍。", "郊外此時涼葉亂，嶺頭平日臘梅殘。", "不辭頻寄南州信，草檄無功楯墨乾。"]'),
('6cd9d45a-b155-4e45-89c3-fdfdfb32d4d4','席上感別送桂倅','趙抃','宋','宋诗','song-poetry','','[]','照人冰骨是真仙，失臂江西僅十年。',64,'全唐诗/poet.song.19000.json','["照人冰骨是真仙，失臂江西僅十年。", "子擁倅車袍著茜，我趨賓席幕依蓮。", "今宵把酒方歡甚，明日班荆又黯然。", "八桂到須多假日，府中佳醑主公賢。"]'),
('db02babb-e294-4381-b969-2467926c6daa','和人清明有感','趙抃','宋','宋诗','song-poetry','','[]','湖外清明物態繁，曉林鶯舌鬭關關。',64,'全唐诗/poet.song.19000.json','["湖外清明物態繁，曉林鶯舌鬭關關。", "枉緣春意無時盡，自是人心不暫閒。", "舊隱東君曾藉草，新官南郡亦登山。", "滿頭花卉盈樽酒，且向東風一破顔。"]'),
('b14aa9bf-d699-48b1-9257-8d993ace9adc','和三兄得書喜授掌庾','趙抃','宋','宋诗','song-poetry','','[]','區區宦況遠南州，長得歸鴻與寄愁。',64,'全唐诗/poet.song.19000.json','["區區宦況遠南州，長得歸鴻與寄愁。", "已勝折腰嗟五斗，豈辭銜尾運千舟。", "冰含白玉期無累，路迫青雲愧可求。", "家有舊塤流韻遠，勉將文藻贊宸猷。"]'),
('923ee1a2-18a7-4657-bf59-63fd627181a9','贈狄節推','趙抃','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','唐嗣幾危國步艱，梁公忠力世難攀。',64,'全唐诗/poet.song.19000.json','["唐嗣幾危國步艱，梁公忠力世難攀。", "不辭鼎鑊君臣際，爲正朝廷子母間。", "今見裔孫仍白首，去從幕府綰青綸。", "旌賢有後十二代，轉覺勳名重泰山。"]'),
('8136f4ee-3e66-4f75-b6a1-995fa2360d5e','勸學示江原諸生','趙抃','宋','宋诗','song-poetry','','[]','古人名教自詩書，淺俗頹風好力扶。',64,'全唐诗/poet.song.19000.json','["古人名教自詩書，淺俗頹風好力扶。", "口誦聖賢皆進士，身爲仁義媽真儒。", "任從客笑原思病，莫管時譏孟子迂。", "通要設施窮要樂，不須隨世問榮枯。"]'),
('5663f1b4-dc99-450a-ab6a-3ec6ffae8f22','送何孟侯先生之平原','趙抃','宋','宋诗','song-poetry','','[]','束書携劍出西州，恩舊相歡事遠遊。',64,'全唐诗/poet.song.19000.json','["束書携劍出西州，恩舊相歡事遠遊。", "架上昔曾窮聖卷，幄中今好贊賓籌。", "也知賢帥須青眼，應念慈闈已白頭。", "到日欲憑歸信杳，寒鴻成陣叫清秋。"]'),
('7b7c571a-c187-45ad-862d-d9dbd79be518','題杜子美書室','趙抃','宋','宋诗','song-poetry','','[]','直將騷雅鎮澆淫，瓊貝千章照古今。',64,'全唐诗/poet.song.19000.json','["直將騷雅鎮澆淫，瓊貝千章照古今。", "天地不能籠大句，鬼神無處避幽吟。", "幾逃兵火覊危極，欲厚民生意思深。", "茅屋一間遺像在，有誰於世是知音。"]'),
('b1f8fcb9-7d08-4f57-ab0a-fbeadd50f3b5','春日雪雷並作','趙抃','宋','宋诗','song-poetry','','[]','東君新用少陽時，正月羣陰老未歸。',64,'全唐诗/poet.song.19000.json','["東君新用少陽時，正月羣陰老未歸。", "千里雪花鋪夜景，數聲雷鼓作春威。", "欲開桃李嗟寒勒，尚蟄龍蛇恨力微。", "一挫芳菲一驚物，惘然無處問天機。"]'),
('3c101e79-bed1-4c60-ac1a-6ff84911dacb','初入峽','趙抃','宋','宋诗','song-poetry','','[]','浹江初過三遊洞，天氣新調二月風。',64,'全唐诗/poet.song.19000.json','["浹江初過三遊洞，天氣新調二月風。", "樵戶人家隨處見，仙源雲路有時通。", "峯巒壓岸東西碧，桃李臨波上下紅。", "險磧惡灘知幾許，晚停征棹問漁翁。"]'),
('c7916d57-f8c8-4094-ac12-e368fdf37c64','過嶺回寄張景通先生示邑下同人','趙抃','宋','宋诗','song-poetry','','[]','二年官役愧能名，賢得斯人幸合并。',64,'全唐诗/poet.song.19000.json','["二年官役愧能名，賢得斯人幸合并。", "幾度孝廉交郡辟，一生文行出鄉評。", "君廬皂水江頭遠，我馬青泥嶺頂行。", "西首胡爲書以贈，欲持同邑寄諸生。"]'),
('5e539b35-314c-4581-a0df-abc569542dca','下牢津','趙抃','宋','宋诗','song-poetry','','[]','拖舟百丈苦攀躋，一過牢津恍似迷。',64,'全唐诗/poet.song.19000.json','["拖舟百丈苦攀躋，一過牢津恍似迷。", "花放亂紅迎彩旆，谷傳深響答鳴鼙。", "避人幽鳥凌雲噪，抱子驚猿走險啼。", "春岫重重春水綠，却疑身在武陵溪。"]'),
('95ee5512-21c6-4dce-b78d-78314657563d','同萬州相里殿丞遊溪西山寺','趙抃','宋','宋诗','song-poetry','','[]','使君呼客入山行，曉徑前驅照彩旌。',64,'全唐诗/poet.song.19000.json','["使君呼客入山行，曉徑前驅照彩旌。", "蠻女背樵巖側避，野僧携刺馬頭迎。", "千層雲水迷三峽，一鬨人烟認百城。", "樓閣憑餘清我聽，竹風蕭瑟澗泉鳴。"]'),
('adf08d35-12ea-44c1-82b0-108fdc2c5550','送黄賁赴渭州機宜','趙抃','宋','宋诗','song-poetry','','[]','我愧非才敢贈言，告新今幸接英躔。',64,'全唐诗/poet.song.19000.json','["我愧非才敢贈言，告新今幸接英躔。", "炎威滿路千山去，和氣流民百口傳。", "就捧絲綸天子命，到參帷幄主人賢。", "前籌要使邊陲靜，報德銘功願兩全。"]'),
('18f4b9ec-9470-4153-954a-563cb8ad8691','次韻張著作贈講禮孫秀才','趙抃','宋','宋诗','song-poetry','','[]','丈席橫經事講評，暫開雄辯五河傾。',64,'全唐诗/poet.song.19000.json','["丈席橫經事講評，暫開雄辯五河傾。", "十年素藴胸中吐，一日清風坐上生。", "諸子授來疑頓釋，先儒宗後業偏精。", "塵編古有多門學，今喜公能爲發明。"]'),
('2829b1dd-7ca4-4127-9cbe-180c9845b46e','酬楊鴻漸察判見寄','趙抃','宋','宋诗','song-poetry','','[]','進不驚人退不藏，朅來士術惠殊鄉。',64,'全唐诗/poet.song.19000.json','["進不驚人退不藏，朅來士術惠殊鄉。", "踈餘益信琴多樂，拙甚方虞錦重傷。", "顧我未能精俗事，感公偏遺好詩章。", "懷間得勝千金直，莫謂無人識夜光。"]'),
('70c5e190-8a66-42cb-8eab-c698f93e05fa','送崔度推官任滿還長安','趙抃','宋','宋诗','song-poetry','','[]','三歲西州此效官，幕中無事有賓歡。',64,'全唐诗/poet.song.19000.json','["三歲西州此效官，幕中無事有賓歡。", "瞻雲預喜長安近，歸騎還驚蜀道難。", "分袂天涯逢臘盡，入關時候正春寒。", "前途應念朋從意，回首秦亭一據鞍。"]'),
('92a0fb82-0ad7-4f98-aadd-fa4029074b6d','謁青城山','趙抃','宋','宋诗','song-poetry','','[]','背琴肩酒上青城，雲爲開收月爲明。',64,'全唐诗/poet.song.19000.json','["背琴肩酒上青城，雲爲開收月爲明。", "觀宿有詩招主簿，廬空無分遇先生。", "牆留古畫仙姿活，石載奇文俗眼驚。", "却念吾鄉山亦好，二年孤負爛柯行。"]'),
('67224e29-326e-41db-9a03-4510ef93d35b','次韻孫直言正旦馬上有感','趙抃','宋','宋诗','song-poetry','','[]','蜀國從官又見春，物華人事兩俱新。',64,'全唐诗/poet.song.19000.json','["蜀國從官又見春，物華人事兩俱新。", "已推才力多餘地，更賦詞章妙入神。", "要路我甘無俗迹，夷途公自有通津。", "逢時得用看施設，未止區區庇遠民。"]'),
('8a231d0d-2df6-46fc-ad8e-3f7c343e851d','次韻僉判俞尚都官寄兄君然中允致政','趙抃','宋','宋诗','song-poetry','','[]','勇退如公世少儔，樂天知命富春秋。',64,'全唐诗/poet.song.19000.json','["勇退如公世少儔，樂天知命富春秋。", "峩峩去得寒宮桂，泛泛歸乘雪水舟。", "舉目烟霞中有趣，無心軒冕外何求。", "引高應笑朝閨客，白首龍鐘未肯休。"]'),
('5b6e14ac-ef6f-4477-a105-a5eb83a0be5d','和淮上喜雪呈貫之','趙抃','宋','宋诗','song-poetry','','[]','落雪紛紛甚羽毛，相逢淮上繫輕舠。',64,'全唐诗/poet.song.19000.json','["落雪紛紛甚羽毛，相逢淮上繫輕舠。", "壓低酒力威稜健，助豁詩懷氣象豪。", "兩岸遠山供玉障，一天長水盡雲濤。", "歸歟喜見豐年瑞，南顧無煩帝力勞。"]'),
('ba15d189-b14a-4052-8404-e92f03320bc1','和潁川見徐學士','趙抃','宋','宋诗','song-poetry','','[]','臺閣官資屬二賢，歲寒相見潁流邊。',64,'全唐诗/poet.song.19000.json','["臺閣官資屬二賢，歲寒相見潁流邊。", "新醪喜泛千鐘蟻，永漏驚移數葉蓮。", "致主聖神躋舜禹，濟時功業企閎顛。", "故人清會俱高論，肯事狂歌學少年。"]'),
('be05d9d8-5c00-4083-a8b3-9b4dee035321','次韻范師道御史','趙抃','宋','宋诗','song-poetry','','[]','昔如李郭去登仙，今復東行並客船。',64,'全唐诗/poet.song.19000.json','["昔如李郭去登仙，今復東行並客船。", "夾岸雲山千里路，滿襟風月九秋天。", "持杯旋斫桐江鱠，覓句頻賡蜀國箋。", "君到七閩佳麗地，荔枝紅發欲殷然。"]'),
('aad4aa78-72db-4081-a87d-5c88d72b34d9','和見雪','趙抃','宋','宋诗','song-poetry','','[]','驚怪窮冬百物繁，落梅狂絮逐風翻。',64,'全唐诗/poet.song.19000.json','["驚怪窮冬百物繁，落梅狂絮逐風翻。", "酒無戈甲爭酣戰，詩似波瀾競討源。", "且卸帆檣隈斷岸，好開屏嶂畫孤村。", "知音若問陽春曲，待把琴調細細論。"]'),
('f88c350d-87e6-45a7-a2d7-09ec7ff664ca','新定即事','趙抃','宋','宋诗','song-poetry','','[]','泉高終日聽潺湲，花草纔佳爛漫看。',64,'全唐诗/poet.song.19000.json','["泉高終日聽潺湲，花草纔佳爛漫看。", "言念君恩得私請，敢於身計學偷安。", "開元刺史名千古，東漢先生釣一竿。", "賢迹勉尋余自愧，牧民猶带觸邪冠。"]'),
('f8cb5824-7778-48d0-8305-c858e9e32862','初到睦州寄毗陵范御史','趙抃','宋','宋诗','song-poetry','','[]','前日鵷鴻接羽儀，平生風誼見施爲。',64,'全唐诗/poet.song.19000.json','["前日鵷鴻接羽儀，平生風誼見施爲。", "蘇臺薄暮分襟後，嚴瀨逢佳佇立時。", "歸棹豈能忘舊里，去筒猶未寄新詩。", "寒泉繞石山環坐，一弄南風慰所思。"]'),
('fedf64fd-f64f-4b74-9ba8-a28710fafb30','和范都官述懷','趙抃','宋','宋诗','song-poetry','','[]','人爲閒郡我爲榮，僚友多歡事少生。',64,'全唐诗/poet.song.19000.json','["人爲閒郡我爲榮，僚友多歡事少生。", "詩裏江山今共樂，籍中龍虎舊傳名。", "逢時自可青雲致，喜老休將白髮輕。", "垂世功名期力到，上方求治急材英。"]'),
('5ed432ea-0e94-4a20-ae14-ecaafa467684','勉郡學諸生','趙抃','宋','宋诗','song-poetry','','[]','桐江爲守愧顓蒙，來喜衣冠好士風。',64,'全唐诗/poet.song.19000.json','["桐江爲守愧顓蒙，來喜衣冠好士風。", "勸學重思唐吏部，教人多謝漢文翁。", "濟時事業期深得，落筆詞章貴不空。", "道有未充須自立，莫將榮悴汩於中。"]'),
('647607c4-dbef-4feb-bd16-3a4ca0bbb343','和彥塗田曹見寄','趙抃','宋','宋诗','song-poetry','','[]','自喜還家入郡閎，久無書簡到京城。',64,'全唐诗/poet.song.19000.json','["自喜還家入郡閎，久無書簡到京城。", "棊觀每笑機心巧，琴斷還憂曲意生。", "厚祿萬鐘身外薄，冷泉千尺耳邊清。", "來詩詠歎陶然樂，疑夢鈞天奏九成。"]'),
('460892af-e5c9-454b-8796-3ba84a19ea0a','送范都官','趙抃','宋','宋诗','song-poetry','','[]','莫惜芳樽細細斟，還臺詩句滿離襟。',64,'全唐诗/poet.song.19000.json','["莫惜芳樽細細斟，還臺詩句滿離襟。", "海潮風駕漫幽渚，鄉岫雲開認故林。", "八月氣涼歸棹快，三年恩厚在人深。", "紫宸曉拜天光近，宜有封囊悟主心。"]'),
('fac97575-b69d-45ea-9489-17d5db3a3837','和前人重九日寄','趙抃','宋','宋诗','song-poetry','','[]','丁字溪流甚箭奔，忍看行色夕陽村。',64,'全唐诗/poet.song.19000.json','["丁字溪流甚箭奔，忍看行色夕陽村。", "三吳望遠迷烟棹，九日登高泥酒樽。", "詩得瓊瑶今有意，感充懷抱更無言。", "歸歟一曲桐江好，西北通宵欲夢魂。"]'),
('41bd5091-34f8-4080-b3ee-976cb02fb72b','新定獲龜繼得梓漕携之赴官','趙抃','宋','宋诗','song-poetry','','[]','買自桐江數歲前，潔中輕外欲巢蓮。',64,'全唐诗/poet.song.19000.json','["買自桐江數歲前，潔中輕外欲巢蓮。", "同麟薦世宜爲瑞，邀鶴尋真定得仙。", "肯示吉兇貽後悔，祇隨呼吸到長年。", "主人幸不煩供養，俾託軺車看兩川。"]'),
('d1757fb1-bcc2-4076-940f-07449fa4ab2d','過子陵故祠','趙抃','宋','宋诗','song-poetry','','[]','帝念先生素所親，殊恩終不顧絲綸。',64,'全唐诗/poet.song.19000.json','["帝念先生素所親，殊恩終不顧絲綸。", "圖勳恥預凌烟像，辭貴甘爲擲釣人。", "雲水孤高教適意，俗風奔競使還淳。", "如今丘壑無遺士，天子思賢號聖神。"]'),
('71c28d93-6086-463d-81c3-f3d2100de71b','次韻石溫之都官見贈','趙抃','宋','宋诗','song-poetry','','[]','桐江得請上恩榮，孤士慚無善可旌。',64,'全唐诗/poet.song.19000.json','["桐江得請上恩榮，孤士慚無善可旌。", "望闕天光驚已遠，到家春色喜先迎。", "雲邊舊念青山隱，鑑裏新逢白髮生。", "多謝賢朋遺佳句，重於珍璧價連城。"]'),
('60cdae82-e4cd-40ff-860a-43d9e418a42e','憶松溪三兄縣尉','趙抃','宋','宋诗','song-poetry','','[]','憶別揚州六月中，倏今三已換春冬。',64,'全唐诗/poet.song.19000.json','["憶別揚州六月中，倏今三已換春冬。", "烟帆去蜀七千里，雲嶺瞻閩幾萬重。", "莫爲沈迷嗟下邑，要將清白廣吾宗。", "天遥最是書難得，早倩來鴻寄一封。"]'),
('0b0e835e-d227-4960-9ad0-d1b79400e0a4','次韻鄭琰登睦州高峯塔','趙抃','宋','宋诗','song-poetry','','[]','舊迹蒙君麗句誇，昔同峯頂躡雲霞。',64,'全唐诗/poet.song.19000.json','["舊迹蒙君麗句誇，昔同峯頂躡雲霞。", "逢秋謁寺留詩筆，薄暮歸鞍照月華。", "旋酌香醪浮甕蟻，鬭烹新茗滿甌花。", "心餘更作儒官會，帳內諸生擁絳紗。"]'),
('588aeb99-ce4d-4c28-9648-a72faa98c2b2','得守虔州過鄉邦贈別衢州太守高賦同年','趙抃','宋','宋诗','song-poetry','','[]','俞請分符入贛川，過家爲幸獲於天。',64,'全唐诗/poet.song.19000.json','["俞請分符入贛川，過家爲幸獲於天。", "桂宮舊有同年契，梓里今逢太守賢。", "釃酒殷勤供去帳，解囊分耀貯離篇。", "曉來頗覺思君夢，烟水蒼茫隔畫船。"]'),
('941267f9-ba92-4bf9-9613-ba3ad4409acb','守虔過家登高齋即事','趙抃','宋','宋诗','song-poetry','','[]','舊里徘徊忽四旬，高齋高勝足懽忻。',64,'全唐诗/poet.song.19000.json','["舊里徘徊忽四旬，高齋高勝足懽忻。", "當軒曉看山橫黛，負郭秋成稼覆雲。", "酌酒屢邀朋契樂，弄琴真與俗喧分。", "虔州莫訝遲遲去，鄉便恩榮荷聖君。"]'),
('0d6f7d1b-18a2-4fad-887b-4249b6819535','寄永倅周敦頤虞部','趙抃','宋','宋诗','song-poetry','','[]','君去濂溪湖外行，倅藩仍喜便鄉程。',64,'全唐诗/poet.song.19000.json','["君去濂溪湖外行，倅藩仍喜便鄉程。", "九疑南向參空碧，二水秋臨徹底清。", "詩筆不閒真吏隱，訟庭無事洽民情。", "霜鴻已到衡陽轉，遠緒憑誰數寄聲。"]'),
('19cc494f-be40-4fb0-8483-c08461ae5c1a','虔州即事','趙抃','宋','宋诗','song-poetry','','[]','君恩山重若爲酬，補郡都忘樂與憂。',64,'全唐诗/poet.song.19000.json','["君恩山重若爲酬，補郡都忘樂與憂。", "惶恐灘長從險絕，鬰孤臺迥足觀遊。", "贛川在昔名難治，鈴閤于今幸少休。", "人謂闊疎予自喜，遠民安堵更何求。"]'),
('9e618bc8-f638-42cc-a98f-554dc93bb60d','次韻何若谷都官燈夕','趙抃','宋','宋诗','song-poetry','','[]','千門燈燭事遨遊，車馬通宵不暫休。',64,'全唐诗/poet.song.19000.json','["千門燈燭事遨遊，車馬通宵不暫休。", "幸免烟氛遮皓月，任隨笳鼓雜鳴騶。", "金壺漏下丁丁永，玉斝霞生灧灧流。", "帝澤遠臨人鼓腹，贛川宜有太平謳。"]'),
('ad3de640-7e20-4b1d-89db-8326c5a4a362','次韻徐師回殿丞捧詔亭聽琴','趙抃','宋','宋诗','song-poetry','','[]','訟缿無譁去訪真，並遊僚友若天倫。',64,'全唐诗/poet.song.19000.json','["訟缿無譁去訪真，並遊僚友若天倫。", "庭存列宿仙壇古，堂啟先生詔墨新。", "膝上揮絃清度曲，席間傾耳靜留神。", "泠泠不斷綿綿意，追想南風解慍人。"]'),
('32ecc2c9-8280-4384-956b-1e006c33473f','寄知福州范師道龍圖','趙抃','宋','宋诗','song-poetry','','[]','十年游霧入蘭薰，本末聊同出處均。',64,'全唐诗/poet.song.19000.json','["十年游霧入蘭薰，本末聊同出處均。", "五嶺昔將巴蜀遠，七閩今與贛川隣。", "雪中始見松難改，火後須知玉是真。", "事業他時公自任，致君堯舜澤吾民。"]'),
('9e7fff20-5fcf-4cca-9ab8-69a0266b011c','次韻何若谷寒食燕集','趙抃','宋','宋诗','song-poetry','','[]','雨過江城絕點塵，清明佳節正千門。',64,'全唐诗/poet.song.19000.json','["雨過江城絕點塵，清明佳節正千門。", "舞香撲坐花新戴，歌響盤雲曲旋翻。", "幾欲爲春留日馭，直須同俗醉衢樽。", "因思老氏登臺樂，若此斯民未足論。"]'),
('b892e865-1bcf-4995-852b-6c4737638f61','次韻錢顗喜雨','趙抃','宋','宋诗','song-poetry','','[]','山川靈秀降豐穰，十里油雲澤我疆。',64,'全唐诗/poet.song.19000.json','["山川靈秀降豐穰，十里油雲澤我疆。", "爲叩明神虞歲旱，故飄甘澤助春陽。", "征人共解江頭纜，遊女爭誇陌上桑。", "令尹愛民形喜色，作詩先已報豐祥。"]'),
('219402b7-ce7a-4a9a-9ad3-fe50b9d8a97d','次何若谷上巳遊江','趙抃','宋','宋诗','song-poetry','','[]','祓禊追修宴集開，山川聊爲霽風雷。',64,'全唐诗/poet.song.19000.json','["祓禊追修宴集開，山川聊爲霽風雷。", "衣冠愷樂觴傳羽，旗鼓號呶笛弄梅。", "畫鷁穩移隨岸曲，珍禽驚避逐波頹。", "百城錦繡人如織，笑看使君乘興來。"]'),
('de786c5b-e1f1-4f32-b022-83d8412626a7','次韻錢顗見贈入學聽講','趙抃','宋','宋诗','song-poetry','','[]','文翁治蜀澤民深，贛守無堪愧士林。',64,'全唐诗/poet.song.19000.json','["文翁治蜀澤民深，贛守無堪愧士林。", "長育務先庠序教，講磨思見聖賢心。", "今茲未肯孤毫善，學者尤宜念寸陰。", "三百餘篇金石奏，席間願聽得遺音。"]'),
('f35e3b9b-1b0e-48b8-81b1-51a85d4eac40','次韻何若谷寄提刑蔡挺','趙抃','宋','宋诗','song-poetry','','[]','遠俗斯年荷德豐，一麾烏足滯才雄。',64,'全唐诗/poet.song.19000.json','["遠俗斯年荷德豐，一麾烏足滯才雄。", "朝簽寄任非輕外，聖詔丁寧果發中。", "却念松楸還里閈，再馳牛犢懇天聰。", "只應未遂歸歟興，江右澄清已望風。"]'),
('05a0d283-e014-4ced-a211-7e94875bb7ae','次韻楚守孫直言職方見寄','趙抃','宋','宋诗','song-poetry','','[]','間關來贛會年豐，十里農桑畫障中。',64,'全唐诗/poet.song.19000.json','["間關來贛會年豐，十里農桑畫障中。", "雨足山川多秀氣，暑消臺閣有清風。", "人驚地遠還同近，誰道江西不似東。", "琴酒從容隨分樂，敢將身計事怱怱。"]'),
('caed2015-a7d4-488f-b744-b7bccb293fbf','次韻廣東轉運董儀職方同年見寄','趙抃','宋','宋诗','song-poetry','','[]','贛守無堪出榜中，日聞將漕稱才雄。',64,'全唐诗/poet.song.19000.json','["贛守無堪出榜中，日聞將漕稱才雄。", "感公迢遞詩筒至，謂我優游訟缿空。", "高會正遥千障月，羈懷聊寄七絃風。", "何時把酒朋從樂，也待醒狂學次公。"]'),
('0ddbd458-dc5b-42db-949c-0f02eeb39767','次韻黄伯度虞部見贈','趙抃','宋','宋诗','song-poetry','','[]','念昔相逢向上方，別來驚已換星霜。',64,'全唐诗/poet.song.19000.json','["念昔相逢向上方，別來驚已換星霜。", "夢回半是烟波阻，詩寄全篇篋笥光。", "近喜歲豐無劇訟，更多雨足壓驕陽。", "施爲自顧如何爾，鳧鶴奚煩問短長。"]'),
('d96e4b15-89a3-4c46-afed-29c03e5b4d8f','聞杜植移使湖南','趙抃','宋','宋诗','song-poetry','','[]','去歲南來幸守麾，故人江上喜新眉。',64,'全唐诗/poet.song.19000.json','["去歲南來幸守麾，故人江上喜新眉。", "十分勸我流霞酒，一曲聽公白雪詞。", "此後拙疎真有賴，而今談笑杳無涯。", "驚聞擁節重湖去，憑仗西風寄所思。"]'),
('0aaa12aa-8f49-4cb4-a22e-3ea1fe520754','留題悅亭因簡何若谷都官','趙抃','宋','宋诗','song-poetry','','[]','翠栢環庭數畝間，蕭疎仍是枕江干。',64,'全唐诗/poet.song.19000.json','["翠栢環庭數畝間，蕭疎仍是枕江干。", "都如君子憐松茂，半爲主人諳歲寒。", "素壁留詩多健羨，畫船過里暫盤桓。", "因公此景予心喜，亦有高齋待掛冠。"]'),
('587b1eef-ed33-4a54-85b4-0c284d4ccb77','送前人過鄉還朝','趙抃','宋','宋诗','song-poetry','','[]','景祐賢科昔共登，長沙賓佐復交承。',64,'全唐诗/poet.song.19000.json','["景祐賢科昔共登，長沙賓佐復交承。", "三千里外今同郡，二十年前舊得朋。", "贛水帆檣驚遠別，玉峯欄檻到先憑。", "朝廷正是求材日，欲戀仙鄉算未能。"]'),
('68e85ff1-539f-4504-8d23-e56c15a0de03','次韻董儀都官見贈','趙抃','宋','宋诗','song-poetry','','[]','海陵余昔嗣英僚，舊尹咨新治有條。',64,'全唐诗/poet.song.19000.json','["海陵余昔嗣英僚，舊尹咨新治有條。", "此別風波嗟各路，但聞名譽籍當朝。", "美夫郡接瀕江地，幸矣民多樂歲謠。", "南國故人千里隔，舉頭雲嶺鬰岧嶢。"]'),
('b444ed0d-0a00-4a9f-8952-f77f1870d660','同周敦頤國博遊馬祖山','趙抃','宋','宋诗','song-poetry','','[]','曉出東江向近郊，舍車乘棹復登高。',64,'全唐诗/poet.song.19000.json','["曉出東江向近郊，舍車乘棹復登高。", "虎頭城裏人烟闊，馬祖岩前氣象豪。", "下指正聲調玉軫，放懷雄辯起雲濤。", "聯鑣歸去尤清樂，數里松風聳骨毛。"]'),
('322ccd26-f227-4919-a999-2b0a66257e10','南康公餘有作','趙抃','宋','宋诗','song-poetry','','[]','道未中充氣未閎，聖神遭遇本寒生。',64,'全唐诗/poet.song.19000.json','["道未中充氣未閎，聖神遭遇本寒生。", "廷中入愧言無補，嶺下來欣治有名。", "世路計身焉用巧，古人逢物要推誠。", "從容章貢臺前望，贛水秋天一樣清。"]'),
('56469e60-bc17-4aa7-9b80-0f2a76995f70','次韻周敦頤國博見贈','趙抃','宋','宋诗','song-poetry','','[]','蜀川一見無多日，潮水重來復後時。',64,'全唐诗/poet.song.19000.json','["蜀川一見無多日，潮水重來復後時。", "古栢根深容不變，老桐音淡世難知。", "觀遊邂逅須同樂，離合參差益再思。", "籬有黄花樽有酒，大家尋賞莫遲疑。"]'),
('9c1672bc-0984-4cb2-b03c-c6251e8381e8','和虔守任滿前人香林寺錢別','趙抃','宋','宋诗','song-poetry','','[]','顧我入趨堯闕去，煩公出餞贛江頭。',64,'全唐诗/poet.song.19000.json','["顧我入趨堯闕去，煩公出餞贛江頭。", "爲逢蕭寺千山好，不惜蘭船一日留。", "清極往來無俗論，道通何處有離憂。", "分携豈用驚南北，水闊風高萬里秋。"]'),
('9fc6b392-a3e8-482a-b121-9302c13001a3','次韻衢守陳守言職方招遊爛柯山','趙抃','宋','宋诗','song-poetry','','[]','賢侯九日去尋山，牽俗無由得附攀。',64,'全唐诗/poet.song.19000.json','["賢侯九日去尋山，牽俗無由得附攀。", "換世昔傳仙局久，登高今喜使車還。", "平原豐稔農歡勸，犴獄空虛吏放閒。", "從此爛柯光價起，爲留佳句落人寰。"]'),
('b868ae5e-873e-4016-8129-df6c7fc7e1a4','按獄眉山舟行','趙抃','宋','宋诗','song-poetry','','[]','携琴曉出錦官城，千里秋原一望平。',64,'全唐诗/poet.song.19000.json','["携琴曉出錦官城，千里秋原一望平。", "放舸急流身覺快，披雲孤嶼眼增明。", "農田雨後畦畦綠，漁笛風前曲曲清。", "訊獄遠邦先滌慮，卹哉休戚在民情。"]'),
('2d01f67b-59e1-4b55-9658-64373658abe3','次韻蔡挺提刑出巡將還','趙抃','宋','宋诗','song-poetry','','[]','榜契推誠積有年，天淵冲躍見魚鳶。',64,'全唐诗/poet.song.19000.json','["榜契推誠積有年，天淵冲躍見魚鳶。", "方欣友會爲愚幸，又辱詩情著意緣。", "庾嶺棠陰留遠俗，贛川舟御若飛仙。", "明朝預想陪高誼，滿座清風盛暑天。"]'),
('74995e27-443b-4fd3-9ec6-f77190ea95ba','會新都孫直言于成都','趙抃','宋','宋诗','song-poetry','','[]','同志同年分若親，幸從天與豈關人。',64,'全唐诗/poet.song.19000.json','["同志同年分若親，幸從天與豈關人。", "交情舊別江鄉晚，客宦今逢蜀國春。", "酌酒强論賢否事，畏塗休說利名身。", "鄰封却喜無多遠，來往詩筒莫厭頻。"]'),
('1a74a621-dc1a-4f0b-b030-ca5a0ff5cd0b','題三泉縣龍洞','趙抃','宋','宋诗','song-poetry','','[]','蜀道羣山盡可名，更逢佳處愈神清。',64,'全唐诗/poet.song.19000.json','["蜀道羣山盡可名，更逢佳處愈神清。", "初疑谷口連雲掩，入見天心滿洞明。", "怪石磷磷蹲虎豹，飛泉落落碎瑶瓊。", "嵬巔別有神仙路，又得攀躋向上行。"]'),
('ed1bc097-8c0e-4067-8219-e0a1e43eab3d','成都西樓','趙抃','宋','宋诗','song-poetry','','[]','多暇朱欄倚望頻，遠雲開即見峨岷。',64,'全唐诗/poet.song.19000.json','["多暇朱欄倚望頻，遠雲開即見峨岷。", "昔賢初盡經營力，今我獨爲優幸人。", "勝閣簾高惟掩雨，老臺民樂只登春。", "爭如蜀國西樓好，四序風光日日新。"]'),
('13a076f9-1623-47d4-be07-c87b89726868','張公詠二月二日始遊江以集觀者韓公絳因創樂俗亭爲駐車登舟之所','趙抃','宋','宋诗','song-poetry','','[]','長橋東畔尼朱輪，畫棟雕欄錦水濱。',64,'全唐诗/poet.song.19000.json','["長橋東畔尼朱輪，畫棟雕欄錦水濱。", "子美浮槎傳大句，乖崖遊棹看芳春。", "樽罍泛泛留佳客，鼓吹喧喧樂遠人。", "夾岸香風十餘里，晚隨和氣入城闉。"]'),
('b809ad1c-c7ee-48f1-a9c6-633b1dce112c','和交代韓公絳端明別後見寄','趙抃','宋','宋诗','song-poetry','','[]','關山晴曉過綿州，兩蜀人思惠愛稠。',64,'全唐诗/poet.song.19000.json','["關山晴曉過綿州，兩蜀人思惠愛稠。", "去路旌麾朝日下，駕空橋棧接雲頭。", "初觀妙句離懷釋，似酌清泉渴恙瘳。", "孤緒摇摇更東望，西樓千尺止三休。"]'),
('89ad5fdd-0ef6-4ddf-a195-24f773b1479d','寄謝蒙州守周源屯田','趙抃','宋','宋诗','song-poetry','','[]','念公別後固依然，蜀距炎方里數千。',64,'全唐诗/poet.song.19000.json','["念公別後固依然，蜀距炎方里數千。", "劍棧過來纔一月，詩筒傳得已三篇。", "胸藏忠誼堅於石，口吐文章湧似泉。", "何日解符還闕去，如今朝野不遺賢。"]'),
('c905f26d-d12f-4390-a7bf-c3adfa3b0010','運使王舉元兵部因談道惠詩次韻','趙抃','宋','宋诗','song-poetry','','[]','初窮文字作階緣，若得嘉魚即棄筌。',64,'全唐诗/poet.song.19000.json','["初窮文字作階緣，若得嘉魚即棄筌。", "堪笑蚊蠅驚八月，豈知龜鶴壽千年。", "無心是處非關境，有命由來不在天。", "自古君臣悉功行，不然終未到神仙。"]'),
('45f761dc-fc2e-47c0-bd7f-d12ba2e6a279','送前人還都','趙抃','宋','宋诗','song-poetry','','[]','蜀道將輸茂績成，遠人安靖歲豐盈。',64,'全唐诗/poet.song.19000.json','["蜀道將輸茂績成，遠人安靖歲豐盈。", "發施號令岷山峻，除去貪婪錦水清。", "一旦賜環來日下，九秋乘驛度雲程。", "朝廷禮盛榮歸好，親見吾皇講太平。"]'),
('3f6cbe0e-d701-48a6-8d27-4c2d2edf20a3','榮諲學士按部未還因寄','趙抃','宋','宋诗','song-poetry','','[]','欲見遐陬盡樂康，沈黎回即按嘉陽。',64,'全唐诗/poet.song.19000.json','["欲見遐陬盡樂康，沈黎回即按嘉陽。", "尋山舉屐三峨峻，度嶺驅車九折長。", "塢栢正宜寒後悅，驛梅多向臘前芳。", "錦川遨樂春期近，早著鞭來入醉鄉。"]'),
('de9d15da-442a-454d-af8e-2d6bb6043eee','題天彭鮑郎中南樓','趙抃','宋','宋诗','song-poetry','','[]','彭門於蜀最無雙，人悅南樓重歎降。',64,'全唐诗/poet.song.19000.json','["彭門於蜀最無雙，人悅南樓重歎降。", "㶁㶁鳴泉潄金玉，森森佳木擁旌幢。", "仙飚出洞清來坐，巒雪排巖冷透窗。", "太守瞻雲日登向，巴江迢遞隔吳江。"]'),
('d8e2c3be-7cc6-41e8-9432-5dd064648e96','贈玉局李垂應太師','趙抃','宋','宋诗','song-poetry','','[]','坐觀山水地幽清，恬淡冲虛樂性情。',64,'全唐诗/poet.song.19000.json','["坐觀山水地幽清，恬淡冲虛樂性情。", "跡混光塵宗老氏，術通仙俗似君平。", "欣逢真侶論根本，恥向權門叩利名。", "濟世金丹得傳授，先生高隱在青城。"]'),
('2b47aea8-e687-486b-9acf-1693eff18e78','成都轉運翠錦亭','趙抃','宋','宋诗','song-poetry','','[]','羣木依亭翠錦開，主人吟燕日徘徊。',64,'全唐诗/poet.song.19000.json','["羣木依亭翠錦開，主人吟燕日徘徊。", "青幃照坐初疑染，紺障鋪簷不是裁。", "蟻酌對傾金斝滿，鴨頭前引五溪來。", "勸公勿用遲留賞，早暮須賢即召迴。"]'),
('b3d5cd18-4040-4d36-a9d9-e96c40663722','提刑邢夢臣度支連理荔枝','趙抃','宋','宋诗','song-poetry','','[]','嘉陽天遠被薰風，荔子呈祥郡館中。',64,'全唐诗/poet.song.19000.json','["嘉陽天遠被薰風，荔子呈祥郡館中。", "庇本莫將慈竹較，媚時寧與瑞蓮同。", "並柯晝聳烟光動，異幹霄空月影通。", "奇木幸逢真賞筆，誰誇丹實一庭紅。"]'),
('a480afb0-639e-4eaf-9484-dda805948ec4','送蘇宷刑部赴召','趙抃','宋','宋诗','song-poetry','','[]','有詔西來亟治裝，古今威望重癡牀。',64,'全唐诗/poet.song.19000.json','["有詔西來亟治裝，古今威望重癡牀。", "不煩右蜀專飛輓，直爲南臺正紀綱。", "豸角風霜秋肅肅，鶴形環珮曉鏘鏘。", "忠賢得用朝廷美，禮法匡時事業光。"]'),
('68848ed9-2d1f-48d0-a5f0-26501dda11ca','次韻張唐民都官道中有懷','趙抃','宋','宋诗','song-poetry','','[]','言念離情積有年，朋心金石孰爲堅。',64,'全唐诗/poet.song.19000.json','["言念離情積有年，朋心金石孰爲堅。", "殿廬未入承明直，郡閣先傳太守賢。", "且向天涯行五馬，不妨神液溉三田。", "聞公比悟莊生指，於此紛華已泊然。"]'),
('574b40f5-2f4a-4fc8-8c33-c3b74112d271','再經江原縣有作','趙抃','宋','宋诗','song-poetry','','[]','徙命乘軺入錦川，岷沱寒霽好人烟。',64,'全唐诗/poet.song.19000.json','["徙命乘軺入錦川，岷沱寒霽好人烟。", "彈琴舊治俄三政，持斧重來未十年。", "欲去民憂同樂只，敢孤朝寄獨恬然。", "邑城東望踟躕久，魏闕天遥里數千。"]'),
('ecc2d236-ab8f-4a3a-92fa-97f9dee0f34b','招運判霍交回轅','趙抃','宋','宋诗','song-poetry','','[]','自邛之雅漸高丘，所過從容盡勝遊。',64,'全唐诗/poet.song.19000.json','["自邛之雅漸高丘，所過從容盡勝遊。", "白鶴山頭雲裏寺，金雞關外雨中州。", "公今南按蠲民瘼，歲已西成輟上憂。", "江瀆荷花開似錦，且同歸去採蓮舟。"]'),
('c752f030-60de-473a-b4b5-0e6d57df0a11','遊青城山','趙抃','宋','宋诗','song-poetry','','[]','山到青城險復奇，地平孤起壓坤維。',64,'全唐诗/poet.song.19000.json','["山到青城險復奇，地平孤起壓坤維。", "直通一徑岧嶢上，俯覺千山迤邐卑。", "爲訪隱賢題古壁，因觀幽境過荒祠。", "白雲深處逢巖老，醉酌松醪滿鬢絲。"]'),
('76b0e403-23b6-4d8a-ae62-31448b1548c7','題張唐英祕校桂香亭','趙抃','宋','宋诗','song-poetry','','[]','月中新得桂香清，歸向斯亭立美名。',64,'全唐诗/poet.song.19000.json','["月中新得桂香清，歸向斯亭立美名。", "作賦仗前登第好，拜恩堂下到家榮。", "曉羞蘭饍親心樂，春照藍袍俗眼驚。", "跬步不宜輕自待，青雲岐路坦然平。"]'),
('7feacf55-3631-4d6c-a7ab-9744511f5fbd','送蜀倅楊瑜東歸','趙抃','宋','宋诗','song-poetry','','[]','倅郡優游得治聲，代還東出錦官城。',64,'全唐诗/poet.song.19000.json','["倅郡優游得治聲，代還東出錦官城。", "一州和氣三年迹，萬里寒威十月行。", "江外預通鄉信喜，仗前歸拜帝恩榮。", "逢今僉用良材日，好使明堂大厦成。"]'),
('772a9de8-d5ce-421d-ad2c-f9ae754608af','送張唐英司理赴渝州','趙抃','宋','宋诗','song-poetry','','[]','不用咨嗟愴別離，聽吾持酒祝公詞。',64,'全唐诗/poet.song.19000.json','["不用咨嗟愴別離，聽吾持酒祝公詞。", "少年得第人誰似，純孝於親里共推。", "姓字已通丞相夢，才名須結聖君知。", "嶽情要在平生允，容駟高門自有期。"]'),
('419d9877-de29-4c9e-afe0-a37528fd1465','題運判霍交瞻岷閣','趙抃','宋','宋诗','song-poetry','','[]','閣外風光滿意新，諸公同上看梁岷。',64,'全唐诗/poet.song.19000.json','["閣外風光滿意新，諸公同上看梁岷。", "蜀天六月雲如火，夷界千峯雪似銀。", "巖叟近傳多得壽，羽人曾此數登真。", "夫君不爲神仙事，早暮孜孜澤遠民。"]'),
('edef29d6-0fa3-47c6-bca4-25db5bf60523','送張唐英太博','趙抃','宋','宋诗','song-poetry','','[]','蜀卿榮耀跂光塵，忠孝兼全到古人。',64,'全唐诗/poet.song.19000.json','["蜀卿榮耀跂光塵，忠孝兼全到古人。", "萬乘累年聞奏牘，雙親同日拜恩綸。", "志侔鸞鵠風儀遠，文得岷峨氣象新。", "聖政於今急賢者，肯教留滯蜀江濱。"]'),
('987bbd87-57d9-45d1-9ecf-d90e77687911','寄酬梓路運使趙諴度支','趙抃','宋','宋诗','song-poetry','','[]','東川使者駐前旌，西念鄰邦眷舊情。',64,'全唐诗/poet.song.19000.json','["東川使者駐前旌，西念鄰邦眷舊情。", "屐齒峻登雲頂寺，詩筒遥寄錦官城。", "民間樂矣原田稔，境上熙然嶽犴平。", "聞說提封足和氣，我心懽快爲宗盟。"]'),
('181ff2f9-3f21-4333-a838-79a7c3c4574a','次韻蔡仲偃都官南歸留別','趙抃','宋','宋诗','song-poetry','','[]','留詩爲別重依依，春浪桃花曉弄暉。',64,'全唐诗/poet.song.19000.json','["留詩爲別重依依，春浪桃花曉弄暉。", "柯嶺崢嶸何處所，蘭橈安穩送將歸。", "與君志有雲泉約，顧我身無羽翼飛。", "浮石仙今遺跡在，吾廬江畔憶漁磯。"]'),
('b08d6387-16ba-4a01-a1b0-9a8f59c1a03f','次韻孫直言書懷','趙抃','宋','宋诗','song-poetry','','[]','四十驚霜入鬢新，道光休歎守官貧。',64,'全唐诗/poet.song.19000.json','["四十驚霜入鬢新，道光休歎守官貧。", "榮塗漸快青雲步，寵祿方酬白首親。", "此日文詞誇世俗，異時才術濟吾民。", "功名立去何憂晚，要得相期到古人。"]'),
('f8bb1058-b3bf-4977-971b-608cd4431d2e','青州勸學','趙抃','宋','宋诗','song-poetry','','[]','學欲精勤志欲專，魯門高第美淵騫。',64,'全唐诗/poet.song.19000.json','["學欲精勤志欲專，魯門高第美淵騫。", "文章行業初由己，富貴榮華只自天。", "一簣爲山先聖戒，寸陰輕璧古人賢。", "沂公庠序親模範，今日諸生爲勉旃。"]'),
('6281f243-18ba-4e97-973c-bfc231aa7d0c','述懷','趙抃','宋','宋诗','song-poetry','','[]','三十年前一布衣，爛柯山下驟鳴飛。',64,'全唐诗/poet.song.19000.json','["三十年前一布衣，爛柯山下驟鳴飛。", "夢刀蜀國青天上，衣錦杭州白晝歸。", "曾預機衡蒙帝眷，自同葵藿向晨暉。", "東齋事少愚知幸，終日平嵐面翠微。"]'),
('7c4ea9ac-04ea-4e44-9c5f-5163019dcdfa','夏末喜雨','趙抃','宋','宋诗','song-poetry','','[]','靈湫祈禱酌樽罍，稽首精神敢惰哉。',64,'全唐诗/poet.song.19000.json','["靈湫祈禱酌樽罍，稽首精神敢惰哉。", "民意欲從千里雨，天威爲動一聲雷。", "預期多稼如雲去，且免飛蝗入境來。", "酷暑驟祛還自喜，清風朝夕上樓臺。"]'),
('737f5871-c51c-4b45-a567-c3765c056117','次韻孔宗翰水磨園亭','趙抃','宋','宋诗','song-poetry','','[]','南洋一派通機磨，更引餘波遶曲池。',64,'全唐诗/poet.song.19000.json','["南洋一派通機磨，更引餘波遶曲池。", "高柳碧陰無酷暑，小蓮紅老惜芳時。", "臨流共賞休辭醉，按轡重來未可期。", "從此邦人爲勝事，范公亭榭孔君詩。"]'),
('481bbb47-597f-40dc-aed5-138f9104fd41','次韻王居卿提刑遊雲門山','趙抃','宋','宋诗','song-poetry','','[]','千里崢嶸到忽平，兀然如覺夢魂醒。',64,'全唐诗/poet.song.19000.json','["千里崢嶸到忽平，兀然如覺夢魂醒。", "石通幽室心生白，逕擁寒雲步入青。", "一水下窺疑絕線，兩山前列似開屏。", "重城歸去仍堪喜，歲稔人家戶不扃。"]'),
('ce54bf4c-60c2-4b22-9762-bbb7a2026c29','次韻王憲中秋不見月','趙抃','宋','宋诗','song-poetry','','[]','一城歌管中秋樂，薄暮樓臺六幕垂。',64,'全唐诗/poet.song.19000.json','["一城歌管中秋樂，薄暮樓臺六幕垂。", "明月幸無虧損處，浮雲應有斂收時。", "聊因表海今宵醉，却起錢塘去歲思。", "有美堂前如白晝，練鋪江面鏡鬚眉。"]'),
('7884f971-6495-4e46-9b28-d53214f02e1e','寄餘慶講僧思辯','趙抃','宋','宋诗','song-poetry','','[]','年光已占六十四，七十歸來尚六年。',64,'全唐诗/poet.song.19000.json','["年光已占六十四，七十歸來尚六年。", "顧我久慚迷利祿，與師同約老林泉。", "政爲豈弟聊康俗，心放逍遥自到仙。", "身寄東州夢南去，山堂依約艮菴前。"]'),
('bae4de73-aefd-4168-96da-8225ce099566','次韻孔憲重九出巡未回','趙抃','宋','宋诗','song-poetry','','[]','東望迢迢百尺臺，清風徒念故人來。',64,'全唐诗/poet.song.19000.json','["東望迢迢百尺臺，清風徒念故人來。", "幸空訟缿澄心坐，喜得詩筒盥手開。", "不覺登高佳節到，未期行旆幾時回。", "堯山雖與民同樂，阻共車公把酒杯。"]'),
('82fbfdf2-09a3-4cff-85b9-9c12450181d9','酬孔憲將還','趙抃','宋','宋诗','song-poetry','','[]','待月登高悉後時，還轅今喜近郊岐。',64,'全唐诗/poet.song.19000.json','["待月登高悉後時，還轅今喜近郊岐。", "再圓光彩蟾升漢，未謝馨香菊滿籬。", "乘暇尋山應有得，許陪觀海不知誰。", "感君按轡澄外清，遺我瓊瑶兩首詩。"]'),
('cef59fb4-2e4c-4a69-b4eb-0c9728965b67','送十二弟太博揚倅潭州','趙抃','宋','宋诗','song-poetry','','[]','我憶初筵湖外日，于今三十八年間。',64,'全唐诗/poet.song.19000.json','["我憶初筵湖外日，于今三十八年間。", "無緣再得遊潭府，有夢還應到嶽山。", "屈指春秋驚老大，滿頭霜雪欲歸閒。", "之官莫憚長沙遠，行業於人不愧顔。"]'),
('1087a2ac-41ad-48f9-a2cf-d33f5601eb12','次韻孔憲蓬萊閣','趙抃','宋','宋诗','song-poetry','','[]','山巔危構傍蓬萊，水閣風長此快哉。',64,'全唐诗/poet.song.19000.json','["山巔危構傍蓬萊，水閣風長此快哉。", "天地涵容百川入，晨昏浮動兩潮來。", "遥思坐上遊觀遠，愈覺胸中度量開。", "憶我去年曾望海，杭州東向亦樓臺。"]'),
('fbe5822c-6c54-419a-95d5-181c7036af9b','次韻王憲表海亭賞雪','趙抃','宋','宋诗','song-poetry','','[]','開樽表海最高亭，正是紛紛雪態輕。',64,'全唐诗/poet.song.19000.json','["開樽表海最高亭，正是紛紛雪態輕。", "比屋萬層瓊室徧，夷塗千里玉沙平。", "因風起絮先春意，與月交光後夜清。", "共喜豐登有佳兆，結成和氣在民情。"]'),
('80eb1fe0-8d9f-462e-aae1-116ebc52ba77','再登亭偶作','趙抃','宋','宋诗','song-poetry','','[]','氣象三齊古得名，時登表海最高亭。',64,'全唐诗/poet.song.19000.json','["氣象三齊古得名，時登表海最高亭。", "河源一水下青嶂，人物兩城如畫屏。", "邑報有秋期俗阜，守慚無術濟民靈。", "從來獄市并容地，且向樽前任醉醒。"]'),
('bcb7dd50-c9cd-4927-82ce-d17233b0d634','寄酬舊交吳中復龍圖','趙抃','宋','宋诗','song-poetry','','[]','我昔夢刀慙樂土，群今叱馭信賢哉。',64,'全唐诗/poet.song.19000.json','["我昔夢刀慙樂土，群今叱馭信賢哉。", "芝蘭舊友三年別，金玉新詩萬里來。", "石室清風期俗變，錦城珍宴爲民開。", "中和有頌朝廷喜，行看春光擁詔回。"]'),
('396742f0-d43b-47a6-9474-9e5cafbe6431','酬越守孔延之度支','趙抃','宋','宋诗','song-poetry','','[]','君詩感別我依依，言念朋懷與願違。',64,'全唐诗/poet.song.19000.json','["君詩感別我依依，言念朋懷與願違。", "京口落帆初醉後，江心登寺復分飛。", "回思二浙風烟好，來喜三齊獄訟稀。", "舊里未歸徒仰羨，小蓬萊上占春輝。"]'),
('16cb78a6-f1a0-4e0a-95dc-b6dfbf0af20b','青社有懷杭州','趙抃','宋','宋诗','song-poetry','','[]','早暮濤聲遶郡衙，湖山樓閣襯烟霞。',64,'全唐诗/poet.song.19000.json','["早暮濤聲遶郡衙，湖山樓閣襯烟霞。", "渾疑出處神仙地，不似尋常刺史家。", "假守半年無惠愛，退公連日不諠譁。", "東州久發同歸夢，却念重來未有涯。"]'),
('4d7cac6d-73c3-4d11-adf4-65d01cd1a92a','再有蜀命別王居卿','趙抃','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','穆陵關望劍門關，岱嶽山連蜀道山。',64,'全唐诗/poet.song.19000.json','["穆陵關望劍門關，岱嶽山連蜀道山。", "自顧松筠根節老，誰憐霜雪鬢毛斑。", "離家詎謂虞私計，過闕尤欣覲帝顔。", "叱馭重行君莫訝，古人辭易不辭難。"]'),
('154522db-eb07-4dc7-8f85-4ca115dc77ee','入蜀先寄青城張遨先生','趙抃','宋','宋诗','song-poetry','','[]','踰年青社得徘徊，一日皇華下詔催。',64,'全唐诗/poet.song.19000.json','["踰年青社得徘徊，一日皇華下詔催。", "蜀道五千馳驛去，秦關百二拂雲開。", "不同參政初時入，也似尚書兩度來。", "到日先生應笑我，白頭猶自走塵埃。"]'),
('4f5fedd9-1fc2-4f42-878a-92b92a7b31e8','寄題劉詔寺丞檻泉亭','趙抃','宋','宋诗','song-poetry','','[]','泉名從古冠齊丘，獨占溪心湧不休。',64,'全唐诗/poet.song.19000.json','["泉名從古冠齊丘，獨占溪心湧不休。", "深似蜀都分海眼，勢如吳分起潮頭。", "連宵鼓浪摇明月，當暑迎風作素秋。", "亭上主人留我語，只將塵事指浮漚。"]'),
('eb7b735c-9ae3-49ea-a32e-3b694db8174f','過鐵山鋪寄交代吳龍圖','趙抃','宋','宋诗','song-poetry','','[]','暫留山驛又晨興，西望旌麾想舊朋。',64,'全唐诗/poet.song.19000.json','["暫留山驛又晨興，西望旌麾想舊朋。", "三院華簪曾對直，兩川兵印復交承。", "年光頭鬢華如雪，世態心情冷似冰。", "境上憑詩馳遠意，青泥寒曉入雲登。"]'),
('911723e0-c5fe-4c38-846c-6815b8d9b170','過左綿偶成','趙抃','宋','宋诗','song-poetry','','[]','東南再守二年間，徙蜀何須問險艱。',64,'全唐诗/poet.song.19000.json','["東南再守二年間，徙蜀何須問險艱。", "入覲已違龍尾道，出麾還過鹿頭關。", "與民共約三春樂，顧我都忘兩鬢斑。", "歲滿乞骸何處好，仙棊一局爛柯山。"]'),
('34bd00cc-9c9a-4455-bfe5-233e562ef07f','次韻吳龍圖別後言懷','趙抃','宋','宋诗','song-poetry','','[]','言念朋遊二紀間，離樽前對鬢絲斑。',64,'全唐诗/poet.song.19000.json','["言念朋遊二紀間，離樽前對鬢絲斑。", "告新劍外皆遺愛，道舊臺中共解顔。", "我固無辭來蜀國，公聞有命鎮秦關。", "西東接畛三千里，莫厭詩筒數往還。"]'),
('3328afa7-0a69-4c2f-9d81-ac267fdad7f2','至成都有作二首  其一','趙抃','宋','宋诗','song-poetry','','[]','四十年間利祿身，平生踈拙任天真。',64,'全唐诗/poet.song.19000.json','["四十年間利祿身，平生踈拙任天真。", "慙無治迹留青社，喜奉恩華覲紫宸。", "去國早逢關右雪，下車還人劍南春。", "爲憐錦里風光好，不倦從來作主人。"]'),
('f1ff08dc-ed21-4a2d-a043-964be20979e5','至成都有作二首  其二','趙抃','宋','宋诗','song-poetry','','[]','西指梁岷路屈盤，猶能矍鑠據征鞍。',64,'全唐诗/poet.song.19000.json','["西指梁岷路屈盤，猶能矍鑠據征鞍。", "大庭臨遣皇恩重，還俗傳聞睿詔寬。", "峯聳雲粧銀世界，江深春動錦波瀾。", "遨頭老矣民知否，莫作風流太守看。"]'),
('a6eabc40-6d05-4a34-9199-f6400bba8e90','次韻提刑張廣民度支射中金錢','趙抃','宋','宋诗','song-poetry','','[]','百發秋毫不少偏，宜應佳兆中青錢。',64,'全唐诗/poet.song.19000.json','["百發秋毫不少偏，宜應佳兆中青錢。", "鳴弦迅發心先正，破的勞觀眼欲穿。", "賞勸坐添杯上桂，詠歌賓許幙中蓮。", "古人一箭功名立，豈止文章獨炳然。"]'),
('f79581a5-4d43-4a25-ac53-29c634c3ea12','題江原張著作善頌堂','趙抃','宋','宋诗','song-poetry','','[]','構堂賓族聚於斯，屈指高風劍外稀。',64,'全唐诗/poet.song.19000.json','["構堂賓族聚於斯，屈指高風劍外稀。", "七十年尊君樂隱，二千石重子榮歸。", "溪流石上來清響，岩洞簷前聳翠微。", "舊令尹今西處望，江原閭巷正光輝。"]'),
('6b52e875-9f1b-4e37-b186-6d5e52b7b9a6','送運判韓宗道赴闕','趙抃','宋','宋诗','song-poetry','','[]','去歲間關到蜀時，聞君早作促裝期。',64,'全唐诗/poet.song.19000.json','["去歲間關到蜀時，聞君早作促裝期。", "初疑傾蓋無多日，今幸分携已及朞。", "曉棧直登雲裏路，臘梅還見雪中枝。", "紫宸入覲從容對，劍外民靈荷帝慈。"]'),
('a20ff847-5300-4200-aa36-1ce4bbac8b7d','送別張憲唐民','趙抃','宋','宋诗','song-poetry','','[]','三年持節按刑章，豈弟其誰不歎降。',64,'全唐诗/poet.song.19000.json','["三年持節按刑章，豈弟其誰不歎降。", "才者設施功第一，使乎光彩竟無雙。", "宣風蜀右成新法，易拜秦東得舊邦。", "欲識遠人留戀意，隴泉幽咽下巴江。"]'),
('9e49b5d6-2e68-4f84-8731-d18977000aad','次韻運使榮諲學士遊浄眾尋梅','趙抃','宋','宋诗','song-poetry','','[]','飛蓋城西探早梅，僧園欄榭燕游陪。',64,'全唐诗/poet.song.19000.json','["飛蓋城西探早梅，僧園欄榭燕游陪。", "微寒始報冬初信，清艷應留臘後開。", "子美英詞誇雪色，趙昌精筆寫香腮。", "此花自有天容意，迎得春陽次第來。"]'),
('ddd77da0-4300-4505-80c7-0be14d9dac72','送茂守吳彥先郎中赴闕','趙抃','宋','宋诗','song-poetry','','[]','汶山爲郡數逢春，被詔還都歲又新。',64,'全唐诗/poet.song.19000.json','["汶山爲郡數逢春，被詔還都歲又新。", "惠政久通蠻徼外，愴懷初去蜀江濱。", "邛崍古未兼忠孝，宣室今非訪鬼神。", "制禦羌夷知有術，上前章牘爲開陳。"]'),
('49add150-34f2-4dd2-94e8-dab926328bce','次韻黎守毛抗屯田見寄','趙抃','宋','宋诗','song-poetry','','[]','岷峨還是一川雄，我愧行春與欲同。',64,'全唐诗/poet.song.19000.json','["岷峨還是一川雄，我愧行春與欲同。", "樂國比年豐衍後，嘉朋終日笑談中。", "沈黎太守初成政，蕃詔諸蠻悉向風。", "聖世唐虞流澤遠，啟行無復用元戎。"]'),
('d0a30e44-4cc4-4720-88c1-5fecd89b9be9','送左緜孫珪職方赴闕','趙抃','宋','宋诗','song-poetry','','[]','三年遺愛被西州，供帳民情豈易留。',64,'全唐诗/poet.song.19000.json','["三年遺愛被西州，供帳民情豈易留。", "險道若天春氣近，雄關如劍曉光浮。", "禁中曾上臺僚薦，使者仍書郡課優。", "去矣青雲岐路穩，不須回首越王樓。"]'),
('cb85ecba-b31d-4d83-8fa3-f1fea13cd18e','鈐兵李左藏廳賞梅','趙抃','宋','宋诗','song-poetry','','[]','歲晏珍林發素葩，樽前奇賞著詩誇。',64,'全唐诗/poet.song.19000.json','["歲晏珍林發素葩，樽前奇賞著詩誇。", "驚逢臘去已三日，喜見春初第一花。", "照水冷容酥點綴，摇風香片雪紛拏。", "主賓莫作尋常看，錦里名園只兩家。"]'),
('105bf5e7-312f-4fa3-addc-93f11ef9ba45','次韻榮學士按簡州見寄','趙抃','宋','宋诗','song-poetry','','[]','我昔坤維濫使權，簡池行部屬豐年。',64,'全唐诗/poet.song.19000.json','["我昔坤維濫使權，簡池行部屬豐年。", "盤桓郡驛留單騎，徙倚江亭按七絃。", "今愧高賢傳麗藻，遠聞清思湧寒泉。", "置藏巾衍光華甚，不使珠璣只媚川。"]'),
('f8caa302-17ea-42bd-96dd-e859598a7162','鈐兵王閤使素芳亭賞梅花','趙抃','宋','宋诗','song-poetry','','[]','素萼清香並酒巵，主人勤意囑留詩。',64,'全唐诗/poet.song.19000.json','["素萼清香並酒巵，主人勤意囑留詩。", "爲逢蜀國新開日，却憶江南舊賞時。", "春密未通桃李信，臘殘都放雪霜姿。", "先公舊植亭欄外，肯構重來見本枝。"]'),
('0f372263-7fc3-42bf-8f29-93872f74f1bf','答彭守鮑叔軻郎中','趙抃','宋','宋诗','song-poetry','','[]','白雲東向日瞻凝，連掞封章寫至誠。',64,'全唐诗/poet.song.19000.json','["白雲東向日瞻凝，連掞封章寫至誠。", "八十親高思就養，二千石貴退辭榮。", "蘭陔得志趨吳分，棠芾留陰在蜀城。", "腰印還鄉人子樂，錦衣光動綵衣明。"]'),
('37487ece-d632-4db7-8c4f-ae56c6438eb4','酬劍守王嘉錫郎中','趙抃','宋','宋诗','song-poetry','','[]','登科三十四年春，五百人中有幾人。',64,'全唐诗/poet.song.19000.json','["登科三十四年春，五百人中有幾人。", "顧我虛名慚過分，得公佳句讀驚神。", "初疑暗裏雙珠擲，自喜懷間萬玉陳。", "預卜鈴齋論仕契，入關聊爲駐車輪。"]'),
('30e109c1-8309-479e-81a6-724bc991b352','次韻周源屯田禱雨二首  其一','趙抃','宋','宋诗','song-poetry','','[]','城東野老告予知，四載兇荒語益悲。',64,'全唐诗/poet.song.19000.json','["城東野老告予知，四載兇荒語益悲。", "遠水又成千里涸，闊天無復寸雲垂。", "倉箱勢絕豐登望，道路人爲殍死期。", "刺史至誠天若應，願留遺愛入生祠。"]'),
('4dc537aa-e8f9-4dcd-8b7b-0914eef2c6c8','次韻周源屯田禱雨二首  其二','趙抃','宋','宋诗','song-poetry','','[]','炎曦禾稼猛於燒，試問靈龜兆已焦。',64,'全唐诗/poet.song.19000.json','["炎曦禾稼猛於燒，試問靈龜兆已焦。", "雨意幾時隨氣協，雷威何日勝氛妖。", "漢朝八使煩敦遣，周室三公重燮調。", "有禱願將明德薦，芳馨何必在蘭椒。"]'),
('e10b0c99-159b-4b73-8a78-f8da56ebe143','答江鉞都官見招','趙抃','宋','宋诗','song-poetry','','[]','風波岐路益馳奔，踈靜嗟誰得似君。',64,'全唐诗/poet.song.19000.json','["風波岐路益馳奔，踈靜嗟誰得似君。", "樂矣夜觴西嶺月，傲然秋釣北谿雲。", "詩章有趣爲千首，利祿無心顧一分。", "雞黍辱招來慰意，俗拘何計入蘭薰。"]'),
('c541cce7-cd65-47af-89e6-f76455917c91','次韻江原方任太博見寄','趙抃','宋','宋诗','song-poetry','','[]','錦城之別重吁嗟，人事繽紛走歲華。',64,'全唐诗/poet.song.19000.json','["錦城之別重吁嗟，人事繽紛走歲華。", "遺我詩篇來有意，憶君魂夢去無涯。", "秋驚蜀嶺更書近，雲掩閩山故國賒。", "聞說政成風俗好，又添和氣樂人家。"]'),
('7c75d2de-1411-42b6-a651-27569bf3eb24','次韻李元方即事','趙抃','宋','宋诗','song-poetry','','[]','壯歲胸懷獨感時，肯隨寒暑似民咨。',64,'全唐诗/poet.song.19000.json','["壯歲胸懷獨感時，肯隨寒暑似民咨。", "能思損益長開卷，任有閒心不負詩。", "趣向已爲汙俗笑，聲名須共古人期。", "茅齋寂坐生秋思，無語西風夜月知。"]'),
('875d7144-2834-4c6c-b423-5b4aa250d250','聞嶺外寇梗','趙抃','宋','宋诗','song-poetry','','[]','驚說炎飚烟瘴時，洞蠻蜂起寇南陲。',64,'全唐诗/poet.song.19000.json','["驚說炎飚烟瘴時，洞蠻蜂起寇南陲。", "家書萬倍金難得，遠夢千迴路不知。", "刺史沒身專捍禦，諫官銜命救瘡痍。", "伏波死去今誰繼，大筆銘勳壓海涯。"]'),
('9abd9db9-94a7-4983-b076-2eff86ba79fe','贈東川曹道人','趙抃','宋','宋诗','song-poetry','','[]','養生非謂獨存神，功行須令日日新。',64,'全唐诗/poet.song.19000.json','["養生非謂獨存神，功行須令日日新。", "高睨鵬摶風萬里，靜憐龜息壽千春。", "物無凝滯心無積，名已逍遥道已醇。", "命不在天須力信，世間多少未知人。"]'),
('84491cb1-6ef5-4130-a5de-8b533711a2e5','勸成都府學諸生','趙抃','宋','宋诗','song-poetry','','[]','學初心勿動華紛，須念文翁昔日勤。',64,'全唐诗/poet.song.19000.json','["學初心勿動華紛，須念文翁昔日勤。", "事業直教名不朽，聲猷堪畏世無聞。", "平居鄉黨終傳道，得位朝廷必致君。", "爲語諸生期遠到，天衢亨處有青雲。"]'),
('a6edb62e-3167-4814-be2f-af90477b9c84','題府庭海椶','趙抃','宋','宋诗','song-poetry','','[]','海椶根幹出栟櫚，雙勢凌空劍外無。',64,'全唐诗/poet.song.19000.json','["海椶根幹出栟櫚，雙勢凌空劍外無。", "長鎖荆榛嗟廟栢，不禁風雨笑庭梧。", "胡僧過識已千歲，蜀守來觀只兩株。", "離立峩峩同壯士，側身東望拱皇都。"]'),
('12d605a1-2040-464c-abcd-330eeab9289e','次韻文同學士春雪','趙抃','宋','宋诗','song-poetry','','[]','東皇欲報豐年信，千里同雲六幕陰。',64,'全唐诗/poet.song.19000.json','["東皇欲報豐年信，千里同雲六幕陰。", "遇景大吟詩將手，與民偕樂使君心。", "錦城闊暖無多積，岷嶺高寒旋覺深。", "最是西園花木好，曉來粧點作瑶林。"]');
